// Script: Re-embed all lookitry_knowledge items with text-embedding-004 via Vertex AI
// Run: pnpm exec ts-node scripts/backfill-knowledge-embeddings.ts

import * as dotenv from 'dotenv';
dotenv.config({ path: '.env', override: true });

import { createClient } from '@supabase/supabase-js';
import { GoogleGenAI } from '@google/genai';

process.env.GOOGLE_APPLICATION_CREDENTIALS = '/home/travis/Lookitry/Lookitry/backend/secrets/vertex-key.json';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  (process.env.SUPABASE_SERVICE_KEY ?? process.env.SUPABASE_SERVICE_ROLE_KEY)!
);

const ai = new GoogleGenAI({
  vertexai: true,
  project: process.env.VERTEX_PROJECT_ID || 'gen-lang-client-0591001769',
  location: 'us-central1',
});

async function generateEmbedding(text: string): Promise<number[] | null> {
  try {
    const result = await (ai.models as any).embedContent({
      model: 'text-embedding-004',
      contents: [{ parts: [{ text }] }],
      taskType: 'RETRIEVAL_DOCUMENT',
    });
    return result?.embeddings?.[0]?.values ?? result?.embedding?.values ?? null;
  } catch (err: any) {
    console.error('Error calling Vertex embedding:', err.message);
    return null;
  }
}

async function main() {
  const { data: items, error } = await supabase
    .from('lookitry_knowledge')
    .select('id, title, content');

  if (error) {
    console.error('Error reading lookitry_knowledge:', error.message);
    process.exit(1);
  }

  console.log(`Processing ${items?.length ?? 0} items with text-embedding-004 (768 dims)...`);
  let ok = 0, failed = 0;

  for (const item of items ?? []) {
    const text = `${item.title}\n\n${item.content}`.slice(0, 2000);
    const embedding = await generateEmbedding(text);
    if (!embedding) {
      console.error(`✗ ${item.id}: embedding failed`);
      failed++;
      continue;
    }
    if (embedding.length !== 768) {
      console.error(`✗ ${item.id}: wrong dimension ${embedding.length} (expected 768)`);
      failed++;
      continue;
    }
    const { error: updateError } = await supabase
      .from('lookitry_knowledge')
      .update({ embedding: JSON.stringify(embedding) })
      .eq('id', item.id);

    if (updateError) {
      console.error(`✗ ${item.id}: update failed —`, updateError.message);
      failed++;
    } else {
      console.log(`✓ ${item.id}: ${item.title} (${embedding.length} dims)`);
      ok++;
    }
    await new Promise(r => setTimeout(r, 300));
  }

  console.log(`\nDone: ${ok} OK, ${failed} failed`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

/**
 * Script para limpiar leads duplicados de Rebecca
 * Normaliza phones (sin +) y elimina duplicados
 */

const SUPABASE_URL = 'https://vkdooutklowctuudjnkl.supabase.co';
const SUPABASE_KEY = '***REMOVED-SECRET***';

interface LeadRecord {
  id: string;
  phone: string;
  created_at: string;
  updated_at: string;
  name: string | null;
  email: string | null;
  internal_notes: string | null;
}

async function supabaseQuery<T = unknown>(table: string, options: {
  select?: string;
  eq?: Record<string, string>;
  order?: string;
  limit?: number;
} = {}): Promise<T> {
  let url = `${SUPABASE_URL}/rest/v1/${table}?`;

  const params = new URLSearchParams();
  if (options.select) params.append('select', options.select);
  if (options.order) params.append('order', options.order);
  if (options.limit) params.append('limit', options.limit.toString());

  if (options.eq) {
    for (const [col, val] of Object.entries(options.eq)) {
      params.append(col, `eq.${val}`);
    }
  }

  url += params.toString();

  const res = await fetch(url, {
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
    }
  });

  if (!res.ok) {
    throw new Error(await res.text());
  }

  return res.json() as T;
}

async function supabaseDelete(table: string, ids: string[]) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?id=in.(${ids.join(',')})`;

  const res = await fetch(url, {
    method: 'DELETE',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
    }
  });

  if (!res.ok) {
    throw new Error(await res.text());
  }

  return true;
}

async function supabaseUpdate(table: string, id: string, data: Record<string, unknown>) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`;

  const res = await fetch(url, {
    method: 'PATCH',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(data)
  });

  if (!res.ok) {
    throw new Error(await res.text());
  }

  return true;
}

// Normalizar phone: siempre sin +
function normalizePhone(phone: string): string {
  return phone.replace(/^\+/, '').replace(/^0/, '');
}

// Agrupar phones similares
function areSamePhone(phone1: string, phone2: string): boolean {
  const n1 = normalizePhone(phone1);
  const n2 = normalizePhone(phone2);
  return n1 === n2;
}

async function cleanupDuplicates() {
  console.log('🔍 Buscando leads duplicados (normalizando phones)...\n');

  try {
    const leads = await supabaseQuery<LeadRecord[]>('leads', {
      select: 'id,phone,created_at,updated_at,name,email,internal_notes',
      eq: { source: 'whatsapp' }
    });

    const webLeads = await supabaseQuery<LeadRecord[]>('leads', {
      select: 'id,phone,created_at,updated_at,name,email,internal_notes',
      eq: { source: 'web' }
    });

    const allLeads: LeadRecord[] = [...leads, ...webLeads];
    console.log(`📊 Total leads: ${allLeads.length}\n`);

    // Agrupar por phone normalizado
    const normalizedGroups: Record<string, LeadRecord[]> = {};
    for (const lead of allLeads) {
      const normalized = normalizePhone(lead.phone);
      if (!normalizedGroups[normalized]) {
        normalizedGroups[normalized] = [];
      }
      normalizedGroups[normalized].push(lead);
    }

    // Filtrar grupos con duplicados
    const duplicatedGroups = Object.entries(normalizedGroups)
      .filter(([_, leads]) => leads.length > 1);

    console.log(`📊 Grupos con duplicados: ${duplicatedGroups.length}`);

    if (duplicatedGroups.length === 0) {
      console.log('✅ No hay duplicados para limpiar');
      return;
    }

    let totalDeleted = 0;

    for (const [normalizedPhone, leadRecords] of duplicatedGroups) {
      console.log(`\n📱 Procesando: ${normalizedPhone}`);
      console.log(`   variants: ${leadRecords.map(l => l.phone).join(', ')}`);

      // Ordenar por updated_at descendente
      leadRecords.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());

      const [keep, ...toDelete] = leadRecords;
      console.log(`  ✅ Mantener: ${keep.id} (${keep.phone})`);
      console.log(`  🗑️  Eliminar: ${toDelete.length} registros`);

      // Merge notes de todos
      const mergedNotes = leadRecords
        .map(r => r.internal_notes)
        .filter((n): n is string => n !== null)
        .join('\n---\n');

      // Merge name y email (preferir el que tenga más datos)
      const mergedName = keep.name || toDelete.find(r => r.name)?.name || null;
      const mergedEmail = keep.email || toDelete.find(r => r.email)?.email || null;

      await supabaseUpdate('leads', keep.id, { 
        internal_notes: mergedNotes,
        name: mergedName,
        email: mergedEmail,
        phone: normalizedPhone // Normalizar el phone del que mantenemos
      });
      console.log('  📝 Datos mergeados y phone normalizado');

      const idsToDelete = toDelete.map(r => r.id);
      await supabaseDelete('leads', idsToDelete);

      totalDeleted += toDelete.length;
      console.log(`  ✅ Eliminados ${toDelete.length} duplicados`);
    }

    console.log(`\n\n🎉 Total de duplicados eliminados: ${totalDeleted}`);
    console.log(`📊 Leads únicos restantes: ${allLeads.length - totalDeleted}`);

  } catch (error) {
    console.error('Error:', error);
  }
}

cleanupDuplicates();

/**
 * Prospecting Script - Google Places Lead Generation
 * Run: npx ts-node scripts/prospect-google-places.ts
 */

import dotenv from 'dotenv';
dotenv.config();

import { supabaseAdmin } from '../src/config/supabase';

const GOOGLE_PLACES_API_KEY = process.env.GOOGLE_PLACES_API_KEY || '';

interface GooglePlaceResult {
  place_id: string;
  name: string;
  formatted_address?: string;
  formatted_phone_number?: string;
  website?: string;
  geometry?: { location: { lat: number; lng: number } };
  types?: string[];
  rating?: number;
  user_ratings_total?: number;
}

interface GooglePlacesResponse {
  results?: GooglePlaceResult[];
  status: string;
  next_page_token?: string;
}

const CITIES = [
  { query: 'tienda ropa Cali', city: 'Cali', country: 'Colombia', priority: 1 },
  { query: 'tienda ropa latina Miami', city: 'Miami', country: 'USA', priority: 2 },
  { query: 'boutique Medellín', city: 'Medellín', country: 'Colombia', priority: 3 },
  { query: 'zapatería Bogotá', city: 'Bogotá', country: 'Colombia', priority: 4 },
  { query: 'boutique ropa Madrid', city: 'Madrid', country: 'España', priority: 5 },
  { query: 'boutique hispana Los Angeles', city: 'Los Angeles', country: 'USA', priority: 6 },
  { query: 'tienda moda Barcelona', city: 'Barcelona', country: 'España', priority: 7 },
];

const MAX_RESULTS_PER_CITY = 50;
const DAILY_LIMIT = 500;

async function httpGet(url: string): Promise<string> {
  return new Promise((resolve, reject) => {
    const https = require('https');
    https
      .get(url, (res: any) => {
        let data = '';
        res.on('data', (chunk: string) => (data += chunk));
        res.on('end', () => resolve(data));
      })
      .on('error', reject);
  });
}

async function searchPlaces(query: string): Promise<GooglePlaceResult[]> {
  const url = `https://maps.googleapis.com/maps/api/place/textsearch/json?query=${encodeURIComponent(query)}&type=store|clothing_store|fashion_accessories_store&key=${GOOGLE_PLACES_API_KEY}`;

  const data = await httpGet(url);
  const response = JSON.parse(data) as GooglePlacesResponse;

  if (response.status !== 'OK' && response.status !== 'ZERO_RESULTS') {
    console.error(`[Google Places] Error: ${response.status}`);
    return [];
  }

  return response.results || [];
}

async function getQuotaStatus(): Promise<{ daily_used: number; remaining: number }> {
  const { data } = await supabaseAdmin
    .from('google_places_quota')
    .select('daily_used')
    .eq('id', 1)
    .single();

  const used = data?.daily_used || 0;
  return { daily_used: used, remaining: DAILY_LIMIT - used };
}

async function incrementQuota(count: number): Promise<void> {
  const today = new Date().toISOString().split('T')[0];
  const firstOfMonth = today.substring(0, 7) + '-01';

  const { data } = await supabaseAdmin
    .from('google_places_quota')
    .select('*')
    .eq('id', 1)
    .maybeSingle();

  let dailyUsed = data?.daily_used || 0;
  const lastReset = data?.last_reset_date;

  if (lastReset !== today) {
    dailyUsed = 0;
  }

  dailyUsed += count;

  await supabaseAdmin
    .from('google_places_quota')
    .upsert({
      id: 1,
      daily_used: dailyUsed,
      monthly_used: (data?.monthly_used || 0) + count,
      last_reset_date: today,
      last_month_reset: firstOfMonth,
    });
}

async function saveLead(place: GooglePlaceResult, city: string, country: string): Promise<{ id: string; isNew: boolean } | null> {
  // Check if already exists
  const { data: existing } = await supabaseAdmin
    .from('leads')
    .select('id')
    .eq('source_id', place.place_id)
    .maybeSingle();

  if (existing) {
    return { id: existing.id, isNew: false };
  }

  // Insert new lead
  const { data, error } = await supabaseAdmin
    .from('leads')
    .insert({
      name: place.name,
      business_type: place.types?.[0] || 'store',
      address: place.formatted_address,
      phone: place.formatted_phone_number,
      website: place.website,
      source: 'google_places',
      source_id: place.place_id,
      country,
      city,
      latitude: place.geometry?.location?.lat,
      longitude: place.geometry?.location?.lng,
      status: 'new',
      is_fashion_relevant: null,
    })
    .select('id')
    .single();

  if (error) {
    console.error(`Error saving lead ${place.name}:`, error.message);
    return null;
  }

  return { id: data.id, isNew: true };
}

async function runProspecting() {
  console.log('🚀 Starting Google Places Prospecting...\n');

  // Check quota
  const quota = await getQuotaStatus();
  console.log(`📊 Quota Status: ${quota.daily_used}/${DAILY_LIMIT} used, ${quota.remaining} remaining\n`);

  if (quota.remaining <= 0) {
    console.error('❌ Daily quota exhausted. Try again tomorrow.');
    return;
  }

  const results: Record<string, { found: number; saved: number; duplicates: number }> = {};

  // Process each city
  for (const cityConfig of CITIES) {
    if (quota.remaining <= 0) {
      console.log('⚠️ Quota limit reached, stopping.');
      break;
    }

    console.log(`🔍 [${cityConfig.priority}/7] Searching: "${cityConfig.query}"...`);

    try {
      const places = await searchPlaces(cityConfig.query);
      console.log(`   Found ${places.length} places`);

      results[cityConfig.city] = { found: places.length, saved: 0, duplicates: 0 };

      // Increment quota for the search
      await incrementQuota(1);
      quota.daily_used++;
      quota.remaining--;

      // Save leads (up to MAX_RESULTS_PER_CITY)
      const placesToSave = places.slice(0, MAX_RESULTS_PER_CITY);

      for (const place of placesToSave) {
        const result = await saveLead(place, cityConfig.city, cityConfig.country);

        if (result) {
          if (result.isNew) {
            results[cityConfig.city].saved++;
          } else {
            results[cityConfig.city].duplicates++;
          }
        }

        // Small delay to avoid overwhelming Supabase
        await new Promise(resolve => setTimeout(resolve, 100));
      }

      console.log(`   ✓ Saved: ${results[cityConfig.city].saved}, Duplicates: ${results[cityConfig.city].duplicates}\n`);

      // Delay between cities
      await new Promise(resolve => setTimeout(resolve, 500));

    } catch (error: any) {
      console.error(`   ❌ Error: ${error.message}\n`);
    }
  }

  // Final summary
  console.log('\n📈 PROSPECTING SUMMARY');
  console.log('='.repeat(50));

  let totalFound = 0;
  let totalSaved = 0;
  let totalDuplicates = 0;

  for (const [city, stats] of Object.entries(results)) {
    console.log(`${city.padEnd(15)} | Found: ${String(stats.found).padStart(3)} | Saved: ${String(stats.saved).padStart(3)} | Dups: ${stats.duplicates}`);
    totalFound += stats.found;
    totalSaved += stats.saved;
    totalDuplicates += stats.duplicates;
  }

  console.log('='.repeat(50));
  console.log(`TOTAL             | Found: ${String(totalFound).padStart(3)} | Saved: ${String(totalSaved).padStart(3)} | Dups: ${totalDuplicates}`);
  console.log(`\n📊 Final Quota Used: ${quota.daily_used}/${DAILY_LIMIT}`);
  console.log('\n✅ Prospecting complete!');
}

runProspecting().catch(console.error);

