import { supabaseAdmin } from '../config/supabase';

export interface HealthAuditResult {
  summary: string;
  sections: string[];
}

export async function auditHealth(): Promise<HealthAuditResult> {
  const sections: string[] = [];

  try {
    const { data: brands, error: brandsError } = await supabaseAdmin
      .from('brands')
      .select('id')
      .limit(1);

    if (brandsError) {
      sections.push(`Supabase: ERROR - ${brandsError.message}`);
    } else {
      sections.push(`Supabase: OK`);
    }
  } catch (e) {
    sections.push(`Supabase: ERROR - ${(e as Error).message}`);
  }

  try {
    const minioEndpoint = process.env.MINIO_ENDPOINT || 'https://minio.wilkiedevs.com';
    const response = await fetch(minioEndpoint, { method: 'HEAD', signal: AbortSignal.timeout(5000) });
    sections.push(`MinIO: OK (${response.status})`);
  } catch (e) {
    sections.push(`MinIO: ERROR - ${(e as Error).message}`);
  }

  try {
    const n8nUrl = process.env.N8N_WEBHOOK_URL || 'https://n8n.wilkiedevs.com';
    const baseUrl = n8nUrl.replace(/\/webhook.*/, '');
    const response = await fetch(baseUrl, { method: 'GET', signal: AbortSignal.timeout(5000) });
    sections.push(`n8n: OK (${response.status})`);
  } catch (e) {
    sections.push(`n8n: ERROR - ${(e as Error).message}`);
  }

  try {
    const wompiEnabled = process.env.WOMPI_ENABLED === 'true';
    if (wompiEnabled) {
      sections.push(`Wompi: Configurado`);
    } else {
      sections.push(`Wompi: Deshabilitado`);
    }
  } catch (e) {
    sections.push(`Wompi: ERROR - ${(e as Error).message}`);
  }

  try {
    const paypalClientId = process.env.PAYPAL_CLIENT_ID;
    if (paypalClientId) {
      sections.push(`PayPal: Configurado`);
    } else {
      sections.push(`PayPal: No configurado`);
    }
  } catch (e) {
    sections.push(`PayPal: ERROR - ${(e as Error).message}`);
  }

  const uptime = process.uptime();
  const uptimeDays = Math.floor(uptime / 86400);
  const uptimeHours = Math.floor((uptime % 86400) / 3600);
  const uptimeMinutes = Math.floor((uptime % 3600) / 60);
  sections.push(`\nBackend uptime: ${uptimeDays}d ${uptimeHours}h ${uptimeMinutes}m`);
  sections.push(`Node.js: ${process.version}`);
  sections.push(`Memoria: ${(process.memoryUsage().heapUsed / 1024 / 1024).toFixed(1)}MB / ${(process.memoryUsage().heapTotal / 1024 / 1024).toFixed(1)}MB`);

  const env = process.env.NODE_ENV || 'development';
  sections.push(`\nEntorno: ${env}`);

  const summary = `Health check del sistema`;

  return { summary, sections };
}

import { supabaseAdmin } from '../config/supabase';

export interface SecurityAuditResult {
  summary: string;
  sections: string[];
}

export async function auditSecurity(hours = 24): Promise<SecurityAuditResult> {
  const now = new Date();
  const cutoff = new Date(now.getTime() - hours * 60 * 60 * 1000).toISOString();
  const sections: string[] = [];

  const { data: trialRegistrations, error: trialError } = await supabaseAdmin
    .from('trial_registrations')
    .select('id, ip_address, brand_id, created_at')
    .gte('created_at', cutoff)
    .order('created_at', { ascending: false });

  if (trialError) {
    sections.push(`Error consultando trials: ${trialError.message}`);
  } else {
    const ipCounts = new Map<string, number>();
    trialRegistrations?.forEach(r => {
      ipCounts.set(r.ip_address, (ipCounts.get(r.ip_address) || 0) + 1);
    });

    const suspiciousIPs = Array.from(ipCounts.entries()).filter(([, count]) => count > 2);

    sections.push(`Registros de trial (${hours}h): ${trialRegistrations?.length ?? 0}`);
    if (suspiciousIPs.length > 0) {
      const list = suspiciousIPs.map(([ip, count]) => `  - ${ip}: ${count} intentos`).join('\n');
      sections.push(`ALERTA - IPs sospechosas:\n${list}`);
    }
  }

  const { data: failedLogins } = await supabaseAdmin
    .from('admin_notifications')
    .select('title, message, severity, created_at')
    .ilike('title', '%login%')
    .gte('created_at', cutoff)
    .order('created_at', { ascending: false })
    .limit(10);

  if (failedLogins && failedLogins.length > 0) {
    sections.push(`\nNotificaciones de login (${hours}h): ${failedLogins.length}`);
    const list = failedLogins.slice(0, 5).map(n => `  - [${n.severity?.toUpperCase() || 'INFO'}] ${n.message?.slice(0, 100)}`).join('\n');
    sections.push(list);
  }

  const { data: brands } = await supabaseAdmin
    .from('brands')
    .select('id, name, email, plan, subscription_status');

  if (brands) {
    const suspended = brands.filter(b => b.subscription_status === 'suspended');
    const expired = brands.filter(b => b.subscription_status === 'expired');
    sections.push(`\nMarcas suspendidas/expiradas: ${suspended.length}/${expired.length}`);

    const activeWithNoLanding = brands.filter(b => b.subscription_status === 'active' && !(b as any).has_landing_page);
    if (activeWithNoLanding.length > 0) {
      sections.push(`Marcas activas sin landing: ${activeWithNoLanding.length}`);
    }
  }

  const { count: totalGenerations } = await supabaseAdmin
    .from('generations')
    .select('*', { count: 'exact', head: true });

  const { count: totalBrands } = await supabaseAdmin
    .from('brands')
    .select('*', { count: 'exact', head: true });

  sections.push(`\nTotales del sistema:`);
  sections.push(`Marcas: ${totalBrands ?? 0} | Generaciones: ${totalGenerations ?? 0}`);

  const summary = `Auditoria de seguridad - ${hours}h`;

  return { summary, sections };
}

