import { Response } from 'express';
import { AdminService } from '../../services/admin.service';
import { auditService } from '../../services/audit.service';
import { generateToken } from '../../utils/jwt';
import { emailService } from '../../services/email.service';
import { authAdminService } from '../../services/admin/auth.admin.service';
import { GOOGLE_CONFIG } from '../../config/google';
import { verifyGoogleAccessToken, verifyGoogleToken } from '../../services/google-auth.service';
import { sanitizeError } from '../../utils/sanitizeError';

const adminService = new AdminService();

const IS_PROD = process.env.NODE_ENV === 'production';
const COOKIE_DOMAIN = process.env.COOKIE_DOMAIN;

/**
 * POST /api/admin/auth/login
 * Login de administrador
 */
export const adminLogin = async (req: any, res: Response) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({
        error: 'VALIDATION_ERROR',
        message: 'Email y contraseña son requeridos',
      });
    }

    // Validación de formato de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({
        error: 'VALIDATION_ERROR',
        message: 'Formato de email inválido',
      });
    }

    // Buscar admin
    const admin = await adminService.getAdminByEmail(email);

    if (!admin) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'Credenciales inválidas',
      });
    }

    // Verificar contraseña
    const isValidPassword = await adminService.verifyPassword(password, (admin as any).password);

    if (!isValidPassword) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'Credenciales inválidas',
      });
    }

    // Generar token
    const token = generateToken({
      adminId: admin.id,
      email: admin.email,
    });

    // Seguridad: Cookie HTTP-Only
    const cookieOptions: any = {
      httpOnly: true,
      secure: IS_PROD,
      sameSite: 'lax',
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 días
      path: '/',
    };

    if (COOKIE_DOMAIN && IS_PROD) {
      cookieOptions.domain = COOKIE_DOMAIN;
    }

    res.cookie('admin_token', token, cookieOptions);

    // Auditoría de login
    auditService.log({
      admin_id: admin.id,
      admin_email: admin.email,
      action: 'admin.login',
    });

    return res.status(200).json({
      // Token se envía solo en cookie HTTP-only por seguridad
      admin: {
        id: admin.id,
        email: admin.email,
        name: admin.name,
        role: admin.role,
      },
    });
  } catch (error: any) {
    console.error('Error in adminLogin:', error);
    return res.status(500).json({
      error: 'INTERNAL_ERROR',
      message: 'Error interno del servidor',
    });
  }
};

