        .from('rebecca_config')
        .update({
          config_value: value,
          updated_at: now,
          updated_by: adminEmail,
        })
        .eq('config_key', key);

      if (error) {
        console.error(`[RebeccaAdmin] Error updating ${key}:`, error);
