   * POST /api/category-attributes - Crear o actualizar atributos de una categoría
   */
  async upsert(req: AuthRequest, res: Response) {
    try {
      const { category_key, category_label, attributes } = req.body;

      if (!category_key || !category_label) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'category_key y category_label son requeridos',
        });
      }

      if (!Array.isArray(attributes)) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'attributes debe ser un array',
        });
      }

      // Validar estructura de cada atributo
      for (const attr of attributes) {
        if (!attr.key || !attr.label || !attr.type) {
          return res.status(400).json({
            error: 'VALIDATION_ERROR',
            message: 'Cada atributo debe tener key, label y type',
          });
        }
        if (!['text', 'number', 'select', 'tags', 'boolean'].includes(attr.type)) {
          return res.status(400).json({
            error: 'VALIDATION_ERROR',
            message: 'Tipo de atributo inválido. Valores válidos: text, number, select, tags, boolean',
          });
        }
      }

      const result = await categoryAttributesService.upsertCategoryAttributes(
        category_key,
        category_label,
        attributes as AttributeDefinition[]
      );

      return res.status(200).json(result);
    } catch (error: any) {
      console.error('Error en upsertCategoryAttributes:', error);
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al guardar atributos de categoría'),
      });
    }
  }

  /**
   * DELETE /api/category-attributes/:categoryKey - Eliminar atributos de una categoría
   */
  async delete(req: AuthRequest, res: Response) {
    try {
      const { categoryKey } = req.params;

      if (!categoryKey) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'CategoryKey requerida',
        });
      }

      await categoryAttributesService.deleteCategoryAttributes(categoryKey);

      return res.status(200).json({
        success: true,
        message: 'Atributos de categoría eliminados correctamente',
      });
    } catch (error: any) {
      console.error('Error en deleteCategoryAttributes:', error);
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al eliminar atributos de categoría'),
      });
    }
  }
}

import { Request, Response } from 'express';
import { supabaseAdmin } from '../config/supabase';
import { rebeccaChatService } from '../services/rebecca-chat.service';
import { rebeccaIdentityService } from '../services/rebecca-identity.service';
import { upsertRebeccaLead, appendLeadNote, updateLeadContactInfo, getLeadContextForRebecca, updateLeadStage, updateLeadProfile } from '../services/rebecca-lead.service';
import type { LeadSource } from '../services/rebecca-lead.service';

const WHATSAPP_HISTORY_TTL = 86400 * 7; // 7 días — memoria de conversación extendida
const WHATSAPP_HISTORY_MAX = 40; // Más contexto para evitar redundancia y mantener flujo

/**
 * POST /api/chat/whatsapp
 * Called by n8n instead of running AI Agent in-workflow.
 * Manages conversation history in Redis keyed by phone.
 */
export const whatsappReply = async (req: Request, res: Response) => {
  try {
    const { phone, message } = req.body as { phone?: unknown; message?: unknown };

    if (typeof phone !== 'string' || !phone.trim()) {
      return res.status(400).json({ error: 'phone required' });
    }
    if (typeof message !== 'string' || !message.trim()) {
      return res.status(400).json({ error: 'message required' });
    }
    if (message.length > 4000) {
      return res.status(400).json({ error: 'message too long' });
    }

    const { redis } = await import('../config/redis');
    const historyKey = `whatsapp:history:${phone}`;

    let history: Array<{ role: 'user' | 'assistant'; content: string }> = [];
    if (redis) {
      const raw = await redis.get(historyKey);
      if (raw) {
        try { history = JSON.parse(raw); } catch { /* corrupt cache, start fresh */ }
      }
    }

    const locale = rebeccaIdentityService.detectLocale(message);
    const reply = await rebeccaChatService.replyForChannel('whatsapp', phone, message, history, locale);

    if (redis) {
      history.push({ role: 'user', content: message });
      history.push({ role: 'assistant', content: reply });
      if (history.length > WHATSAPP_HISTORY_MAX) {
        history = history.slice(-WHATSAPP_HISTORY_MAX);
      }
      await redis.set(historyKey, JSON.stringify(history), 'EX', WHATSAPP_HISTORY_TTL);
    }

    // Guardar lead en Supabase (crea o actualiza)
    await upsertRebeccaLead({
      phone,
      source: 'whatsapp_rebecca' as LeadSource,
      last_message: message,
    });

    // Guardar respuesta de Rebecca también
    await appendLeadNote(phone, `Rebecca: ${reply}`);

    return res.status(200).json({ reply });
  } catch (error: any) {
    console.error('[Chat] whatsappReply:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

type ConversationStatus = 'new' | 'in_progress' | 'classified' | 'resolved' | 'escalated';

interface UpdateConversationStatusBody {
  last_response?: string;
  status?: ConversationStatus;
  lead_category?: string;
  bot_status?: string;
}

/**
 * PATCH /api/chat/conversations/:id/status
 * Called by n8n WhatsApp workflow. :id is the contact phone number.
 * Accepts any combination of: last_response, status, lead_category, bot_status.
 */
export const updateConversationStatus = async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const body = req.body as UpdateConversationStatusBody;

    const update: Record<string, string> = {
      updated_at: new Date().toISOString(),
    };

    if (body.status) {
      update.status = body.status;
    }

    if (body.last_response) {
      update.internal_notes = body.last_response;
    }

    if (body.lead_category) {
      update.business_type_confirmed = body.lead_category;
    }

    const fieldCount = Object.keys(update).length - 1; // exclude updated_at

    const { error } = await supabaseAdmin
      .from('leads')
      .update(update)
      .eq('phone', id);

    if (error) throw error;

    return res.status(200).json({ success: true, updated: fieldCount });
  } catch (error: any) {
    console.error('[Chat] updateConversationStatus:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

