// POST /admin/enterprise/create-client

// Alta completa de un cliente Enterprise: crea la marca con plan ENTERPRISE,

// activa la suscripción, registra el pago y genera la notificación de admin.

// ——————————————————————————————————————â

export const createEnterpriseClient = async (req: Request, res: Response) => {

  const {

    name,

    email,

    password,

    slug,

    contact_name,

    phone,

    monthly_amount,     // Mensualidad acordada en COP

    setup_amount,       // Pago único de setup en COP (puede ser 0)

    source_plan,        // Plan previo si la alta enterprise viene de otro ciclo comercial

    months_paid,        // Meses del contrato (1, 3, 6, 12...)

    payment_method,     // 'transfer', 'efectivo', 'wompi', 'otro'

    notes,              // Notas internas del contrato

    products_limit,     // Máximo de productos activos (default 50)

    generations_limit,  // Generaciones por mes (default 2000)

  } = req.body;



  // — Validaciones básicas —————————————————————————

  if (!name || !email || !password || !slug) {

    return res.status(400).json({

      error: 'VALIDATION_ERROR',

      message: 'nombre, email, contraseña y slug son requeridos',

    });

  }

  if (!monthly_amount || Number(monthly_amount) <= 0) {

    return res.status(400).json({

      error: 'VALIDATION_ERROR',

      message: 'monthly_amount debe ser mayor a 0',

    });

  }

  if (!/^[a-z0-9-]+$/.test(slug)) {

    return res.status(400).json({

      error: 'VALIDATION_ERROR',

      message: 'El slug solo puede contener letras minúsculas, números y guiones',

    });

  }



  try {

    // 1. Verificar email único

    const { data: existingEmail } = await supabaseAdmin

      .from('brands')

      .select('id')

      .eq('email', email)

      .maybeSingle();

    if (existingEmail) {

      return res.status(409).json({ error: 'CONFLICT', message: 'El email ya está registrado' });

    }



    // 2. Verificar slug único

    const { data: existingSlug } = await supabaseAdmin

      .from('brands')

      .select('id')

      .eq('slug', slug)

      .maybeSingle();

    if (existingSlug) {

      return res.status(409).json({ error: 'CONFLICT', message: 'El slug ya está en uso' });

    }



    // 3. Hash de contraseña

    const bcrypt = await import('bcryptjs');

    const hashedPassword = await bcrypt.hash(password, 10);



    // 4. Calcular fechas de suscripción

    const now = new Date();

    const contractMonths = Number(months_paid) || 1;

    const normalizedSourcePlan = ['TRIAL', 'BASIC', 'PRO'].includes(String(source_plan || '').toUpperCase()) ? String(source_plan).toUpperCase() : 'NONE';

    const endDate = new Date(now);

    endDate.setMonth(endDate.getMonth() + contractMonths);



    // 5. Crear la marca con plan ENTERPRISE y suscripción activa inmediata

    const { data: newBrand, error: createError } = await supabaseAdmin

      .from('brands')

      .insert({

        email,

        password: hashedPassword,

        name,

        slug,

        contact_name: contact_name || null,

        phone: phone || null,

        plan: 'ENTERPRISE',

        subscription_status: 'active',

        subscription_start_date: now.toISOString(),

        subscription_end_date: endDate.toISOString(),

        last_payment_date: now.toISOString(),

        next_payment_date: endDate.toISOString(),

        email_verified: true, // El admin es responsable de la verificación

        trial_generations_limit: Number(generations_limit) || 2000,

        social_links: normalizedSourcePlan !== 'NONE' ? { acquisition_source_plan: normalizedSourcePlan, enterprise_created_at: now.toISOString() } : { enterprise_created_at: now.toISOString() },

      })

      .select()

      .single();



    if (createError || !newBrand) {

      console.error('[Enterprise] Error creando marca:', createError);

      return res.status(500).json({

        error: 'ERROR_CREATING_BRAND',

        message: sanitizeError(createError, 'Error desconocido al crear la marca'),

      });

    }



    if (normalizedSourcePlan === 'TRIAL') {

      await recordTrialEvent(newBrand.id, 'trial_converted', {

        planPurchased: 'ENTERPRISE',

        sourcePlan: 'TRIAL',

        conversionSource: 'admin_enterprise_create',

      }).catch(() => {});

    }



    // 6. Registrar pago en subscription_payments

    const totalSetup = Number(setup_amount) || 0;

    const totalMonthly = Number(monthly_amount) * contractMonths;

    const totalPaid = totalSetup + totalMonthly;



    await supabaseAdmin.from('subscription_payments').insert({

      brand_id: newBrand.id,

      amount: totalPaid,

      currency: 'COP',

      payment_date: now.toISOString(),

      payment_method: payment_method || 'manual',

      status: 'completed',

      months_paid: contractMonths,

      notes: notes

        ? `[ENTERPRISE] ${notes}`

        : `Alta Enterprise — $${Number(monthly_amount).toLocaleString('es-CO')} COP/mes ñ ${contractMonths} mes(es) + Setup $${totalSetup.toLocaleString('es-CO')} COP`,

    });



    // 7. Notificación de admin

    await supabaseAdmin.from('admin_notifications').insert({

      type: 'new_enterprise_client',

      title: 'Nuevo cliente Enterprise activado',

      message: `${name} (${email}) dado de alta como cliente Enterprise — ${contractMonths} mes(es) de contrato.`,

      severity: 'success',

      brand_id: newBrand.id,

      metadata: {

        monthly_amount: Number(monthly_amount),

        setup_amount: totalSetup,

        total_paid: totalPaid,

        months_paid: contractMonths,

        products_limit: Number(products_limit) || 50,

        generations_limit: Number(generations_limit) || 2000,

        payment_method: payment_method || 'manual',

        source_plan: normalizedSourcePlan,

        subscription_end_date: endDate.toISOString(),

      },

    });



    // 8. Auditoría

    const adminReq = req as any;

    console.log(`[Enterprise] Alta por ${adminReq.admin?.email || 'admin'}: ${name} (${email}) hasta ${endDate.toISOString()}`);



    return res.status(201).json({

      message: 'Cliente Enterprise activado exitosamente',

      brand: {

        id: newBrand.id,

        name: newBrand.name,

        email: newBrand.email,

        slug: newBrand.slug,

        plan: newBrand.plan,

        subscription_status: newBrand.subscription_status,

        subscription_start_date: newBrand.subscription_start_date,

        subscription_end_date: newBrand.subscription_end_date,

      },

      contract: {

        monthly_amount: Number(monthly_amount),

        setup_amount: totalSetup,

        total_paid: totalPaid,

        months_paid: contractMonths,

        subscription_end_date: endDate.toISOString(),

      },

    });

  } catch (err: any) {

    console.error('[Enterprise] Error en createEnterpriseClient:', err);

    return res.status(500).json({ error: sanitizeError(err, 'Error interno del servidor') });

  }

};

import { Request, Response } from 'express';

import { GenerationsService } from '../services/generations.service';

import { ProductsService } from '../services/products.service';

import { asyncHandler, ValidationError } from '../middleware/errorHandler';



const generationsService = new GenerationsService();

const productsService = new ProductsService();



export class GenerationsController {

  getGenerations = asyncHandler(async (req: Request, res: Response) => {

    const brandId = (req as any).brand?.id;

    const limit = Math.min(Number(req.query.limit) || 50, 100);



    const status = (req.query.status as string) || 'SUCCESS';

    const generations = await generationsService.getGenerationsByBrand(brandId, limit, status);



    const productIds = [...new Set(generations.map(g => g.product_id).filter(Boolean))];

    const productMap: Record<string, { name: string; imageUrl: string }> = {};



    await Promise.all(

      productIds.map(async id => {

        try {

          const p = await productsService.getProductById(id);

          if (p) productMap[id] = { name: p.name, imageUrl: p.image_url };

        } catch { /* producto eliminado */ }

      })

    );



    // Ley 1581 Art. 10-C: solo resultImageUrl (imagen generada sintética), nunca selfie_url
    const result = generations

      .map(g => ({

        id: g.id,

        productId: g.product_id,

        productName: productMap[g.product_id]?.name ?? 'Producto eliminado',

        productImageUrl: productMap[g.product_id]?.imageUrl ?? null,

        resultImageUrl: g.result_image_url,
        resultImageDeletedAt: (g as any).result_image_deleted_at ?? null,
        status: g.status,

        error_message: g.error_message,

        generatedAt: g.generated_at,

        processingTime: g.processing_time ?? null,

        has_feedback: g.has_feedback ?? false,

        feedback_types: g.feedback_types ?? [],

        feedback_count: g.feedback_count ?? 0,

      }));



    return res.status(200).json({ generations: result, total: result.length });

  });



  /** DELETE /api/generations/:id — borrar una generación */

  deleteGeneration = asyncHandler(async (req: Request, res: Response) => {

    const brandId = (req as any).brand?.id;

    const { id } = req.params;

    if (!id) throw new ValidationError('ID requerido');

    await generationsService.deleteGeneration(id, brandId);

    return res.status(200).json({ success: true });

  });



  /** DELETE /api/generations — borrado masivo por IDs */

  deleteGenerations = asyncHandler(async (req: Request, res: Response) => {

    const brandId = (req as any).brand?.id;

    const { ids } = req.body as { ids: string[] };

    if (!Array.isArray(ids) || ids.length === 0) throw new ValidationError('Se requiere un array de IDs');

    if (ids.length > 100) throw new ValidationError('Máximo 100 generaciones por operación');

    const deleted = await generationsService.deleteGenerations(ids, brandId);

    return res.status(200).json({ success: true, deleted });

  });

}

import { Request, Response } from 'express';

import axios from 'axios';

import os from 'os';

import { supabaseAdmin } from '../config/supabase';

import { emailService } from '../services/email.service';

import { N8nClient } from '../services/n8n.client';

import { createAdminNotification } from '../utils/adminNotifications';

import { redis } from '../config/redis';



type ServiceStatus = 'ok' | 'degraded' | 'down';



interface ServiceResult {

  status: ServiceStatus;

  latency: number;

}



const n8nClient = new N8nClient();



async function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T> {

  const timeout = new Promise<never>((_, reject) =>

    setTimeout(() => reject(new Error('timeout')), ms)

  );

  return Promise.race([promise, timeout]);

}



async function checkSupabase(): Promise<ServiceResult> {

  const start = Date.now();

  try {

    const { error } = await withTimeout(

      Promise.resolve(supabaseAdmin.from('brands').select('id').limit(1)),

      5000

    );

    

    const latency = Date.now() - start;

    if (error) {

      console.error('[HealthCheck] Supabase error:', error.message);

      return { status: 'degraded', latency };

    }

    return { status: 'ok', latency };

  } catch (err: any) {

    console.error('[HealthCheck] Supabase connection failed:', err.message);

    return { status: 'down', latency: Date.now() - start };

  }

}



async function checkN8n(): Promise<ServiceResult> {

  const start = Date.now();

  // Usar siempre el health endpoint público de n8n, NO el webhook de producción

  // El webhook de tryon es: https://n8n.wilkiedevs.com/webhook/tryon

  // El health endpoint es: https://n8n.wilkiedevs.com/healthz

  const n8nHealthUrl = 'https://n8n.wilkiedevs.com/healthz';



  try {

    await withTimeout(

      axios.get(n8nHealthUrl, {

        timeout: 5000,

        validateStatus: (status) => status >= 200 && status < 300,

      }),

      5000

    );

    return { status: 'ok', latency: Date.now() - start };

  } catch (err: any) {

    if (err.code === 'ECONNREFUSED' || err.code === 'ENOTFOUND') {

      console.error(`[HealthCheck] n8n network error:`, err.message);

      return { status: 'down', latency: Date.now() - start };

    }

    console.error(`[HealthCheck] n8n health check failed:`, err.message);

    return { status: 'degraded', latency: Date.now() - start };

  }

}



async function checkEmail(): Promise<ServiceResult> {

  const start = Date.now();

  try {

    const ok = await withTimeout(emailService.verifyConnection(), 5000);

    const latency = Date.now() - start;

    return { status: ok ? 'ok' : 'degraded', latency };

  } catch (err: any) {

    console.error(`[HealthCheck] Email failed:`, err.message);

    return { status: 'down', latency: Date.now() - start };

  }

}



async function checkMinio(): Promise<ServiceResult> {

  const start = Date.now();

  // Use internal Docker hostname for MinIO health check

  // The public endpoint (minio.wilkiedevs.com) is not reachable from within containers

  const minioHost = 'http://minio:9000';



  try {

    await axios.get(`${minioHost}/minio/health/live`, { timeout: 5000, validateStatus: () => true });

    return { status: 'ok', latency: Date.now() - start };

  } catch (err: any) {

    // MinIO failure is degraded, not down - it's not critical for basic API operation

    console.error(`[HealthCheck] MinIO degraded:`, err.message);

    return { status: 'degraded', latency: Date.now() - start };

  }

}



async function checkRedis(): Promise<ServiceResult> {

  const start = Date.now();

  try {

    // Si lazyConnect y no est�xa1 conectado, marcar down sin esperar

    if ((redis as any).status !== 'ready') {

      return { status: 'down', latency: Date.now() - start };

    }

    const result = await Promise.race([

      redis.ping(),

      new Promise<null>((_, reject) => setTimeout(() => reject(new Error('timeout')), 2000)),

    ]) as string | null;

    if (result === 'PONG') {

      return { status: 'ok', latency: Date.now() - start };

    }

    return { status: 'degraded', latency: Date.now() - start };

  } catch (err: any) {

    console.error(`[HealthCheck] Redis error:`, err.message);

    return { status: 'down', latency: Date.now() - start };

  }

}



const previousStatus: Record<string, ServiceStatus> = {};



function overallStatus(services: Record<string, ServiceResult>): 'healthy' | 'degraded' | 'down' {

  const statuses = Object.values(services).map((s) => s.status);

  if (statuses.includes('down')) return 'down';

  if (statuses.includes('degraded')) return 'degraded';

  return 'healthy';

}



const SERVICE_LABELS: Record<string, string> = {

  supabase: 'Base de datos (Supabase)',

  n8n: 'Automatizaciones (n8n)',

  email: 'Servicio de email (SMTP)',

  minio: 'Almacenamiento (MinIO)',

  redis: 'Redis',

};



const SERVICE_NOTIF_TYPE: Record<string, { down: string; recovered: string }> = {

  supabase: { down: 'service_down', recovered: 'service_recovered' },

  n8n:      { down: 'service_down', recovered: 'service_recovered' },

  email:    { down: 'smtp_down',    recovered: 'smtp_recovered' },

  minio:    { down: 'service_down', recovered: 'service_recovered' },

  redis:    { down: 'service_down', recovered: 'service_recovered' },

};



async function notifyServiceChange(name: string, prev: ServiceStatus, current: ServiceStatus) {

  if (prev === current) return;

  const types = SERVICE_NOTIF_TYPE[name] ?? { down: 'service_down', recovered: 'service_recovered' };

  if (current === 'down' || current === 'degraded') {

    await createAdminNotification({

      type: types.down as any,

      title: `Servicio caído: ${SERVICE_LABELS[name] || name}`,

      message: `${SERVICE_LABELS[name] || name} está ${current === 'down' ? 'caído' : 'degradado'}. Verifica el estado del servicio.`,

      severity: current === 'down' ? 'error' : 'warning',

      metadata: { service: name, status: current, previousStatus: prev },

    });

  } else if (current === 'ok' && (prev === 'down' || prev === 'degraded')) {

    await createAdminNotification({

      type: types.recovered as any,

      title: `Servicio recuperado: ${SERVICE_LABELS[name] || name}`,

      message: `${SERVICE_LABELS[name] || name} volvió a funcionar correctamente.`,

      severity: 'success',

      metadata: { service: name, status: current, previousStatus: prev },

    });

  }

}



export async function getHealth(_req: Request, res: Response): Promise<void> {
  res.status(200).json({ status: 'ok' });
}

export async function getHealthDeep(_req: Request, res: Response): Promise<void> {

  const [supabaseResult, n8nResult, emailResult, minioResult, redisResult] = await Promise.allSettled([

    checkSupabase(),

    checkN8n(),

    checkEmail(),

    checkMinio(),

    checkRedis(),

  ]);



  const servicesMap = {

    supabase: supabaseResult.status === 'fulfilled' ? supabaseResult.value : { status: 'down' as ServiceStatus, latency: 0 },

    n8n: n8nResult.status === 'fulfilled' ? n8nResult.value : { status: 'down' as ServiceStatus, latency: 0 },

    email: emailResult.status === 'fulfilled' ? emailResult.value : { status: 'down' as ServiceStatus, latency: 0 },

    minio: minioResult.status === 'fulfilled' ? minioResult.value : { status: 'down' as ServiceStatus, latency: 0 },

    redis: redisResult.status === 'fulfilled' ? redisResult.value : { status: 'down' as ServiceStatus, latency: 0 },

  };



  const status = overallStatus(servicesMap);



  for (const [name, result] of Object.entries(servicesMap)) {

    const prev = previousStatus[name] ?? 'ok';

    notifyServiceChange(name, prev, result.status).catch(() => {});

    previousStatus[name] = result.status;

  }



  // Formatting for Frontend

  const services = Object.entries(servicesMap).map(([name, result]) => ({

    name: SERVICE_LABELS[name] || name,

    status: result.status === 'ok' ? 'up' : (result.status as 'down' | 'degraded'),

    latency_ms: result.latency,

  }));



  const totalMem = os.totalmem();

  const freeMem = os.freemem();

  const memory = {

    used_mb: (totalMem - freeMem) / 1024 / 1024,

    total_mb: totalMem / 1024 / 1024,

    percent: ((totalMem - freeMem) / totalMem) * 100,

  };



  // CPU usage (1 minute average)

  const cpus = os.cpus();

  let totalIdle = 0, totalTick = 0;

  for (const cpu of cpus) {

    for (const type in cpu.times) {

      totalTick += cpu.times[type as keyof typeof cpu.times];

    }

    totalIdle += cpu.times.idle;

  }

  const cpuPercent = ((totalTick - totalIdle) / totalTick) * 100;



  const body = {

    status,

    timestamp: new Date().toISOString(),

    uptime_seconds: Math.floor(process.uptime()),

    version: '0.9.0-beta.1',

    services,

    database: {

      status: servicesMap.supabase.status === 'ok' ? 'connected' : 'disconnected',

      pool_size: 20,

      active_connections: servicesMap.supabase.status === 'ok' ? 5 : 0,

    },

    memory,

    cpu: {

      percent: cpuPercent,

      cores: cpus.length,

    },

    redis: {

      status: servicesMap.redis.status === 'ok' ? 'connected' : 'disconnected',

    }

  };



  res.status(status === 'down' ? 503 : 200).json(body);

}

import { Request, Response } from 'express';
import { ImageService } from '../services/image.service';
import { asyncHandler, ValidationError } from '../middleware/errorHandler';
import { redis } from '../config/redis';
import crypto from 'crypto';

const imageService = new ImageService();

export class ImageController {
  /**
   * GET /api/images/render
   * Renderiza una imagen con marca de agua dinámica.
   */
  renderImage = asyncHandler(async (req: Request, res: Response) => {
    const { src, plan, download } = req.query as { src: string; plan: string; download?: string };

    if (!src || !plan) {
      throw new ValidationError('Faltan parámetros: src y plan son requeridos');
    }

    // Validar que la URL sea de nuestro MinIO para evitar SSRF
    const allowedHost = process.env.MINIO_PUBLIC_URL || 'https://minio.wilkiedevs.com';
    if (!src.startsWith(allowedHost)) {
      throw new ValidationError('URL de imagen no permitida');
    }

    // — Lógica de Caché con Redis ——————————————————â
    const cacheKey = `img:${plan}:${crypto.createHash('md5').update(src).digest('hex')}`;
    
    try {
      // Intentar obtener de Redis (fallback silencioso si falla la conexión)
      const cached = await redis.getBuffer(cacheKey).catch(() => null);
      
      if (cached) {
        res.setHeader('Content-Type', 'image/jpeg');
        res.setHeader('Cache-Control', 'public, max-age=604800'); // Cache persistente del navegador (1 semana)
        res.setHeader('X-Cache', 'HIT');
        res.setHeader('Access-Control-Allow-Origin', req.headers.origin || '*');
        res.setHeader('Cross-Origin-Resource-Policy', 'cross-origin');

        if (download === 'true') {
          res.setHeader('Content-Disposition', 'attachment; filename="lookitry-result.jpg"');
        }

        return res.send(cached);
      }
    } catch (e) {
      console.warn('[Redis] Fallo en lectura de caché:', e);
    }
    // —————————————————————————————————

    try {
      const processedBuffer = await imageService.processWithWatermark(src, plan);
      
      // Guardar en Redis de forma asíncrona (sin bloquear el response)
      redis.set(cacheKey, processedBuffer, 'EX', 86400).catch(e => {
        console.warn('[Redis] Fallo al guardar en caché:', e);
      });

      // Headers de seguridad y caché
      res.setHeader('Content-Type', 'image/jpeg');
      res.setHeader('Cache-Control', 'public, max-age=604800');
      res.setHeader('X-Cache', 'MISS');
      res.setHeader('Access-Control-Allow-Origin', req.headers.origin || '*');
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      res.setHeader('Cross-Origin-Resource-Policy', 'cross-origin');

      if (download === 'true') {
        res.setHeader('Content-Disposition', 'attachment; filename="lookitry-result.jpg"');
      }
      
      return res.send(processedBuffer);
    } catch (error: any) {
      console.error('[ImageController] Error en render:', error.message);
      return res.redirect(src);
    }
  });
}

import { Request, Response } from 'express';

import { sanitizeError } from '../utils/sanitizeError';

import { supabaseAdmin } from '../config/supabase';



export type NotificationType =

  | 'new_brand'

  | 'upgrade_request'

  | 'plan_change_request'

  | 'trial_expiring'

  | 'trial_expired'

  | 'trial_converted'

  | 'high_usage'

  | 'credits_exhausted'

  | 'suspended'

  | 'payment_received'

  | 'multi_month_purchase'

  | 'subscription_expiring'

  | 'service_down'

  | 'service_recovered'

  | 'smtp_down'

  | 'smtp_recovered'

  | 'plugin_error_spike';



export interface AdminNotification {

  id: string;

  type: NotificationType;

  title: string;

  message: string;

  brandId?: string;

  brandName?: string;

  createdAt: string;

  severity: 'info' | 'warning' | 'error' | 'success';

  metadata?: Record<string, unknown>;

}



export interface NotificationPreference {

  type: NotificationType;

  enabled: boolean;

}



const BASIC_LIMIT = 100;

const PRO_LIMIT = 1200;



/** Carga las preferencias activas desde Supabase. Devuelve un Set de tipos desactivados. */

async function getDisabledTypes(): Promise<Set<string>> {

  const { data } = await supabaseAdmin

    .from('admin_notification_preferences')

    .select('type, enabled')

    .eq('enabled', false);

  return new Set((data ?? []).map((r: { type: string }) => r.type));

}



export async function getAdminNotifications(_req: Request, res: Response): Promise<void> {

  try {

    const now = new Date();

    const last7Days = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);



    const [brandsRes, generationsRes, paymentsRes, persistentRes, disabledTypes] = await Promise.all([

      supabaseAdmin

        .from('brands')

        .select('id, name, email, plan, subscription_status, trial_end_date, subscription_end_date, created_at, upgrade_requested_at')

        .order('created_at', { ascending: false }),

      supabaseAdmin

        .from('generations')

        .select('brand_id, generated_at')

        .gte('generated_at', last7Days.toISOString()),

      supabaseAdmin

        .from('subscription_payments')

        .select('id, brand_id, amount, status, months_paid, created_at, brands(name)')

        .eq('status', 'completed')

        .gte('created_at', last7Days.toISOString())

        .order('created_at', { ascending: false })

        .limit(20),

      supabaseAdmin

        .from('admin_notifications')

        .select('*')

        .gte('created_at', last7Days.toISOString())

        .order('created_at', { ascending: false })

        .limit(200),

      getDisabledTypes(),

    ]);



    const brands = brandsRes.data || [];

    const generations = generationsRes.data || [];

    const payments = paymentsRes.data || [];

    const persistentNotifications = persistentRes.data || [];

    const notifications: AdminNotification[] = [];



    const push = (n: AdminNotification) => {

      if (!disabledTypes.has(n.type)) notifications.push(n);

    };



    // 1. Marcas nuevas (últimos 7 días)

    brands

      .filter(b => new Date(b.created_at) >= last7Days)

      .forEach(b => push({

        id: 'new_brand_' + b.id,

        type: 'new_brand',

        title: 'Nueva marca registrada',

        message: `${b.name} (${b.email}) se registró en el plan ${b.plan}`,

        brandId: b.id, brandName: b.name,

        createdAt: b.created_at, severity: 'info',

      }));



    // 2. Solicitudes de upgrade pendientes

    brands

      .filter(b => b.upgrade_requested_at)

      .forEach(b => push({

        id: 'upgrade_' + b.id,

        type: 'upgrade_request',

        title: 'Solicitud de upgrade a Pro',

        message: `${b.name} solicitó actualizar al Plan Pro`,

        brandId: b.id, brandName: b.name,

        createdAt: b.upgrade_requested_at, severity: 'warning',

      }));



    // 3. Trials por vencer (1-3 días)

    brands
      .filter(b => {
        if (!b.trial_end_date) return false;
        const daysLeft = Math.ceil((new Date(b.trial_end_date).getTime() - now.getTime()) / 86400000);
        return daysLeft >= 0 && daysLeft <= 3;
      })
      .forEach(b => {

        const daysLeft = Math.ceil((new Date(b.trial_end_date).getTime() - now.getTime()) / 86400000);

        push({

          id: 'trial_expiring_' + b.id,

          type: 'trial_expiring',

          title: 'Trial por vencer',

          message: `${b.name} tiene ${daysLeft} día${daysLeft !== 1 ? 's' : ''} restante${daysLeft !== 1 ? 's' : ''} de prueba`,

          brandId: b.id, brandName: b.name,

          createdAt: now.toISOString(), severity: 'warning',

        });

      });



    // 4. Trials vencidos sin convertir

    brands
      .filter(b => {
        if (!b.trial_end_date) return false;
        return new Date(b.trial_end_date) < now &&
          b.subscription_status !== 'suspended';
      })
      .slice(0, 5)

      .forEach(b => push({

        id: 'trial_expired_' + b.id,

        type: 'trial_expired',

        title: 'Trial vencido sin conversión',

        message: `${b.name} terminó su prueba y no ha contratado un plan`,

        brandId: b.id, brandName: b.name,

        createdAt: b.trial_end_date, severity: 'error',

      }));



    // 5. Suscripción activa por vencer (â¤7 días)

    brands
      .filter(b => {
        if (!b.subscription_end_date) return false;
        if (b.trial_end_date && new Date(b.trial_end_date) > now) return false;
        if (b.subscription_status !== 'active' && b.subscription_status !== 'expiring_soon') return false;
        const daysLeft = Math.ceil((new Date(b.subscription_end_date).getTime() - now.getTime()) / 86400000);
        return daysLeft >= 0 && daysLeft <= 7;
      })

      .forEach(b => {

        const daysLeft = Math.ceil((new Date(b.subscription_end_date).getTime() - now.getTime()) / 86400000);

        push({

          id: 'sub_expiring_' + b.id,

          type: 'subscription_expiring',

          title: 'Suscripción por vencer',

          message: `${b.name} (${b.plan}) vence en ${daysLeft} día${daysLeft !== 1 ? 's' : ''}`,

          brandId: b.id, brandName: b.name,

          createdAt: now.toISOString(),

          severity: daysLeft <= 2 ? 'error' : 'warning',

          metadata: { plan: b.plan, daysLeft },

        });

      });



    // 6. Créditos agotados (100%) y uso alto (â¥80%)

    const genByBrand: Record<string, number> = {};

    generations.forEach(g => { genByBrand[g.brand_id] = (genByBrand[g.brand_id] || 0) + 1; });



    brands.forEach(b => {

      const used = genByBrand[b.id] || 0;

      const limit = b.plan === 'PRO' ? PRO_LIMIT : BASIC_LIMIT;

      const pct = (used / limit) * 100;

      if (pct >= 100) {

        push({

          id: 'credits_exhausted_' + b.id,

          type: 'credits_exhausted',

          title: 'Créditos agotados',

          message: `${b.name} agotó sus ${limit} generaciones del mes`,

          brandId: b.id, brandName: b.name,

          createdAt: now.toISOString(), severity: 'error',

          metadata: { used, limit, plan: b.plan },

        });

      } else if (pct >= 80) {

        push({

          id: 'high_usage_' + b.id,

          type: 'high_usage',

          title: 'Uso alto de generaciones',

          message: `${b.name} usó ${used} de ${limit} generaciones este mes (${Math.round(pct)}%)`,

          brandId: b.id, brandName: b.name,

          createdAt: now.toISOString(), severity: 'warning',

          metadata: { used, limit, pct: Math.round(pct) },

        });

      }

    });



    // 7. Marcas suspendidas

    brands

      .filter(b => b.subscription_status === 'suspended')

      .slice(0, 5)

      .forEach(b => push({

        id: 'suspended_' + b.id,

        type: 'suspended',

        title: 'Marca suspendida',

        message: `${b.name} tiene su cuenta suspendida`,

        brandId: b.id, brandName: b.name,

        createdAt: now.toISOString(), severity: 'error',

      }));



    // 8. Pagos recibidos

    payments.forEach((p: any) => {

      const brandName = p.brands?.name || 'Marca desconocida';

      const months = p.months_paid || 1;

      if (months > 1) {

        const discountPct = months >= 12 ? 15 : months >= 6 ? 10 : months >= 3 ? 5 : 0;

        push({

          id: 'payment_' + p.id,

          type: 'multi_month_purchase',

          title: `Compra de ${months} meses`,

          message: `${brandName} pagó ${months} meses por adelantado${discountPct > 0 ? ` (${discountPct}% descuento)` : ''}`,

          brandId: p.brand_id, brandName,

          createdAt: p.created_at, severity: 'success',

          metadata: { months, amount: p.amount, discountPct },

        });

      } else {

        push({

          id: 'payment_' + p.id,

          type: 'payment_received',

          title: 'Pago recibido',

          message: `${brandName} realizó un pago de ${Number(p.amount).toLocaleString('es-CO')} COP`,

          brandId: p.brand_id, brandName,

          createdAt: p.created_at, severity: 'success',

        });

      }

    });



    // 9. Notificaciones persistentes (n8n, health, acciones del cliente)

    const dynamicIds = new Set(notifications.map(n => n.id));

    persistentNotifications.forEach((n: any) => {

      if (disabledTypes.has(n.type)) return;

      if (n.type === 'upgrade_request' && dynamicIds.has('upgrade_' + n.brand_id)) return;

      push({

        id: 'persistent_' + n.id,

        type: n.type as NotificationType,

        title: n.title,

        message: n.message,

        brandId: n.brand_id,

        brandName: n.brand_name,

        createdAt: n.created_at,

        severity: n.severity,

        metadata: n.metadata || {},

      });

    });



    notifications.sort((a, b) => {

      // Prioridad: 1=cliente (pagos, upgrades, nuevas marcas), 2=alertas, 3=sistema

      const priority = (n: AdminNotification): number => {

        if (['payment_received', 'multi_month_purchase', 'upgrade_request', 'plan_change_request', 'trial_converted', 'new_brand'].includes(n.type)) return 1;

        if (['credits_exhausted', 'suspended', 'trial_expired', 'subscription_expiring'].includes(n.type)) return 2;

        if (['trial_expiring', 'high_usage'].includes(n.type)) return 3;

        return 4; // sistema

      };

      const pa = priority(a), pb = priority(b);

      if (pa !== pb) return pa - pb;

      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();

    });

    res.json({ notifications, total: notifications.length });

  } catch (error: any) {

    console.error('Error in getAdminNotifications:', error);

    res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al obtener notificaciones' });

  }

}



