import { Response } from 'express';
import { AuthRequest } from '../middleware/auth';
import { addonCreditsService } from '../services/addonCredits.service';
import { sanitizeError } from '../utils/sanitizeError';

export class PaymentsController {
  async checkoutAddon(req: AuthRequest, res: Response) {
    try {
      if (!req.brand?.id) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'Debes iniciar sesión para comprar créditos extra',
        });
      }

      const { gateway, packageId } = req.body || {};
      const result = await addonCreditsService.createCheckoutForBrand(req.brand.id, gateway, packageId);

      return res.status(200).json(result);
    } catch (error: any) {
      return res.status(400).json({
        error: 'BAD_REQUEST',
        message: sanitizeError(error, 'No se pudo iniciar el checkout del add-on'),
      });
    }
  }

  async verifyAddon(req: AuthRequest, res: Response) {
    try {
      if (!req.brand?.id) {
        return res.status(401).json({ error: 'UNAUTHORIZED' });
      }

      const { reference } = req.body;
      if (!reference) return res.status(400).json({ error: 'Falta la referencia' });

      // Verificar en Wompi primero
      const { wompiService } = require('../services/wompi.service');
      const tx = await wompiService.getTransactionByReference(reference);

      if (tx && tx.status === 'APPROVED') {
        await addonCreditsService.applyPurchasedCredits(
          reference,
          'wompi',
          tx.amount_in_cents / 100,
          String(tx.id)
        );
        return res.status(200).json({ status: 'applied_now', message: 'Compra unificada (Wompi).' });
      }

      // Si no es Wompi, verificamos en PayPal
      const { paypalService } = require('../services/paypal.service');
      const paypalOrder = await paypalService.getTrackedOrder(reference);
      if (paypalOrder && paypalOrder.order_id) {
        const order = await paypalService.getOrder(paypalOrder.order_id);
        if (order && (order.status === 'COMPLETED' || order.status === 'APPROVED')) {
           // En caso de que haya quedado en APPROVED, idealmente la captura se debió hacer en paypal.controller
           // pero si no, igual la aplicamos (idealmente el webhook o /capture la captura).
           await addonCreditsService.applyPurchasedCredits(
               reference,
               'paypal',
               paypalOrder.amount_usd_expected,
               paypalOrder.order_id
           );
           return res.status(200).json({ status: 'applied_now', message: 'Compra unificada (PayPal).' });
        }
      }

      return res.status(200).json({ status: 'pending_or_not_found' });
    } catch (error: any) {
      // Ignorar errores silenciándolos, puede que ya se haya aplicado (violación Unique)
      if (error.message?.includes('violates unique constraint')) {
        return res.status(200).json({ status: 'already_applied' });
      }
      console.error('[PaymentsController] Error en verifyAddon:', error);
      return res.status(500).json({ error: 'Error verificando el add-on' });
    }
  }
}

export const paymentsController = new PaymentsController();

import { Request, Response } from 'express';

import { paypalService } from '../services/paypal.service';

import { SubscriptionService } from '../services/subscription.service';

import { supabaseAdmin } from '../config/supabase';

import { asyncHandler } from '../middleware/errorHandler';

import { pricingService } from '../services/pricing.service';

import { NotificationService } from '../services/notification.service';

import { addonCreditsService } from '../services/addonCredits.service';

import { planChangeService } from '../services/planChange.service';

import { hasActivePaidSubscription, isTrialLandingBlocked } from '../utils/brandLifecycle';



const subscriptionService = new SubscriptionService();

const notificationService = new NotificationService();



// Tolerancia de monto: 2% o mínimo $0.50 para prevenir manipulación

const PAYPAL_AMOUNT_TOLERANCE_PCT = 0.02;

const PAYPAL_AMOUNT_TOLERANCE_MIN = 0.50;



function getPaypalTolerance(expectedAmount: number): number {

  return Math.max(expectedAmount * PAYPAL_AMOUNT_TOLERANCE_PCT, PAYPAL_AMOUNT_TOLERANCE_MIN);

}



const PAYPAL_AMOUNT_TOLERANCE = 0.01; // Mantenido para compatibilidad legacy



async function insertPaypalPaymentCompat(payload: Record<string, unknown>) {

  let result = await supabaseAdmin.from('subscription_payments').insert(payload);



  if (result.error?.message?.toLowerCase().includes('reference') && 'reference' in payload) {

    const { reference, ...fallbackPayload } = payload;

    result = await supabaseAdmin.from('subscription_payments').insert(fallbackPayload);

  }



  if (result.error) {

    throw new Error(result.error.message);

  }

}



function parsePaypalReference(reference: string): {

  brandId: string | null;

  months: number;

  plan: string;

  isNewRegistration: boolean;

  isTrial: boolean;

} {

  if (reference.startsWith('GUEST-TRIAL-')) {

    return {

      brandId: null,

      months: 0,

      plan: 'TRIAL',

      isNewRegistration: true,

      isTrial: true,

    };

  }



  if (reference.startsWith('TRIAL-')) {

    const parts = reference.split('-');

    return {

      brandId: parts.slice(1, -1).join('-'),

      months: 0,

      plan: 'TRIAL',

      isNewRegistration: false,

      isTrial: true,

    };

  }



  const match = reference.match(/PAYPAL-(.+)-M(\d+)-P([^-]+)/);

  if (!match) {

    throw new Error(`Referencia inválida o malformada: ${reference}`);

  }



  const brandIdOrVisitor = match[1];



  return {

    brandId: brandIdOrVisitor.startsWith('visitor_') ? null : brandIdOrVisitor,

    months: parseInt(match[2], 10),

    plan: match[3],

    isNewRegistration: brandIdOrVisitor.startsWith('visitor_'),

    isTrial: false,

  };

}



function assertTrackedOrder(reference: string, trackedOrder: any, orderId: string, amountUSD: number) {

  if (!trackedOrder) {

    throw new Error('No se encontró la orden interna de PayPal para esta referencia');

  }



  if (trackedOrder.order_id && trackedOrder.order_id !== orderId) {

    throw new Error('La orden de PayPal no coincide con la referencia registrada');

  }



  if (Math.abs(Number(trackedOrder.amount_usd_expected) - amountUSD) > PAYPAL_AMOUNT_TOLERANCE) {

    throw new Error('El monto capturado no coincide con el monto esperado');

  }

}



async function fulfillPaypalPayment(reference: string, orderId: string, amountUSD: number, source: 'capture' | 'webhook') {

  if (addonCreditsService.isAddonReference(reference)) {

    await addonCreditsService.applyPurchasedCredits(reference, 'paypal', amountUSD, orderId);

    return;

  }



  const { brandId, months, plan, isNewRegistration, isTrial } = parsePaypalReference(reference);

  const includesLanding = reference.includes('LANDING');

  const notesPrefix = source === 'webhook' ? 'PayPal webhook' : 'PayPal';



  if (isTrial && brandId) {

    await supabaseAdmin

      .from('brands')

      .update({ plan: 'TRIAL', trial_payment_status: 'active' })

      .eq('id', brandId);



    await insertPaypalPaymentCompat({

      brand_id: brandId,

      amount: amountUSD,

      currency: 'USD',

      payment_method: 'paypal',

      status: 'completed',

      months_paid: 1,

      reference,

      notes: `${notesPrefix} orderId=${orderId}. Trial`,

    });

    return;

  }



  if (isNewRegistration) {

    const { data: pendingRegistration } = await supabaseAdmin

      .from('pending_registrations')

      .select('email, reference, plan, amount, status')

      .eq('reference', reference)

      .maybeSingle();



    const wasPending = pendingRegistration?.status === 'pending';



    await supabaseAdmin

      .from('pending_registrations')

      .update({

        status: 'paid',

        payment_id: orderId,

      })

      .eq('reference', reference);



    if (wasPending && pendingRegistration?.email && ['BASIC', 'PRO'].includes((pendingRegistration.plan || '').toUpperCase())) {

      notificationService.sendCompleteRegistrationEmail({

        email: pendingRegistration.email,

        reference: pendingRegistration.reference,

        plan: pendingRegistration.plan,

        amount: pendingRegistration.amount,

      }).catch(err => console.error('[PayPal] Error email registro pendiente:', err));

    }

    return;

  }



  if (!brandId) {

    return;

  }



  const { data: currentBrand } = await supabaseAdmin.from('brands').select('*').eq('id', brandId).single();

  if (plan === 'NONE' && currentBrand && isTrialLandingBlocked(currentBrand)) {

    throw new Error('TRIAL_LANDING_BLOCKED');

  }



  if (plan === 'NONE') {

    const { data: existingLandingPayment } = await supabaseAdmin

      .from('subscription_payments')

      .select('id')

      .eq('reference', reference)

      .limit(1)

      .maybeSingle();



    if (!existingLandingPayment) {

      await insertPaypalPaymentCompat({

        brand_id: brandId,

        amount: amountUSD,

        currency: 'USD',

        payment_method: 'paypal',

        status: 'completed',

        months_paid: 1,

        reference,

        notes: `SOLO Landing Page. ${notesPrefix} orderId=${orderId}`,

      });

    }



    await supabaseAdmin

      .from('brands')

      .update({ has_landing_page: true, landing_suspended_at: null })

      .eq('id', brandId);

    return;

  }



  // BUG #3 FIX: Detectar si es un upgrade (BASIC â PRO) para pasar isUpgrade=true

  // Esto activa la lógica de prorrateo en renewSubscription (newStartDate = now, no acumula)

  const isActualUpgrade =

    hasActivePaidSubscription(currentBrand) && currentBrand?.plan === 'BASIC' && String(plan).toUpperCase() === 'PRO';



  try {

    if (isActualUpgrade) {

      await planChangeService.markProcessing(reference, amountUSD);

    }



    if (isActualUpgrade && amountUSD <= PAYPAL_AMOUNT_TOLERANCE && !includesLanding) {

      const newPlanTotal = await pricingService.calculateTotal('PRO', months, false);

      const preview = await subscriptionService.calculateUpgradeProration(

        brandId,

        'PRO',

        months,

        newPlanTotal,

        0

      );



      await subscriptionService.applyFreeUpgrade(

        brandId,

        'PRO',

        months,

        preview.creditAmount,

        preview.newPlanTotal,

        reference,

        preview.newEndDate

      );



      await planChangeService.markCompleted(reference, 0);

      return;

    }



    await subscriptionService.renewSubscription(

      brandId,

      {

        brand_id: brandId,

        amount: amountUSD,

        currency: 'USD',

        payment_method: 'paypal',

        status: 'completed',

        months_paid: months,

        payment_date: new Date().toISOString(),

        notes: `${notesPrefix} orderId=${orderId}. Ref=${reference}. Plan=${plan}. Meses=${months}.${includesLanding ? ' Incluye Landing Page.' : ''}`,

        reference,

      },

      months,

      plan as string,

      isActualUpgrade

    );



    if (isActualUpgrade) {

      await planChangeService.markCompleted(reference, amountUSD);

    }

  } catch (error) {

    if (isActualUpgrade) {

      await planChangeService.markFailed(reference, (error as Error)?.message || 'Error procesando upgrade PayPal');

    }

    throw error;

  }



  if (includesLanding) {

    await supabaseAdmin

      .from('brands')

      .update({ has_landing_page: true, landing_suspended_at: null })

      .eq('id', brandId);

  }

}



export class PaypalController {

  getCheckoutUrl = asyncHandler(async (req: Request, res: Response) => {

    const { months, plan, email, trm, includes_landing } = req.query;

    const brand = (req as any).brand;



    if (!months || !plan) {

      return res.status(400).json({ error: 'Faltan parámetros requeridos: months, plan' });

    }



    // SECURITY: If authenticated, the email must match the session email.

    // Prevents creating orders for a different account while logged in.

    if (brand?.id && email && brand.email && String(email).trim().toLowerCase() !== brand.email.toLowerCase()) {

      return res.status(403).json({

        error: 'EMAIL_MISMATCH',

        message: 'El email del checkout debe coincidir con el email de tu cuenta activa.',

      });

    }



    const selectedMonths = parseInt(months as string, 10);

    const planStr = (plan as string).toUpperCase();

    const landing = includes_landing === 'true';

    if ((req as any).brand?.id && landing && planStr === 'NONE') {

      const { data: currentBrand } = await supabaseAdmin.from('brands').select('*').eq('id', (req as any).brand.id).single();

      if (currentBrand && isTrialLandingBlocked(currentBrand)) {

        return res.status(403).json({ error: 'TRIAL_LANDING_BLOCKED', message: 'La mini-landing requiere primero activar un plan pago.' });

      }

    }



    const hasAuthenticatedBrand = Boolean((req as any).brand?.id);

    if (hasAuthenticatedBrand && planStr === 'TRIAL') {

      const { data: brandData } = await supabaseAdmin

        .from('brands')

        .select('trial_end_date, trial_generations_limit')

        .eq('id', (req as any).brand.id)

        .maybeSingle();



      const hasHadTrial = brandData?.trial_end_date !== null || brandData?.trial_generations_limit !== null;

      

      if (hasHadTrial) {

        return res.status(409).json({

          error: 'TRIAL_ALREADY_USED',

          message: 'Ya usaste tu prueba gratuita. ¡Upgrade a Basic o Pro para continuar!',

        });

      }

      // Si no ha tenido trial, permitir comprar trial para su cuenta existente

    }



    let amountCOP = hasAuthenticatedBrand

      ? await pricingService.calculateTotal(planStr, selectedMonths, landing)

      : await pricingService.calculateExternalCheckoutTotal(planStr, selectedMonths, landing);



    if (hasAuthenticatedBrand && planStr === 'PRO') {

      const { data: currentBrand } = await supabaseAdmin

        .from('brands')

        .select('plan, subscription_status, trial_end_date, trial_payment_status')

        .eq('id', (req as any).brand.id)

        .single();



      const isActualUpgrade =

        hasActivePaidSubscription(currentBrand) &&

        currentBrand?.plan === 'BASIC';



      console.log(`[PaypalCheckout] brand=${(req as any).brand.id} plan=${currentBrand?.plan} status=${currentBrand?.subscription_status} isActualUpgrade=${isActualUpgrade}`);



      if (isActualUpgrade) {

        const planOnlyTotal = await pricingService.calculateTotal(planStr, selectedMonths, false);

        const preview = await subscriptionService.calculateUpgradeProration(

          (req as any).brand.id,

          'PRO',

          selectedMonths,

          planOnlyTotal,

          0

        );



        const landingAmount = landing

          ? await pricingService.calculateTotal(planStr, selectedMonths, true) - planOnlyTotal

          : 0;



        amountCOP = Math.max(0, preview.amountToPay + landingAmount);

        console.log(`[PaypalCheckout] Proration aplicada: credit=${preview.creditAmount} amountToPay=${preview.amountToPay} amountCOP=${amountCOP}`);

      } else {

        console.log(`[PaypalCheckout] Sin proration. Cobro completo: ${amountCOP} COP`);

      }

    }



    const overrideTrm = trm ? parseFloat(trm as string) : undefined;
    const { trm: currentTrm, source } = await pricingService.getEffectiveTrm(overrideTrm);
    console.log(`[PaypalController] TRM usada para checkout: ${currentTrm} (source=${source})`);

    const brandId = (req as any).brand?.id || `visitor_${crypto.randomUUID()}`;
    const reference = `PAYPAL-${brandId}-M${selectedMonths}-P${planStr}${landing ? '-LANDING' : ''}-${Date.now()}`;
    const frontendUrl = process.env.FRONTEND_URL || 'https://lookitry.com';
    const isVisitorCheckout = !hasAuthenticatedBrand && Boolean(email);
    const publicOnboardingPath = `/onboarding-post-pago?ref=${encodeURIComponent(reference)}&method=paypal`;
    const dashboardSuccessPath = `/pago-exitoso?method=paypal&ref=${encodeURIComponent(reference)}`;
    const returnUrl = `${frontendUrl}${isVisitorCheckout ? publicOnboardingPath : dashboardSuccessPath}`;
    const cancelUrl = `${frontendUrl}${hasAuthenticatedBrand ? '/dashboard/checkout' : '/checkout'}`;

    if (isVisitorCheckout) {
      const { error: insertError } = await supabaseAdmin.from('pending_registrations').insert({
        email: email as string,
        reference,
        plan: planStr,
        months: selectedMonths,
        amount: amountCOP,

        includes_landing: landing,

        status: 'pending',

      });



      if (insertError) {

        console.error('[Paypal] Error al insertar registro pendiente:', insertError.message);

        return res.status(500).json({ error: 'Error al iniciar el registro' });

      }

    }



    let createdOrder;

    try {

      createdOrder = await paypalService.createOrder(amountCOP, currentTrm, reference, returnUrl, cancelUrl, planStr);

    } catch (paypalError: any) {

      console.error('[Paypal] Error al crear orden PayPal:', paypalError.response?.data || paypalError.message);

      const statusCode = paypalError.response?.status || 500;

      const paypalMessage = paypalError.response?.data?.message || paypalError.response?.data?.details?.[0]?.description || 'Error al procesar con PayPal';

      return res.status(statusCode).json({

        error: 'PAYPAL_ERROR',

        message: paypalMessage,

        details: paypalError.response?.data?.details || []

      });

    }

    await paypalService.recordOrder({

      reference,

      brand_id: (req as any).brand?.id || null,

      email: email ? String(email) : null,

      plan: planStr,

      months: selectedMonths,

      amount_cop: amountCOP,

      trm: currentTrm,

      amount_usd_expected: createdOrder.amountUSD,

      order_id: createdOrder.orderId,

      status: 'created',

    });



    if (hasAuthenticatedBrand && planStr === 'PRO') {

      const { data: currentBrand } = await supabaseAdmin.from('brands').select('plan, subscription_status, trial_end_date').eq('id', (req as any).brand.id).single();

      if (hasActivePaidSubscription(currentBrand) && currentBrand?.plan === 'BASIC') {

        await planChangeService.createPending({

          brandId: (req as any).brand.id,

          reference,

          source: 'paypal',

          fromPlan: currentBrand?.plan || null,

          toPlan: 'PRO',

          months: selectedMonths,

          amountExpected: amountCOP,

          metadata: { includesLanding: landing, amountUsdExpected: createdOrder.amountUSD },

        });

      }

    }



    return res.status(200).json({ checkoutUrl: createdOrder.checkoutUrl, reference });

  });



  capturePayment = asyncHandler(async (req: Request, res: Response) => {

    const { orderId, reference: requestedReference } = req.body;



    if (!orderId) {

      return res.status(400).json({ error: 'orderId es requerido' });

    }



    // Idempotencia: si la referencia ya está completada en DB, retornar éxito sin re-procesar

    if (requestedReference) {

      const existingByRef = await paypalService.getTrackedOrder(requestedReference);

      if (existingByRef?.status === 'completed') {

        console.log(`[PaypalCapture] Orden ya procesada (by ref): ${requestedReference}`);

        return res.status(200).json({

          success: true,

          message: 'Pago ya procesado anteriormente',

          orderId,

          status: 'COMPLETED',

          reference: requestedReference,

          alreadyProcessed: true,

        });

      }

    }



    const order = await paypalService.getOrder(orderId);

    const resolvedReference = paypalService.extractReference(order);

    if (!resolvedReference) {

      throw new Error('No se pudo resolver la referencia interna del pago PayPal');

    }



    if (requestedReference && requestedReference !== resolvedReference) {

      return res.status(409).json({ error: 'La referencia no coincide con la orden de PayPal' });

    }



    const trackedOrder = await paypalService.getTrackedOrder(resolvedReference);



    // Idempotencia atómica: intentar adquirir lock de procesamiento

    if (trackedOrder?.status === 'pending' || trackedOrder?.status === 'failed') {

      const acquired = await paypalService.tryStartProcessing(resolvedReference);

      if (!acquired) {

        console.log(`[PaypalCapture] Orden siendo procesada por otra request: ${resolvedReference}`);

        return res.status(200).json({

          success: true,

          message: 'Pago siendo procesado',

          orderId,

          status: 'PROCESSING',

          reference: resolvedReference,

          alreadyProcessed: true,

        });

      }

    } else if (trackedOrder?.status === 'completed') {

      console.log(`[PaypalCapture] Orden ya completada en DB: ${resolvedReference}`);

      return res.status(200).json({

        success: true,

        message: 'Pago ya procesado anteriormente',

        orderId,

        status: 'COMPLETED',

        reference: resolvedReference,

        alreadyProcessed: true,

      });

    }



    const orderAmountUSD = paypalService.extractAmountUsd(order);

    if (orderAmountUSD == null) {

      throw new Error('No se pudo validar el monto de la orden PayPal');

    }

    assertTrackedOrder(resolvedReference, trackedOrder, orderId, orderAmountUSD);



    let effectiveOrder = order;

    if (order.status === 'APPROVED') {

      effectiveOrder = await paypalService.captureOrder(orderId);

    } else if (order.status === 'COMPLETED') {

      // Orden ya capturada en PayPal (PAY_NOW sandbox o webhook previo)

      effectiveOrder = order;

    } else {

      throw new Error(`El pago no se completó (Status: ${order.status})`);

    }



    const amountUSD = paypalService.extractAmountUsd(effectiveOrder);

    if (amountUSD == null) {

      throw new Error('No se pudo validar el monto capturado en PayPal');

    }

    // Usar el monto de la orden rastreada si PayPal devuelve algo distinto dentro de tolerancia

    const finalAmount = trackedOrder && Math.abs(amountUSD - Number(trackedOrder.amount_usd_expected)) > PAYPAL_AMOUNT_TOLERANCE

      ? Number(trackedOrder.amount_usd_expected)

      : amountUSD;



    assertTrackedOrder(resolvedReference, trackedOrder, orderId, finalAmount);



    await fulfillPaypalPayment(resolvedReference, orderId, finalAmount, 'capture');

    await paypalService.markOrderStatus(resolvedReference, 'completed', orderId);



    return res.status(200).json({

      success: true,

      message: 'Pago capturado y suscripción activada',

      orderId,

      status: effectiveOrder.status,

      reference: resolvedReference,

    });

  });



  handleWebhook = asyncHandler(async (req: Request, res: Response) => {

    const event = req.body;

    console.log(`[PayPal Webhook] Evento recibido: ${event.event_type}`);



    const isValid = await paypalService.verifyWebhookSignature(req);

    if (!isValid) {

      return res.status(401).json({ error: 'Firma inválida' });

    }



    if (event.event_type === 'PAYMENT.CAPTURE.COMPLETED') {

      const resource = event.resource;

      const captureId = resource.id;

      const amountUSD = parseFloat(resource.amount.value);

      const reference =

        resource.custom_id ||

        resource.invoice_id ||

        resource.supplementary_data?.related_ids?.order_id;

      const orderId = resource.supplementary_data?.related_ids?.order_id || captureId;



      // Log sanitizado (sin exponer referencias completas)

      const refShort = reference ? `${reference.slice(0, 12)}...` : 'N/A';

      console.log(`[PayPal Webhook] Pago completado. CaptureId: ${captureId}, Monto: ${amountUSD}, Ref: ${refShort}`);



      if (

        reference &&

        (

          reference.startsWith('PAYPAL-') ||

          reference.startsWith('TRIAL-') ||

          reference.startsWith('GUEST-TRIAL-') ||

          addonCreditsService.isAddonReference(reference)

        )

      ) {

        const trackedOrder = await paypalService.getTrackedOrder(reference);

        assertTrackedOrder(reference, trackedOrder, orderId, amountUSD);

        await fulfillPaypalPayment(reference, orderId, amountUSD, 'webhook');

        await paypalService.markOrderStatus(reference, 'completed', orderId);

      }

    }



    return res.status(200).json({ received: true });

  });

}

import { Response } from 'express';
import { ProductsService, CreateProductDto, UpdateProductDto } from '../services/products.service';
import { AuthRequest } from '../middleware/auth';
import { invalidateBrandConfigCache } from '../utils/brandConfigCache';
import { sanitizeError } from '../utils/sanitizeError';
import { descriptorService } from '../services/ai-descriptor/ai-descriptor.service';

const productsService = new ProductsService();

export class ProductsController {
  /**
   * GET /api/products - Listar productos de la marca autenticada
   */
  async getProducts(req: AuthRequest, res: Response) {
    try {
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      const products = await productsService.getProductsByBrand(req.brand.id);
      const { currentCount, limit } = await productsService.canCreateProduct(req.brand.id);

      return res.status(200).json({
        products,
        count: currentCount,
        limit,
      });
    } catch (error: any) {
      console.error('Error en getProducts:', error);
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: 'Error al obtener productos',
      });
    }
  }

  /**
   * GET /api/products/:id - Obtener un producto específico (para admin - incluye descripción IA)
   */
  async getProduct(req: AuthRequest, res: Response) {
    try {
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      const productId = req.params.id;

      if (!productId) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'ID de producto requerido',
        });
      }

      const product = await productsService.getProductById(productId);

      if (!product) {
        return res.status(404).json({
          error: 'NOT_FOUND',
          message: 'Producto no encontrado',
        });
      }

      // Verificar que el producto pertenece a la marca
      if (product.brandId !== req.brand.id) {
        return res.status(403).json({
          error: 'FORBIDDEN',
          message: 'No tienes permiso para ver este producto',
        });
      }

      return res.status(200).json(product);
    } catch (error: any) {
      console.error('Error en getProduct:', error);
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: 'Error al obtener el producto',
      });
    }
  }

  /**
   * POST /api/products - Crear un nuevo producto
   */
  async createProduct(req: AuthRequest, res: Response) {
    try {
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      const productData: CreateProductDto = {
        name: req.body.name,
        description: req.body.description, // IA description - interno
        short_description: req.body.short_description,
        image_url: req.body.image_url || req.body.imageUrl,
        category: req.body.category,
        price: req.body.price != null ? Number(req.body.price) : null,
        badge: req.body.badge || null,
        attributes: req.body.attributes || {},
      };

      const product = await productsService.createProduct(req.brand.id, productData);
 
      // Invalidar caché para que el cambio se vea en el plugin y widget inmediatamente
      invalidateBrandConfigCache(req.brand.slug);
      return res.status(201).json(product);
    } catch (error: any) {
      console.error('Error en createProduct:', error);

      // Errores de validación o límite
      if (error.message.includes('límite') || error.message.includes('requerido') || error.message.includes('vacío')) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: sanitizeError(error, 'Error de validación en producto'),
        });
      }

      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al crear el producto'),
      });
    }
  }

  /**
   * PUT /api/products/:id - Actualizar un producto existente
   */
  async updateProduct(req: AuthRequest, res: Response) {
    try {
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      const productId = req.params.id;

      if (!productId) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'ID de producto requerido',
        });
      }

      const updates: UpdateProductDto = {};

      if (req.body.name !== undefined) {
        updates.name = req.body.name;
      }

      if (req.body.description !== undefined) {
        updates.description = req.body.description; // IA description - interno
      }

      if (req.body.short_description !== undefined) {
        updates.short_description = req.body.short_description;
      }

      if (req.body.image_url !== undefined || req.body.imageUrl !== undefined) {
        updates.image_url = req.body.image_url || req.body.imageUrl;
      }

      if (req.body.category !== undefined) {
        updates.category = req.body.category;
      }

      if (req.body.price !== undefined) {
        updates.price = req.body.price != null && req.body.price !== '' ? Number(req.body.price) : null;
      }

      if (req.body.badge !== undefined) {
        updates.badge = req.body.badge || null;
      }

      if (req.body.externalId !== undefined || req.body.external_id !== undefined) {
        updates.external_id = req.body.external_id || req.body.externalId || null;
      }

      if (req.body.attributes !== undefined) {
        updates.attributes = req.body.attributes;
      }

      // Verificar que hay algo que actualizar
      if (Object.keys(updates).length === 0) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'No hay campos para actualizar',
        });
      }

      const product = await productsService.updateProduct(productId, req.brand.id, updates);
 
      // Invalidar caché tras actualización
      invalidateBrandConfigCache(req.brand.slug);
      return res.status(200).json(product);
    } catch (error: any) {
      console.error('Error en updateProduct:', error);

      // Errores de validación o permisos
      if (error.message.includes('no encontrado')) {
        return res.status(404).json({
          error: 'NOT_FOUND',
          message: sanitizeError(error, 'Producto no encontrado'),
        });
      }

      if (error.message.includes('permiso')) {
        return res.status(403).json({
          error: 'FORBIDDEN',
          message: sanitizeError(error, 'No tienes permiso para esta acción'),
        });
      }

      if (error.message.includes('vacío') || error.message.includes('requerido')) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: sanitizeError(error, 'Error de validación en producto'),
        });
      }

      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: 'Error al actualizar el producto',
      });
    }
  }

  /**
   * DELETE /api/products/:id - Eliminar un producto
   */
  async deleteProduct(req: AuthRequest, res: Response) {
    try {
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      const productId = req.params.id;

      if (!productId) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'ID de producto requerido',
        });
      }

      await productsService.deleteProduct(productId, req.brand.id);
 
      // CRITICAL: Invalidar caché para que el plugin de WooCommerce sepa que el producto ya no existe/está inactivo
      invalidateBrandConfigCache(req.brand.slug);
      
      return res.status(200).json({
        success: true,
        message: 'Producto eliminado correctamente',
      });
    } catch (error: any) {
      console.error('Error en deleteProduct:', error);

      // Errores de validación o permisos
      if (error.message.includes('no encontrado')) {
        return res.status(404).json({
          error: 'NOT_FOUND',
          message: sanitizeError(error, 'Producto no encontrado'),
        });
      }

      if (error.message.includes('permiso')) {
        return res.status(403).json({
          error: 'FORBIDDEN',
          message: sanitizeError(error, 'No tienes permiso para esta acción'),
        });
      }

      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al eliminar el producto'),
      });
    }
  }

  /**
   * POST /api/products/describe-ai
   * Generates AI product descriptions using the direct Vertex AI descriptor service.
   * Replaces the former n8n webhook proxy.
   */
  async describeProductWithAI(req: AuthRequest, res: Response) {
    try {
      const { product_name, category, brand_description } = req.body;

      // 1. Validation — product_name and category are required
      if (!product_name || !category) {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'product_name y category son requeridos',
        });
      }

      // 2. Auth check
      if (!req.brand) {
        return res.status(401).json({
          error: 'UNAUTHORIZED',
          message: 'No autenticado',
        });
      }

      // 3. Call descriptorService
      // brand_description comes from the authenticated brand (DB), not the request body
      const descriptionObj = await descriptorService.describeProduct({
        name: product_name,
        category,
        brand_description: req.brand.brand_description || brand_description || undefined,
        image_url: req.body.image_url,
      });

      // Construir un string descriptivo para que el frontend lo guarde como "description"
      const parts = Object.entries(descriptionObj)
        .filter(([k, v]) => v && k !== 'product_type' && k !== 'extra_attributes')
        .map(([k, v]) => `${k}: ${Array.isArray(v) ? v.join(', ') : v}`);
        
      if (descriptionObj.extra_attributes) {
        Object.entries(descriptionObj.extra_attributes).forEach(([k, v]) => {
          parts.push(`${k}: ${v}`);
        });
      }
      
      const descriptionString = parts.join('\n');

      // 4. Return the response in a format the frontend understands
      return res.status(200).json({
        description: descriptionString,
        raw_data: descriptionObj,
        category
      });
    } catch (error: any) {
      // Distinguish error types for debugging
      if (error.name === 'ValidationError') {
        return res.status(502).json({
          error: 'WEBHOOK_NOT_FOUND',
          message: sanitizeError(error, 'Respuesta inválida del servicio de IA'),
        });
      }
      if (error.name === 'VertexError') {
        return res.status(500).json({
          error: 'VERTEX_ERROR',
          message: sanitizeError(error, 'Error del servicio de IA'),
        });
      }

      console.error('[AI-Descriptor] Error general:', error);
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al procesar la descripción con IA'),
      });
    }
  }

  /* ——————— ROLLBACK: n8n webhook code (kept for safe rollback) ———————
