  private async markPluginValidated(brand: any, incomingDomain?: string | null) {

    const currentSocialLinks = ((brand as any).social_links || {}) as Record<string, any>;

    const normalizedIncomingOrigin = normalizeOrigin(incomingDomain || null);

    const mergedOrigins = sanitizeDomainList([

      ...(Array.isArray(currentSocialLinks.allowed_origins) ? currentSocialLinks.allowed_origins : []),

      currentSocialLinks.website,

      currentSocialLinks.woo_plugin_store_domain,

      normalizedIncomingOrigin,

    ]);



    const nextSocialLinks: Record<string, any> = {

      ...currentSocialLinks,

      allowed_origins: mergedOrigins,

      woo_plugin_validated_at:

        currentSocialLinks.woo_plugin_validated_at || new Date().toISOString(),

      woo_plugin_validation_source: 'plugin_handshake',

    };



    if (!currentSocialLinks.website && normalizedIncomingOrigin) {

      nextSocialLinks.website = normalizedIncomingOrigin;

    }



    if (normalizedIncomingOrigin) {

      nextSocialLinks.woo_plugin_store_domain = normalizedIncomingOrigin;

    }



    const shouldUpdate =

      nextSocialLinks.woo_plugin_validated_at !== currentSocialLinks.woo_plugin_validated_at ||

      nextSocialLinks.woo_plugin_store_domain !== currentSocialLinks.woo_plugin_store_domain ||

      JSON.stringify(nextSocialLinks.allowed_origins || []) !== JSON.stringify(currentSocialLinks.allowed_origins || []) ||

      nextSocialLinks.website !== currentSocialLinks.website;



    if (shouldUpdate) {

      await brandsService.updateBrand(brand.id, {

        social_links: nextSocialLinks,

      });

    }

  }



  /**

   * GET /api/pruebalo/img-proxy?url=...

   * Proxy para saltar bloqueos de CORS/Hotlinking de imágenes de productos

   */

  // SSRF protection: allowlist of safe domains for image proxy

  private static readonly ALLOWED_IMAGE_PROXY_DOMAINS = [

    'lookitry.com',

    'lookitry.co',

    'lookitry.app',

    'lookitry.net',

    'cdn.lookitry.com',

    'images.lookitry.com',

    'wilkiedevs.com',

    'www.wilkiedevs.com',

    'minio.wilkiedevs.com',

    'cdn.minio.wilkiedevs.com',

  ];



  /**

   * GET /api/pruebalo/img-proxy?url=...

   * Proxy para saltar bloqueos de CORS/Hotlinking de imágenes de productos

   */

  imgProxy = asyncHandler(async (req: Request, res: Response) => {

    const imageUrl = req.query.url as string;



    if (!imageUrl) {

      throw new ValidationError('URL de imagen requerida');

    }



    try {

      // Validar si es una URL absoluta

      if (!imageUrl.startsWith('http')) {

        throw new ValidationError('URL de imagen inválida');

      }

      // SSRF: validar destino de proxy de imágenes con allowlist y no IPs privadas

      const isAllowedImageUrl = (urlStr: string): boolean => {

        try {

          const u = new URL(urlStr);

          const host = u.hostname;

          const protocol = u.protocol.toLowerCase();



          if (protocol !== 'http:' && protocol !== 'https:') {

            return false;

          }



          if (u.username || u.password) {

            return false;

          }



          const port = u.port ? Number(u.port) : null;

          if (port && port !== 80 && port !== 443) {

            return false;

          }



          if (/^(?:\d{1,3}\.){3}\d{1,3}$/.test(host)) {

            const parts = host.split('.').map((p) => parseInt(p, 10));

            const [a, b] = parts;

            if (a === 10 || (a === 172 && b >= 16 && b <= 31) || (a === 192 && b === 168) || host === '127.0.0.1') {

              return false;

            }

          }



          if (

            host === 'localhost' ||

            host === '0.0.0.0' ||

            host === '::1' ||

            host === '[::1]' ||

            host.endsWith('.local') ||

            host.endsWith('.internal')

          ) {

            return false;

          }



          return true;

        } catch {

          return false;

        }

      };

      if (!isAllowedImageUrl(imageUrl)) {

        throw new ValidationError('URL de imagen no permitida');

      }



      // Validar para prevenir SSRF
      try {
        const parsedUrl = new URL(imageUrl);
        const hostname = parsedUrl.hostname.toLowerCase();

        // ALLOWLIST: always allow our own services even if they resolve to local IPs in some environments
        const isAllowedDomain = hostname.endsWith('wilkiedevs.com') || hostname.endsWith('lookitry.com') || hostname.endsWith('supabase.co');

        if (!isAllowedDomain) {
          // Block localhost, internal IP ranges, and internal hostnames (including IPv6 brackets)
          const isInternal = /^(localhost|127\.0\.0\.1|0\.0\.0\.0|\[?::1\]?)$/.test(hostname) ||
            /^(10\.|192\.168\.|172\.(1[6-9]|2[0-9]|3[0-1])\.|169\.254\.)/.test(hostname) ||
            hostname.endsWith('.local') ||
            hostname.endsWith('.internal');

          if (isInternal) {
            throw new ValidationError('URL de imagen no permitida');
          }
        }
      } catch (err: any) {

        throw new ValidationError(err.message === 'URL de imagen no permitida' ? err.message : 'URL de imagen inválida');

      }



      // WORKAROUND: Si imageUrl apunta a wilkiedevs.com y falla con ECONNREFUSED (Docker local
      // host resolution), reescribir la URL para usar la IP pública del VPS con el header Host
      // original para preservar el virtual host en Traefik.
      let fetchUrl = imageUrl;
      let fetchHeaders: Record<string, string> = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Accept': 'image/avif,image/webp,image/apng,image/*,*/*;q=0.8',
        'Accept-Language': 'en-US,en;q=0.9',
        'Referer': new URL(imageUrl).origin + '/',
        'Sec-Fetch-Dest': 'image',
        'Sec-Fetch-Mode': 'no-cors',
        'Sec-Fetch-Site': 'same-origin',
      };

      // For MinIO URLs, bypass the public URL and use internal Docker hostname directly
      // since the backend container has direct network access to MinIO via Docker DNS
      // The public minio.wilkiedevs.com URL may have CDN/hotlink protection that blocks server-side requests
      console.log(`[imgProxy] Checking MinIO condition: imageUrl.includes('minio.wilkiedevs.com') = ${imageUrl.includes('minio.wilkiedevs.com')}`);
      if (imageUrl.includes('minio.wilkiedevs.com')) {
        const parsed = new URL(imageUrl);
        fetchUrl = `http://minio:9000${parsed.pathname}${parsed.search}${parsed.hash}`;
        console.log(`[imgProxy] MinIO URL detected, using internal Docker hostname: ${fetchUrl}`);
        // MinIO internal doesn't like Sec-Fetch headers and may require minimal headers
        fetchHeaders = {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
          'Accept': 'image/*,*/*',
        };
      } else if (imageUrl.includes('wilkiedevs.com') && !imageUrl.includes('minio.wilkiedevs.com')) {
        // FIX: The VPS has 127.0.1.1 wilkiedevs.com in /etc/hosts causing DNS to resolve
        // locally instead of reaching the actual WordPress server. Use the public IP directly
        // with the Host header to preserve virtual host routing through Traefik.
        const parsed = new URL(imageUrl);
        const originalHost = parsed.host;
        // Replace hostname with public IP, keep path and query
        fetchUrl = `https://92.112.198.238${parsed.pathname}${parsed.search}${parsed.hash}`;
        fetchHeaders['Host'] = originalHost;
        console.log(`[imgProxy] wilkiedevs.com URL detected, using public IP fallback: ${fetchUrl} (Host: ${originalHost})`);
      }

      console.log(`[imgProxy] Final fetchUrl: ${fetchUrl}`);
      console.log(`[imgProxy] fetchHeaders: ${JSON.stringify(fetchHeaders)}`);
      let response: AxiosResponse;
      try {
        response = await axios.get(fetchUrl, {
          headers: fetchHeaders,
          timeout: 10000,
          responseType: 'arraybuffer',
          maxRedirects: 0,
          validateStatus: (status) => status >= 200 && status < 400
        });
      } catch (fetchErr: any) {
        console.error(`[imgProxy] axios error: ${fetchErr.message}, code: ${fetchErr.code}, status: ${fetchErr.response?.status}`);
        console.log(`[imgProxy] fetchErr keys: ${Object.keys(fetchErr)}`);
        console.log(`[imgProxy] fetchErr.isAxiosError: ${fetchErr.isAxiosError}`);
        if (fetchErr.response) {
          console.log(`[imgProxy] fetchErr.response.status: ${fetchErr.response.status}`);
          console.log(`[imgProxy] fetchErr.response.data: ${fetchErr.response.data}`);
        }
        // If direct fetch fails for wilkiedevs.com, try the public IP path
        // The VPS hostname issue causes /etc/hosts to resolve wilkiedevs.com to 127.0.1.1
        if (imageUrl.includes('wilkiedevs.com') && !imageUrl.includes('minio.wilkiedevs.com') && fetchUrl.startsWith('https://wilkiedevs.com')) {
          console.log('[imgProxy] Direct HTTPS failed, trying public IP fallback');
          const parsed = new URL(imageUrl);
          fetchUrl = `https://92.112.198.238${parsed.pathname}${parsed.search}${parsed.hash}`;
          fetchHeaders['Host'] = parsed.host;
          console.log(`[imgProxy] Retry with public IP: ${fetchUrl}`);
          response = await axios.get(fetchUrl, {
            headers: fetchHeaders,
            timeout: 10000,
            responseType: 'arraybuffer',
            maxRedirects: 0,
            validateStatus: (status) => status >= 200 && status < 400,
            httpsAgent: new https.Agent({ rejectUnauthorized: false })
          });
        } else if (fetchUrl.includes('minio:9000') && imageUrl.includes('minio.wilkiedevs.com')) {
          console.log('[imgProxy] MinIO internal failed (axios threw), falling back to public URL');
          fetchUrl = imageUrl;
          console.log(`[imgProxy] Retry with public URL: ${fetchUrl}`);
          response = await axios.get(fetchUrl, {
            headers: fetchHeaders,
            timeout: 10000,
            responseType: 'arraybuffer',
            maxRedirects: 0,
            validateStatus: (status) => status >= 200 && status < 400,
            httpsAgent: new https.Agent({ rejectUnauthorized: false })
          });
        } else {
          throw fetchErr;
        }
      }

      console.log(`[imgProxy] Response status: ${response.status}, ok: ${response.status >= 200 && response.status < 300}`);

      // If MinIO internal returned 403, fall back to public URL
      if (response.status === 403 && fetchUrl.includes('minio:9000') && imageUrl.includes('minio.wilkiedevs.com')) {
        console.log('[imgProxy] MinIO internal returned 403, falling back to public URL');
        fetchUrl = imageUrl;
        console.log(`[imgProxy] Retry with public URL: ${fetchUrl}`);
        response = await axios.get(fetchUrl, {
          headers: fetchHeaders,
          timeout: 10000,
          responseType: 'arraybuffer',
          maxRedirects: 0,
          validateStatus: (status) => status >= 200 && status < 400,
          httpsAgent: new https.Agent({ rejectUnauthorized: false })
        });
        console.log(`[imgProxy] Fallback response status: ${response.status}`);
      }

      // Treat 403/301/302 from fallback path (public IP) as success
      const isFallbackPath = fetchUrl.startsWith('http://traefik:80') || fetchUrl.startsWith('http://31.220.18.39') || fetchUrl.startsWith('https://92.112.198.238');
      if (isFallbackPath && (response.status === 301 || response.status === 302 || response.status === 403)) {
        console.log(`[imgProxy] Fallback path returned ${response.status}, following redirect via location header`);
        const location = response.headers['location'];
        if (location) {
          let redirectUrl: string;
          if (!location.startsWith('http')) {
            // Relative redirect - rebuild using public IP HTTPS
            const parsedImgUrl = new URL(imageUrl);
            fetchHeaders['Host'] = parsedImgUrl.host;
            fetchHeaders['X-Forwarded-Proto'] = 'https';
            redirectUrl = `https://92.112.198.238${location}`;
          } else {
            // Absolute redirect URL - replace origin with public IP to avoid loopback
            const redirParsed = new URL(location);
            fetchHeaders['Host'] = redirParsed.hostname;
            fetchHeaders['X-Forwarded-Proto'] = 'https';
            redirectUrl = `https://92.112.198.238${redirParsed.pathname}${redirParsed.search}${redirParsed.hash}`;
          }
          console.log(`[imgProxy] Following redirect to: ${redirectUrl}`);
          response = await axios.get(redirectUrl, {
            headers: fetchHeaders,
            timeout: 10000,
            responseType: 'arraybuffer',
            maxRedirects: 0,
            validateStatus: (status) => status >= 200 && status < 400,
            httpsAgent: new https.Agent({ rejectUnauthorized: false })
          });
          console.log(`[imgProxy] Redirect response status: ${response.status}`);
        }
      }

      if (response.status < 200 || response.status >= 300) {
        throw new Error(`Error fetching image: HTTP ${response.status}`);
      }

      const contentType = response.headers['content-type'];

      if (contentType && typeof contentType === 'string') {

        res.setHeader('Content-Type', contentType);

      }



      // Cache por 24 horas
      res.setHeader('Cache-Control', 'public, max-age=86400');


      const buffer = Buffer.from(response.data);
      return res.send(buffer);

} catch (error: any) {
      console.error(`[imgProxy] CATCH block reached. Error message: ${error.message}, stack: ${error.stack?.substring(0, 300)}`);
      const cause = error?.cause?.message || error?.cause?.code || 'unknown';
      const detail = `${error.message} | cause: ${cause}`;

      const logObj = { message: detail };

      if (error?.cause) (logObj as any).cause = error.cause;

      

      console.error('[imgProxy] Error:', logObj);

      if (error instanceof ValidationError) {

        return res.status(400).json({

          error: 'INVALID_IMAGE_URL',

          message: sanitizeError(error, 'URL de imagen inválida'),

        });

      }

      return res.status(500).json({ 

        error: 'FAILED_TO_PROXY_IMAGE', 

        message: sanitizeError(error, 'Error al procesar la imagen')

      });

    }

  });

}



/**

 * Construye el prompt de try-on para Gemini.

 * Aplica reglas base por categoría de prenda para evitar errores comunes

 * (ej: vestido que deja pantalón visible, zapatos eliminados incorrectamente).

 */

function buildTryOnPrompt(product: { name: string; category?: string; description?: string | null }): string {

  const rules = getPromptRules(product.category);

  const categoryRulesBlock = buildCategoryRulesBlock(product.category);



  const lines: string[] = [

    `You are a professional virtual try-on AI specialized in fashion photography.`,

    `Your task: generate a single photorealistic image of the person in the selfie wearing the exact product shown in the reference image.`,

    `Product: "${product.name}"${product.category ? ` (${product.category})` : ''}.`,

  ];



  if (product.description) {

    lines.push(`Product visual details (reproduce every single one accurately): ${product.description}`);

  }



  lines.push(

    `ABSOLUTE RULES — follow all of them without exception:`,



    `[CLOTHING REPLACEMENT — MANDATORY]`,

    categoryRulesBlock,

    `- ${rules.replace}`,

    `- ${rules.keep}`,

    `- Do NOT leave any clothing item from the original photo visible if the product replaces it.`,

  );



  // Refuerzo extra para vestidos: el modelo tiende a dejar chaquetas y pantalones

  const cat = (product.category || '').toUpperCase();

  if (cat.includes('VESTIDO') || cat.includes('DRESS')) {

    lines.push(

      `[DRESS OVERRIDE — HIGHEST PRIORITY]`,

      `- The person may be wearing a jacket, denim jacket, cardigan, or coat in the original photo. REMOVE IT COMPLETELY.`,

      `- The person may be wearing pants, jeans, or leggings in the original photo. REMOVE THEM COMPLETELY.`,

      `- After applying the dress, NO jacket, NO pants, NO jeans, NO leggings should be visible anywhere in the image.`,

      `- The dress is the SOLE garment on the body. Treat this as a non-negotiable hard rule.`,

    );

  }



  lines.push(

    `[COMPOSITION & FRAMING]`,

    `- The input photo may be a close-up selfie (face/bust) OR a full-body shot. Detect which type it is and preserve that exact framing.`,

    `- If it is a full-body photo: show the person completely from head to toe. Never crop feet, legs, or any body part.`,

    `- If it is a close-up selfie: keep the same tight framing around the face and upper body.`,

    `- Maintain the exact same pose, body position, background, and spatial composition as the original photo.`,

    `- Fill every pixel of the frame with the scene — no empty space, no unused canvas area.`,



    `[OUTPUT DIMENSIONS]`,

    `- The output image MUST match the EXACT aspect ratio of the input selfie.`,

    `- NEVER add white borders, black bars, gray padding, letterboxing, pillarboxing, or any kind of margin.`,



    `[PRODUCT FIDELITY]`,

    `- Reproduce the garment EXACTLY as shown in the reference image: same colors, patterns, textures, logos, stitching, cuts, and fit.`,

    `- Do NOT invent, simplify, or alter any visual element of the product.`,



    `[NO MODEL-INSERTED WATERMARKS OR OVERLAYS]`,

    `- Preserve all authentic logos, brand marks, graphics, embroidery, and printed details that truly belong to the reference product.`,

    `- Do NOT generate any extra watermark, signature, caption, subtitle, AI stamp, stock-photo mark, UI overlay, or invented text that is not part of the real product design.`,

    `- Background objects, walls, lights, vehicles, and accessories must not contain invented words, signs, or graphic marks added by the model.`,

    `- The final image must look like a clean camera photograph, not a poster, ad creative, screenshot, or designed composition.`,



    `[PERSON & REALISM]`,

    `- Keep the person's face, skin tone, hair, body proportions, and expression IDENTICAL to the selfie.`,

    `- The product must fit naturally on the body with correct perspective, lighting, and shadows.`,

    `- Photorealistic quality only — no illustrations, no stylization.`,



    `Output: the final try-on image only. Keep real product branding if it exists, but never add model-invented watermarks, signatures, or UI overlays.`,

  );



  return lines.join('\n');

}

import { Request, Response } from 'express';
import { supabaseAdmin } from '../config/supabase';

/**
 * GET /api/promotions
 * Devuelve promociones activas y vigentes (público).
 */
export const getActivePromotions = async (_req: Request, res: Response) => {
  try {
    const { data, error } = await supabaseAdmin
      .from('promotions')
      .select('*')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error) throw error;

    const now = new Date();
    const activePromos = (data || []).filter((promo: any) => {
      const startsOk = !promo?.starts_at || new Date(promo.starts_at) <= now;
      const endsOk = !promo?.ends_at || new Date(promo.ends_at) >= now;
      return startsOk && endsOk;
    });

    return res.json({ ok: true, data: activePromos });
  } catch (error: any) {
    console.error('Error in getActivePromotions:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al obtener promociones' });
  }
};

/**
 * Rebecca Ratings Controller
 *
 * API endpoints para gestionar ratings de mensajes de Rebecca.
 * POST /api/chat/rating - Registrar un rating
 * GET /api/chat/ratings/stats - Obtener estadísticas
 * GET /api/chat/ratings/unreviewed - Obtener ratings sin revisar
 * PATCH /api/chat/ratings/:id/review - Marcar como revisado
 */

import { Router, Request, Response } from 'express';
import { rebeccaMessageRatingsService } from '../services/rebecca-message-ratings.service';
import { sanitizeError } from '../utils/sanitizeError';

const router = Router();

// POST /api/chat/rating - Registrar un rating de mensaje
router.post('/rating', async (req: Request, res: Response) => {
  try {
    const { session_id, message_index, message_content, rebecca_response, rating, rating_label, lead_intent, brand_id } = req.body;

    // Validation
    if (!session_id || message_index === undefined || !message_content || !rating || !rating_label) {
      return res.status(400).json({ error: 'MISSING_REQUIRED_FIELDS', message: 'Faltan campos requeridos' });
    }

    if (rating < 1 || rating > 5) {
      return res.status(400).json({ error: 'INVALID_RATING', message: 'Rating debe ser 1-5' });
    }

    if (!['thumbs_up', 'thumbs_down'].includes(rating_label)) {
      return res.status(400).json({ error: 'INVALID_RATING_LABEL', message: 'rating_label debe ser thumbs_up o thumbs_down' });
    }

    const entry = await rebeccaMessageRatingsService.rateMessage({
      session_id,
      message_index,
      message_content,
      rebecca_response,
      rating,
      rating_label,
      lead_intent,
      brand_id,
    });

    if (!entry) {
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al guardar rating' });
    }

    return res.status(201).json({ success: true, id: entry.id });
  } catch (error: any) {
    console.error('[RatingsController] POST /rating error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

// GET /api/chat/ratings/stats - Obtener estadísticas de ratings
router.get('/ratings/stats', async (_req: Request, res: Response) => {
  try {
    const stats = await rebeccaMessageRatingsService.getStats();
    return res.status(200).json(stats);
  } catch (error: any) {
    console.error('[RatingsController] GET /ratings/stats error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

// GET /api/chat/ratings/unreviewed - Obtener ratings sin revisar
router.get('/ratings/unreviewed', async (req: Request, res: Response) => {
  try {
    const limit = parseInt(req.query.limit as string) || 50;
    const ratings = await rebeccaMessageRatingsService.getUnreviewed(limit);
    return res.status(200).json({ ratings });
  } catch (error: any) {
    console.error('[RatingsController] GET /ratings/unreviewed error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

// GET /api/chat/ratings/negative - Obtener conversaciones con ratings negativos
router.get('/ratings/negative', async (req: Request, res: Response) => {
  try {
    const limit = parseInt(req.query.limit as string) || 20;
    const ratings = await rebeccaMessageRatingsService.getNegativeConversations(limit);
    return res.status(200).json({ ratings });
  } catch (error: any) {
    console.error('[RatingsController] GET /ratings/negative error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

// PATCH /api/chat/ratings/:id/review - Marcar rating como revisado
router.patch('/ratings/:id/review', async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const { notes } = req.body;

    if (!id) {
      return res.status(400).json({ error: 'MISSING_ID', message: 'ID requerido' });
    }

    const success = await rebeccaMessageRatingsService.markReviewed(id, notes);

    if (!success) {
      return res.status(500).json({ error: 'UPDATE_FAILED', message: 'Error al marcar como revisado' });
    }

    return res.status(200).json({ success: true });
  } catch (error: any) {
    console.error('[RatingsController] PATCH /ratings/:id/review error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

// PATCH /api/chat/ratings/session/:sessionId/outcome - Actualizar outcome de sesión
router.patch('/ratings/session/:sessionId/outcome', async (req: Request, res: Response) => {
  try {
    const { sessionId } = req.params;
    const { outcome } = req.body;

    if (!sessionId || !outcome) {
      return res.status(400).json({ error: 'MISSING_REQUIRED_FIELDS', message: 'sessionId y outcome requeridos' });
    }

    if (!['converted', 'abandoned'].includes(outcome)) {
      return res.status(400).json({ error: 'INVALID_OUTCOME', message: 'outcome debe ser converted o abandoned' });
    }

    const success = await rebeccaMessageRatingsService.updateOutcome(sessionId, outcome);

    if (!success) {
      return res.status(500).json({ error: 'UPDATE_FAILED', message: 'Error al actualizar outcome' });
    }

    return res.status(200).json({ success: true });
  } catch (error: any) {
    console.error('[RatingsController] PATCH /ratings/session/:sessionId/outcome error:', error);
    return res.status(500).json({ error: 'INTERNAL_ERROR', message: sanitizeError(error, 'Error interno') });
  }
});

