import { Request, Response } from 'express';

import { supabaseAdmin } from '../config/supabase';

import { PaymentSettingsService } from '../services/paymentSettings.service';

import { getReportingTrm, normalizePaymentRecordToCop, convertPaymentToCop } from '../utils/paymentNormalization';

import { inferBillingType, inferPlanPurchased } from '../utils/paymentLedger';

import { sanitizeError } from '../utils/sanitizeError';


const paymentSettingsService = new PaymentSettingsService();



/**

 * RevenueController

 * 

 * Controlador para gestionar reportes de ingresos del sistema.

 * 

 * Requirements: 12.9

 */

export class RevenueController {

  /**

   * GET /api/admin/revenue/stats

   * Obtener estadísticas de ingresos mensuales

   * 

   * Requirement 12.9: Generar reporte mensual de ingresos por suscripciones

   */

  async getRevenueStats(_req: Request, res: Response): Promise<Response> {

    try {

      const paymentSettings = await paymentSettingsService.getSettings().catch(() => null);

      const landingPrice = Number(paymentSettings?.landing_price || 650000);

      const reportingTrm = await getReportingTrm();

      const trmCache = new Map<string, number | null>();



      const splitPaymentAmounts = (amount: number, payment: any) => {
        const billingType = inferBillingType(payment);
        const notes = typeof payment.notes === 'string' ? payment.notes.toLowerCase() : '';
        const hasLandingMention = notes.includes('landing');

        if (billingType === 'landing') {
          return { landing: amount, subscription: 0, billingType };
        }

        if (billingType === 'trial_activation') {
          return { landing: 0, subscription: 0, billingType };
        }

        if (hasLandingMention) {
          const landingComponent = Math.min(amount, landingPrice);
          return {
            landing: landingComponent,
            subscription: Math.max(0, amount - landingComponent),
            billingType,
          };
        }

        return { landing: 0, subscription: amount, billingType };
      };


      // Precios por plan en COP (para proyecciones)

      const PLAN_PRICES = {

        BASIC: 150000,

        PRO: 250000,

        LANDING: 650000, // Aunque suele ser pago único, lo definimos por si acaso

      };



      // 1. Obtener ingresos mensuales de los últimos 12 meses

      const { data: monthlyRevenue, error: monthlyError } = await supabaseAdmin

        .from('subscription_payments')

        .select('payment_date, amount, currency, notes, months_paid')
        .eq('status', 'completed')

        .gte('payment_date', new Date(Date.now() - 365 * 24 * 60 * 60 * 1000).toISOString())

        .order('payment_date', { ascending: true });



      if (monthlyError) {

        throw new Error(monthlyError.message);

      }



      // 2. Agrupar por mes y plan

      const monthlyData: Record<string, { total: number; basic: number; pro: number; landing: number; count: number }> = {};



      const normalizedMonthlyRevenue = await Promise.all(

        (monthlyRevenue || []).map(async (payment: any) => ({

          payment,

          normalized: await normalizePaymentRecordToCop(payment, reportingTrm, trmCache),

        }))

      );



      normalizedMonthlyRevenue.forEach(({ payment, normalized }) => {

        const month = new Date(payment.payment_date).toISOString().substring(0, 7); // YYYY-MM



        if (!monthlyData[month]) {

          monthlyData[month] = { total: 0, basic: 0, pro: 0, landing: 0, count: 0 };

        }



        const amount = normalized.amountCop;

        const split = splitPaymentAmounts(amount, payment);



        monthlyData[month].total += amount;

        monthlyData[month].count += 1;



        if (split.landing > 0) {

          monthlyData[month].landing += split.landing;

        }



        if (split.subscription > 0) {
          const planPurchased = inferPlanPurchased(payment);
          if (planPurchased === 'BASIC') {
            monthlyData[month].basic += split.subscription;
          } else if (planPurchased === 'PRO') {
            monthlyData[month].pro += split.subscription;
          } else if (split.billingType !== 'trial_activation') {
            monthlyData[month].basic += split.subscription;
          }
        } else if (split.landing === 0 && split.billingType !== 'trial_activation') {
          monthlyData[month].basic += amount;
        }
      });



      // 3. Convertir a array ordenado

      const monthlyRevenueArray = Object.entries(monthlyData)

        .map(([month, data]) => ({

          month,

          total: data.total,

          basic: data.basic,

          pro: data.pro,

          landing: data.landing,

          count: data.count,

        }))

        .sort((a, b) => a.month.localeCompare(b.month));



      // 4. Calcular ingresos del mes actual

      const currentMonth = new Date().toISOString().substring(0, 7);

      const currentMonthRevenue = monthlyData[currentMonth] || { total: 0, basic: 0, pro: 0, landing: 0, count: 0 };



      // 5. Calcular proyección del próximo mes basado en suscripciones activas

      const { data: brandsStats, error: brandsError } = await supabaseAdmin

        .from('brands')

        .select('plan, subscription_status, has_landing_page');



      if (brandsError) throw new Error(brandsError.message);



      // Filtro estricto de marcas activas según requerimiento

      const activeBrands = (brandsStats || []).filter(b => 

        ['active', 'expiring_soon'].includes(b.subscription_status)

      );



      let projectedRevenue = 0;

      let projectedBasic = 0;

      let projectedPro = 0;



      activeBrands.forEach((brand: any) => {

        if (brand.plan === 'BASIC') {

          projectedBasic += PLAN_PRICES.BASIC;

          projectedRevenue += PLAN_PRICES.BASIC;

        } else if (brand.plan === 'PRO') {

          projectedPro += PLAN_PRICES.PRO;

          projectedRevenue += PLAN_PRICES.PRO;

        }

        // Nota: LANDING suele ser pago único, no se proyecta a menos que sea recurrente

      });



      // Conteo de landings activas (basado en el flag has_landing_page = true)

      // Aseguramos que solo contamos las de marcas activas si se considera "activa"

      const activeLandings = (brandsStats || []).filter(b => b.has_landing_page === true).length;



      // 6. Desglose por plan (totales históricos)

      const { data: planBreakdown, error: planError } = await supabaseAdmin

        .from('subscription_payments')

        .select('amount, currency, notes, months_paid')
        .eq('status', 'completed');



      if (planError) throw new Error(planError.message);



      let totalBasicRevenue = 0;

      let totalProRevenue = 0;

      let totalLandingRevenue = 0;

      let basicPaymentsCount = 0;

      let proPaymentsCount = 0;

      let landingPaymentsCount = 0;



      const normalizedPlanBreakdown = await Promise.all(

        (planBreakdown || []).map(async (payment: any) => ({

          payment,

          normalized: await normalizePaymentRecordToCop(payment, reportingTrm, trmCache),

        }))

      );



      normalizedPlanBreakdown.forEach(({ payment, normalized }) => {

        const split = splitPaymentAmounts(normalized.amountCop, payment);



        if (split.landing > 0) {

          totalLandingRevenue += split.landing;

          landingPaymentsCount += 1;

        }



        if (split.subscription > 0) {
          const planPurchased = inferPlanPurchased(payment);
          if (planPurchased === 'BASIC') {
            totalBasicRevenue += split.subscription;
            basicPaymentsCount += 1;
          } else if (planPurchased === 'PRO') {
            totalProRevenue += split.subscription;
            proPaymentsCount += 1;
          } else if (split.billingType !== 'trial_activation') {
            totalBasicRevenue += split.subscription;
            basicPaymentsCount += 1;
          }
        } else if (split.landing === 0 && split.billingType !== 'trial_activation') {
          totalBasicRevenue += normalized.amountCop;
          basicPaymentsCount += 1;
        } else if (split.billingType !== 'trial_activation') {
          totalLandingRevenue += normalized.amountCop;
          landingPaymentsCount += 1;
        }
      });



      return res.json({

        monthlyRevenue: monthlyRevenueArray,

        currentMonth: {

          month: currentMonth,

          total: currentMonthRevenue.total,

          basic: currentMonthRevenue.basic,

          pro: currentMonthRevenue.pro,

          landing: currentMonthRevenue.landing,

          paymentsCount: currentMonthRevenue.count,

        },

        projection: {

          nextMonth: new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().substring(0, 7),

          total: projectedRevenue,

          basic: projectedBasic,

          pro: projectedPro,

          activeSubscriptions: activeBrands.length,

          activeLandings, // Entregado dentro de projection como se pidió

        },

        planBreakdown: {

          basic: {

            totalRevenue: totalBasicRevenue,

            paymentsCount: basicPaymentsCount,

            averagePayment: basicPaymentsCount > 0 ? totalBasicRevenue / basicPaymentsCount : 0,

          },

          pro: {

            totalRevenue: totalProRevenue,

            paymentsCount: proPaymentsCount,

            averagePayment: proPaymentsCount > 0 ? totalProRevenue / proPaymentsCount : 0,

          },

          landing: {

            totalRevenue: totalLandingRevenue,

            paymentsCount: landingPaymentsCount,

            averagePayment: landingPaymentsCount > 0 ? totalLandingRevenue / landingPaymentsCount : 0,

          },

        },

      });

    } catch (error: any) {

      console.error('Error in getRevenueStats:', error);

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al obtener estadísticas de ingresos'),

      });

    }

  }



  /**

   * GET /api/admin/revenue/payments

   * Listar todos los pagos con filtros

   */

  async getAllPayments(req: Request, res: Response): Promise<Response> {
    try {
      const { method, payment_method, status, from, to, search, plan } = req.query;
      const reportingTrm = await getReportingTrm();

      let query = supabaseAdmin
        .from('subscription_payments')
        .select(`
          id, brand_id, amount, currency, payment_date,
          payment_method, status, notes, created_at,
          brands(name, email, slug, plan, social_links)
        `)
        .order('payment_date', { ascending: false });

      const methodFilter = (payment_method || method) as string | undefined;
      if (methodFilter && methodFilter !== 'all') query = query.eq('payment_method', methodFilter);
      if (status && status !== 'all') query = query.eq('status', status as string);
      if (from) query = query.gte('payment_date', from as string);
      if (to) query = query.lte('payment_date', `${to}T23:59:59`);

      const { data, error } = await query;
      if (error) throw new Error(error.message);

      let payments = (data || []).map((p: any) => {
        const normalized = convertPaymentToCop(p.amount, p.currency, reportingTrm);
        const brandPlan = inferPlanPurchased(p);
        return {
          id: p.id,
          brandId: p.brand_id,
          brandName: p.brands?.name ?? '?',
          brandEmail: p.brands?.email ?? '?',
          brandSlug: p.brands?.slug ?? '?',
          brandPlan,
          billingType: inferBillingType(p),
          archived: Boolean(p.brands?.social_links?.account_archived_at),
          amount: normalized.amountCop,
          amount_original: normalized.originalAmount,
          amount_cop: normalized.amountCop,
          exchange_rate_used: normalized.exchangeRateUsed,
          currency: normalized.currency,
          paymentDate: p.payment_date,
          paymentMethod: p.payment_method,
          status: p.status,
          notes: p.notes,
          createdAt: p.created_at,
          isLanding: inferBillingType(p) === 'landing',
        };
      });

      if (plan && plan !== 'all') {
        payments = payments.filter((payment) => payment.brandPlan === plan);
      }

      if (search) {
        const q = (search as string).toLowerCase();
        payments = payments.filter(
          p => p.brandName.toLowerCase().includes(q) ||
               p.brandEmail.toLowerCase().includes(q) ||
               p.brandSlug.toLowerCase().includes(q)
        );
      }

      const completedPayments = payments.filter((payment) => payment.status === 'completed');
      const total = completedPayments.reduce((sum, payment) => sum + payment.amount_cop, 0);
      return res.json({
        payments,
        total,
        count: payments.length,
        stats: {
          total_revenue: total,
          completed_count: completedPayments.length,
        },
      });
    } catch (error: any) {
      return res.status(500).json({
        error: 'INTERNAL_ERROR',
        message: sanitizeError(error, 'Error al obtener pagos'),
      });
    }
  }
}

import { Response } from 'express';
import { supabaseAdmin } from '../config/supabase';
import { AuthRequest } from '../middleware/auth';
import { AdminAuthRequest } from '../middleware/adminAuth';
import type {
  Brand,
  BrandReview,
  CreateReviewDto,
  PublicReview,
  ReviewStatus,
  UpdateReviewModerationDto,
} from '../types';

const REVIEWS_PER_PAGE = 10;

function isTrialBrand(brand: Pick<Brand, 'plan' | 'subscription_status'>): boolean {
  return brand.plan === 'TRIAL';
}

function parseRating(value: unknown): number | null {
  const parsed = Number(value);
  if (Number.isNaN(parsed) || parsed < 1 || parsed > 5 || parsed % 0.5 !== 0) return null;
  return parsed;
}

function normalizeComment(value: unknown): string | null {
  if (typeof value !== 'string') return null;
  const comment = value.trim();
  if (comment.length < 10 || comment.length > 500) return null;
  return comment;
}

function parseStatus(value: unknown): ReviewStatus | 'all' | null {
  if (value === undefined || value === null || value === '') return 'all';
  if (value === 'all' || value === 'pending' || value === 'approved' || value === 'rejected') return value;
  return null;
}

function parseSort(value: unknown): 'created_at_desc' | 'created_at_asc' | 'rating_desc' | 'rating_asc' {
  if (
    value === 'created_at_asc' ||
    value === 'rating_desc' ||
    value === 'rating_asc'
  ) {
    return value;
  }
  return 'created_at_desc';
}

async function getAuthenticatedBrand(brandId: string): Promise<Brand | null> {
  const { data, error } = await supabaseAdmin
    .from('brands')
    .select('id, name, plan, logo, subscription_status, review_prompt_shown_at, subscription_start_date, trial_end_date')
    .eq('id', brandId)
    .single();

  if (error || !data) return null;
  return data as Brand;
}

export class ReviewsController {
  async createReview(req: AuthRequest, res: Response) {
    try {
      if (!req.brand?.id) {
        return res.status(401).json({ error: 'UNAUTHORIZED', message: 'No autenticado' });
      }

      const payload = (req.body || {}) as CreateReviewDto;
      const rating = parseRating(payload.rating);
      const comment = normalizeComment(payload.comment);

      if (!rating) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El rating debe estar entre 1 y 5 estrellas.' });
      }

      if (!comment) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El comentario debe tener entre 10 y 500 caracteres.' });
      }

      const brand = await getAuthenticatedBrand(req.brand.id);
      if (!brand) {
        return res.status(404).json({ error: 'NOT_FOUND', message: 'Marca no encontrada.' });
      }

      if (isTrialBrand(brand)) {
        return res.status(403).json({
          error: 'FORBIDDEN',
          message: 'Las reviews están disponibles a partir del plan BASIC. Actualiza tu plan para compartir tu opinión.',
        });
      }

      const { data, error } = await supabaseAdmin
        .from('brand_reviews')
        .insert({
          brand_id: brand.id,
          rating,
          comment,
          reviewer_name: brand.name,
          reviewer_plan: brand.plan,
          status: rating >= 4.5 ? 'approved' : 'pending',
          avatar_url: brand.logo || null,
        })
        .select('*')
        .single();

      if (error) {
        if ((error as any).code === '23505') {
          return res.status(409).json({
            error: 'CONFLICT',
            message: 'Ya enviaste una review. Solo se permite una por marca.',
          });
        }

        throw error;
      }

      await supabaseAdmin
        .from('brands')
        .update({ review_prompt_shown_at: new Date().toISOString() })
        .eq('id', brand.id);

      return res.status(201).json(data as BrandReview);
    } catch (error: any) {
      console.error('Error creando review:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al crear la review.' });
    }
  }

  async getMyReview(req: AuthRequest, res: Response) {
    try {
      if (!req.brand?.id) {
        return res.status(401).json({ error: 'UNAUTHORIZED', message: 'No autenticado' });
      }

      const brand = await getAuthenticatedBrand(req.brand.id);
      if (!brand) {
        return res.status(404).json({ error: 'NOT_FOUND', message: 'Marca no encontrada.' });
      }

      if (isTrialBrand(brand)) {
        return res.status(200).json(null);
      }

      const { data, error } = await supabaseAdmin
        .from('brand_reviews')
        .select('*')
        .eq('brand_id', brand.id)
        .maybeSingle();

      if (error) throw error;

      return res.status(200).json((data as BrandReview | null) ?? null);
    } catch (error: any) {
      console.error('Error obteniendo mi review:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al obtener tu review.' });
    }
  }

  async markPrompted(req: AuthRequest, res: Response) {
    try {
      if (!req.brand?.id) {
        return res.status(401).json({ error: 'UNAUTHORIZED', message: 'No autenticado' });
      }

      const brand = await getAuthenticatedBrand(req.brand.id);
      if (!brand) {
        return res.status(404).json({ error: 'NOT_FOUND', message: 'Marca no encontrada.' });
      }

      if (isTrialBrand(brand)) {
        return res.status(200).json({ success: true });
      }

      await supabaseAdmin
        .from('brands')
        .update({ review_prompt_shown_at: new Date().toISOString() })
        .eq('id', brand.id);

      return res.status(200).json({ success: true });
    } catch (error: any) {
      console.error('Error marcando prompt review:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al marcar el prompt de review.' });
    }
  }

  async getPublicReviews(_req: AuthRequest, res: Response) {
    try {
      const countQuery = await supabaseAdmin
        .from('brand_reviews')
        .select('id', { count: 'exact', head: true })
        .eq('status', 'approved');

      if (countQuery.error) throw countQuery.error;

      const { data, error } = await supabaseAdmin
        .from('brand_reviews')
        .select('id, rating, comment, reviewer_name, reviewer_plan, is_featured, created_at, avatar_url')
        .eq('status', 'approved')
        .order('is_featured', { ascending: false })
        .order('created_at', { ascending: false })
        .limit(20);

      if (error) throw error;

      return res.status(200).json({
        reviews: (data ?? []) as PublicReview[],
        total_approved: countQuery.count ?? 0,
      });
    } catch (error: any) {
      console.error('Error obteniendo reviews públicas:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al obtener las reviews públicas.' });
    }
  }

  async listAdminReviews(req: AdminAuthRequest, res: Response) {
    try {
      const page = Math.max(1, Number(req.query.page) || 1);
      const limit = REVIEWS_PER_PAGE;
      const status = parseStatus(req.query.status);
      const ratingQuery = req.query.rating;
      const sort = parseSort(req.query.sort);
      const search = typeof req.query.search === 'string' ? req.query.search.trim() : '';

      if (!status) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Filtro de estado inválido.' });
      }

      const rating = ratingQuery === undefined || ratingQuery === 'all' || ratingQuery === ''
        ? null
        : parseRating(ratingQuery);

      if (ratingQuery !== undefined && ratingQuery !== 'all' && ratingQuery !== '' && rating === null) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Filtro de rating inválido.' });
      }

      let countBuilder = supabaseAdmin
        .from('brand_reviews')
        .select('id', { count: 'exact', head: true });

      let dataBuilder = supabaseAdmin
        .from('brand_reviews')
        .select('*');

      if (status !== 'all') {
        countBuilder = countBuilder.eq('status', status);
        dataBuilder = dataBuilder.eq('status', status);
      }

      if (rating !== null) {
        countBuilder = countBuilder.eq('rating', rating);
        dataBuilder = dataBuilder.eq('rating', rating);
      }

      if (search) {
        const pattern = `%${search}%`;
        countBuilder = countBuilder.or(`reviewer_name.ilike.${pattern},comment.ilike.${pattern}`);
        dataBuilder = dataBuilder.or(`reviewer_name.ilike.${pattern},comment.ilike.${pattern}`);
      }

      if (sort === 'created_at_asc') {
        dataBuilder = dataBuilder.order('created_at', { ascending: true });
      } else if (sort === 'rating_desc') {
        dataBuilder = dataBuilder.order('rating', { ascending: false }).order('created_at', { ascending: false });
      } else if (sort === 'rating_asc') {
        dataBuilder = dataBuilder.order('rating', { ascending: true }).order('created_at', { ascending: false });
      } else {
        dataBuilder = dataBuilder.order('created_at', { ascending: false });
      }

      const from = (page - 1) * limit;
      const to = from + limit - 1;

      const [countResult, dataResult] = await Promise.all([
        countBuilder,
        dataBuilder.range(from, to),
      ]);

      if (countResult.error) throw countResult.error;
      if (dataResult.error) throw dataResult.error;

      const total = countResult.count ?? 0;
      const totalPages = Math.max(1, Math.ceil(total / limit));

      return res.status(200).json({
        reviews: (dataResult.data ?? []) as BrandReview[],
        total,
        page,
        totalPages,
      });
    } catch (error: any) {
      console.error('Error listando reviews admin:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al listar las reviews.' });
    }
  }

  async moderateReview(req: AdminAuthRequest, res: Response) {
    try {
      const reviewId = req.params.id;
      const body = (req.body || {}) as UpdateReviewModerationDto;
      const updates: Record<string, unknown> = {};

      if (body.status !== undefined) {
        if (body.status !== 'approved' && body.status !== 'rejected') {
          return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El estado debe ser approved o rejected.' });
        }
        updates.status = body.status;
      }

      if (body.is_featured !== undefined) {
        if (typeof body.is_featured !== 'boolean') {
          return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'is_featured debe ser booleano.' });
        }
        updates.is_featured = body.is_featured;
      }

      if (body.admin_note !== undefined) {
        if (body.admin_note !== null && typeof body.admin_note !== 'string') {
          return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'admin_note debe ser texto.' });
        }
        updates.admin_note = body.admin_note?.trim() ? body.admin_note.trim() : null;
      }

      if (Object.keys(updates).length === 0) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'No hay cambios para aplicar.' });
      }

      const { data: existing, error: existingError } = await supabaseAdmin
        .from('brand_reviews')
        .select('*')
        .eq('id', reviewId)
        .single();

      if (existingError || !existing) {
        return res.status(404).json({ error: 'NOT_FOUND', message: 'Review no encontrada.' });
      }

      const finalStatus = (updates.status as ReviewStatus | undefined) ?? (existing as BrandReview).status;
      const finalFeatured = (updates.is_featured as boolean | undefined) ?? (existing as BrandReview).is_featured;

      if (finalFeatured && finalStatus !== 'approved') {
        return res.status(400).json({
          error: 'VALIDATION_ERROR',
          message: 'Solo las reviews aprobadas pueden marcarse como destacadas.',
        });
      }

      updates.updated_at = new Date().toISOString();

      const { data, error } = await supabaseAdmin
        .from('brand_reviews')
        .update(updates)
        .eq('id', reviewId)
        .select('*')
        .single();

      if (error) throw error;

      return res.status(200).json(data as BrandReview);
    } catch (error: any) {
      console.error('Error moderando review:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al moderar la review.' });
    }
  }

  async deleteReview(req: AdminAuthRequest, res: Response) {
    try {
      const reviewId = req.params.id;

      const { data: existing, error: existingError } = await supabaseAdmin
        .from('brand_reviews')
        .select('id')
        .eq('id', reviewId)
        .single();

      if (existingError || !existing) {
        return res.status(404).json({ error: 'NOT_FOUND', message: 'Review no encontrada.' });
      }

      const { error } = await supabaseAdmin
        .from('brand_reviews')
        .delete()
        .eq('id', reviewId);

      if (error) throw error;

      return res.status(200).json({ success: true });
    } catch (error: any) {
      console.error('Error eliminando review:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al eliminar la review.' });
    }
  }
}

export const reviewsController = new ReviewsController();

import { Request, Response } from 'express';

import { SubscriptionService } from '../services/subscription.service';

import { NotificationService } from '../services/notification.service';

import { auditService } from '../services/audit.service';

import { planChangeService } from '../services/planChange.service';

import { AuthRequest } from '../middleware/auth';

import { CreatePaymentDto } from '../types';

import { sanitizeError } from '../utils/sanitizeError';


const notificationService = new NotificationService();



// Extender Request para incluir admin

interface AdminAuthRequest extends Request {

  admin?: {

    id: string;

    email: string;

  };

}



const subscriptionService = new SubscriptionService();



/**

 * SubscriptionController

 * 

 * Controlador para gestionar endpoints de suscripciones.

 * Incluye endpoints para marcas (obtener estado) y admin (gestión completa).

 * 

 * Requirements: 11.5, 11.6, 12.4, 12.5, 12.6

 */

export class SubscriptionController {

  /**

   * GET /api/brands/subscription

   * Obtener estado de suscripción de la marca autenticada

   * 

   * Requirement 11.5: Marca puede consultar su estado de suscripción

   */

  async getBrandSubscription(req: AuthRequest, res: Response): Promise<Response> {

    try {

      const brandId = req.brand?.id;



      if (!brandId) {

        return res.status(401).json({

          error: 'UNAUTHORIZED',

          message: 'Marca no autenticada',

        });

      }



      const subscriptionInfo = await subscriptionService.getSubscriptionInfo(brandId);

      const paymentHistory = await subscriptionService.getPaymentHistory(brandId);



      return res.json({

        subscription: subscriptionInfo,

        payments: paymentHistory,

      });

    } catch (error: any) {

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al obtener información de suscripción'),

      });

    }

  }



  /**

   * GET /api/admin/subscriptions

   * Listar todas las suscripciones con filtros opcionales

   * 

   * Requirement 12.1, 12.2: Admin puede ver todas las suscripciones con filtros

   */

  async getAllSubscriptions(req: AdminAuthRequest, res: Response): Promise<Response> {

    try {

      const { status } = req.query as any;



      // Importar supabaseAdmin para consultas

      const { supabaseAdmin } = await import('../config/supabase');



      let query = supabaseAdmin

        .from('brands')

        .select('id, name, email, slug, plan, trial_end_date, subscription_status, subscription_start_date, subscription_end_date, last_payment_date, next_payment_date')

        .order('subscription_end_date', { ascending: true });



      // Aplicar filtro de estado si se proporciona

      if (status && typeof status === 'string') {

        query = query.eq('subscription_status', status);

      }



      const { data, error } = await query;



      if (error) {

        throw new Error(error.message);

      }



      // Calcular días restantes y estado trial para cada marca

      const now = new Date();

      const subscriptionsWithDays = await Promise.all(

        (data || []).map(async (brand: any) => {
          const daysRemaining = await subscriptionService.getDaysRemaining(brand.id);
          const trialEnd = brand.trial_end_date ? new Date(brand.trial_end_date) : null;
          const is_in_trial =
            brand.plan === 'TRIAL' &&
            trialEnd !== null &&
            trialEnd > now &&
            brand.subscription_status !== 'suspended';
          const trial_days_remaining = is_in_trial && trialEnd
            ? Math.ceil((trialEnd.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
            : null;
          return {
            ...brand,
            daysRemaining,
            is_in_trial,
            trial_days_remaining,
          };

        })

      );



      return res.json({

        subscriptions: subscriptionsWithDays,

        total: subscriptionsWithDays.length,

      });

    } catch (error: any) {

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al obtener suscripciones'),

      });

    }

  }



  /**

   * PATCH /api/admin/subscriptions/:brandId/renew

   * Renovar suscripción manualmente

   * 

   * Requirement 12.4: Admin puede renovar suscripciones manualmente

   */

  async renewSubscription(req: AdminAuthRequest, res: Response): Promise<Response> {

    try {

      const { brandId } = req.params;

      const paymentData: CreatePaymentDto = {

        brand_id: brandId,

        amount: req.body.amount || 0,

        currency: req.body.currency || 'COP',

        payment_date: req.body.payment_date || new Date().toISOString(),

        payment_method: req.body.payment_method || 'manual',

        status: 'completed',

        notes: req.body.notes || 'Renovación manual por administrador',

      };



      const updatedBrand = await subscriptionService.renewSubscription(brandId, paymentData);



      // Enviar email de confirmación de renovación (Req 13.6)

      notificationService.sendRenewalConfirmation(updatedBrand).catch((err) =>

        console.error('[Subscription] Error enviando email de renovación:', err)

      );



      // Auditoría

      auditService.log({

        admin_id: (req as any).admin?.id ?? 'unknown',

        admin_email: (req as any).admin?.email ?? 'unknown',

        action: 'subscription.renew',

        target_brand_id: brandId,

        details: { amount: paymentData.amount, payment_method: paymentData.payment_method },

      });



      return res.json({

        message: 'Suscripción renovada exitosamente',

        brand: {

          id: updatedBrand.id,

          name: updatedBrand.name,

          subscription_status: updatedBrand.subscription_status,

          subscription_start_date: updatedBrand.subscription_start_date,

          subscription_end_date: updatedBrand.subscription_end_date,

        },

      });

    } catch (error: any) {

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al renovar suscripción'),

      });

    }

  }



