  /**

   * POST /api/admin/subscriptions/:brandId/payment

   * Registrar pago manual — soporta 1, 3 o 6 meses con descuento automático.

   * 3 meses = 5% descuento, 6 meses = 10% descuento.

   *

   * Requirement 11.14, 29.3

   */

  async registerPayment(req: AdminAuthRequest, res: Response): Promise<Response> {

    try {

      const { brandId } = req.params;

      const { amount, currency, payment_method, payment_date, notes, months, plan } = req.body;



      if (!amount || amount <= 0) {

        return res.status(400).json({

          error: 'VALIDATION_ERROR',

          message: 'El monto del pago es requerido y debe ser mayor a 0',

        });

      }



      const periodMonths: number = months && [1, 3, 6].includes(Number(months)) ? Number(months) : 1;



      const DISCOUNTS: Record<number, number> = { 1: 0, 3: 0.05, 6: 0.10 };

      const discount = DISCOUNTS[periodMonths] ?? 0;

      const finalAmount = Math.round(Number(amount) * (1 - discount));



      const paymentData: CreatePaymentDto = {

        brand_id: brandId,

        amount: finalAmount,

        currency: currency || 'COP',

        payment_date: payment_date || new Date().toISOString(),

        payment_method: payment_method || 'manual',

        status: 'completed',

        notes: notes

          ? `${notes}${discount > 0 ? ` (descuento ${discount * 100}% por ${periodMonths} meses)` : ''}`

          : discount > 0

            ? `Descuento ${discount * 100}% por pago de ${periodMonths} meses`

            : undefined,

      };



      // Pasar el plan al renewSubscription para que lo actualice en BD

      const planToApply = plan && ['BASIC', 'PRO'].includes(String(plan).toUpperCase())

        ? String(plan).toUpperCase()

        : undefined;



      const updatedBrand = await subscriptionService.renewSubscription(brandId, paymentData, periodMonths, planToApply);



      // Enviar email de confirmación de compra (igual que en renovación PATCH)

      notificationService.sendRenewalConfirmation(updatedBrand).catch((err) =>

        console.error('[Subscription] Error enviando email de confirmación de pago:', err)

      );



      // Auditoría

      auditService.log({

        admin_id: (req as any).admin?.id ?? 'unknown',

        admin_email: (req as any).admin?.email ?? 'unknown',

        action: 'subscription.renew',

        target_brand_id: brandId,

        details: { amount: finalAmount, payment_method: paymentData.payment_method, months: periodMonths, plan: planToApply },

      });



      return res.json({

        message: 'Pago registrado y suscripción renovada exitosamente',

        discount: discount > 0 ? `${discount * 100}%` : null,

        months: periodMonths,

        amountCharged: finalAmount,

        brand: {

          id: updatedBrand.id,

          name: updatedBrand.name,

          plan: updatedBrand.plan,

          subscription_status: updatedBrand.subscription_status,

          subscription_end_date: updatedBrand.subscription_end_date,

        },

      });

    } catch (error: any) {

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al registrar pago'),

      });

    }

  }

  /**

   * POST /api/admin/subscriptions/reprocess-wompi/:reference

   * BUG #6 FIX: Reprocessa un pago de Wompi que fue cobrado pero no activó la suscripción.

   * Consulta la tabla subscription_payments con esa referencia y pending_registrations.

   * ñtil cuando el webhook falló silenciosamente y el usuario pagó pero no tiene plan activo.

   */

  async reprocessWompiPayment(req: AdminAuthRequest, res: Response): Promise<Response> {

    try {

      const { reference } = req.params;

      if (!reference) {

        return res.status(400).json({ error: 'BAD_REQUEST', message: 'Reference requerida' });

      }



      const { supabaseAdmin } = await import('../config/supabase');



      // 1. Verificar que el pago existe en subscription_payments

      const { data: existingPayment } = await supabaseAdmin

        .from('subscription_payments')

        .select('*')

        .eq('reference', reference)

        .maybeSingle();



      if (existingPayment) {

        return res.status(409).json({

          error: 'ALREADY_PROCESSED',

          message: 'Este pago ya fue procesado y registrado correctamente.',

          payment: { id: existingPayment.id, brand_id: existingPayment.brand_id, amount: existingPayment.amount, status: existingPayment.status },

        });

      }



      // 2. Buscar en pending_registrations

      const { data: pending } = await supabaseAdmin

        .from('pending_registrations')

        .select('*')

        .eq('reference', reference)

        .maybeSingle();



      if (!pending) {

        return res.status(404).json({

          error: 'NOT_FOUND',

          message: 'No se encontró ningún pago pendiente con esa referencia.',

        });

      }



      if (pending.status !== 'paid') {

        return res.status(400).json({

          error: 'NOT_PAID',

          message: `El pago tiene status "${pending.status}", no es un pago confirmado.`,

        });

      }



      // 3. Buscar la marca (brand_id desde pending o por email)

      let brandId: string | null = (pending as any).brand_id || null;



      if (!brandId) {

        const { data: brand } = await supabaseAdmin

          .from('brands')

          .select('id')

          .eq('email', pending.email)

          .maybeSingle();

        brandId = brand?.id || null;

      }



      if (!brandId) {

        return res.status(404).json({

          error: 'BRAND_NOT_FOUND',

          message: 'No se encontró la marca asociada. El usuario puede necesitar completar el registro primero.',

          pending: { email: pending.email, plan: pending.plan, status: pending.status },

        });

      }



      // 4. Activar la suscripción manualmente

      const months = pending.months || 1;

      const plan = (pending.plan || 'BASIC').toUpperCase();
      const amount = Number(pending.amount || 0);



      await subscriptionService.renewSubscription(
        brandId,
        {
          brand_id: brandId,

          amount,

          currency: 'COP',

          payment_method: 'wompi',

          status: 'completed',

          months_paid: months,

          payment_date: new Date().toISOString(),

          notes: `[REPROCESS] Reactivado manualmente por admin. Referencia original: ${reference}. Admin: ${(req as AdminAuthRequest).admin?.email || 'unknown'}.`,

          reference,

        },

        months,

        plan,

        false
      );

      await planChangeService.markCompleted(reference, amount).catch(() => {});

      // 5. Registrar en admin_notifications
      await supabaseAdmin.from('admin_notifications').insert({

        type: 'payment_reprocessed',

        title: 'â Pago reprocessado exitosamente',

        message: `Pago ref ${reference} activado manualmente para brand ${brandId}.`,

        severity: 'info',

        brand_id: brandId,

        metadata: { reference, plan, months, amount },

      });



      return res.json({

        success: true,

        message: 'Suscripción activada correctamente.',

        brandId,

        plan,

        months,

        reference,

      });

    } catch (error: any) {

      return res.status(500).json({

        error: 'INTERNAL_ERROR',

        message: sanitizeError(error, 'Error al reprocesar el pago'),

      });

    }

  }



}

