  });



  // Limpieza de admin_notifications con más de 30 días — todos los días a las 4:00 AM

  cron.schedule('0 4 * * *', async () => {

    console.log('[Cleanup Job] Limpiando notificaciones admin antiguas (>30 días)...');

    try {

