import { supabaseAdmin } from '../../config/supabase';
import bcrypt from 'bcryptjs';
import crypto from 'crypto';

export interface Admin {
  id: string;
  email: string;
  name: string;
  role: string;
  created_at: string;
  updated_at: string;
}

type AdminRecord = Admin & {
  password: string;
  permissions?: string[];
  reset_token?: string | null;
  reset_token_expires_at?: string | null;
};

/**
 * Auth Admin Service — Autenticación y gestión de administradores.
 * Extraído de AdminService para mejorar mantenibilidad.
 */
export class AuthAdminService {
  // ———————————————————— Helpers privados —

  private isValidBcryptHash(value: string | null | undefined): boolean {
    if (!value) return false;
    return /^\$2[aby]\$\d{2}\$[./A-Za-z0-9]{53}$/.test(value);
  }

  private validatePasswordComplexity(password: string): { isValid: boolean; message?: string } {
    if (password.length < 8) return { isValid: false, message: 'La contraseña debe tener al menos 8 caracteres' };
    if (!/[A-Z]/.test(password)) return { isValid: false, message: 'La contraseña debe contener al menos una letra mayúscula' };
    if (!/[a-z]/.test(password)) return { isValid: false, message: 'La contraseña debe contener al menos una letra minúscula' };
    if (!/[0-9]/.test(password)) return { isValid: false, message: 'La contraseña debe contener al menos un número' };
    if (!/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password)) {
      return { isValid: false, message: 'La contraseña debe contener al menos un carácter especial (!@#$%^&*...)' };
    }
    return { isValid: true };
  }

  // ———————————————————— Lookup —

  async getAdminByEmail(email: string): Promise<Admin | null> {
    const { data, error } = await supabaseAdmin
      .from('admins')
      .select('*')
      .ilike('email', email.trim())
      .single();
    if (error || !data) return null;
    return data as Admin;
  }

  async getAdminById(adminId: string): Promise<Admin | null> {
    const { data, error } = await supabaseAdmin.from('admins').select('*').eq('id', adminId).single();
    if (error || !data) return null;
    return data as Admin;
  }

  async getAdminByGoogleId(googleId: string): Promise<Admin | null> {
    const { data, error } = await supabaseAdmin.from('admins').select('*').eq('google_id', googleId).single();
    if (error || !data) return null;
    return data as Admin;
  }

  async updateAdminGoogleId(adminId: string, googleId: string): Promise<void> {
    const { error } = await supabaseAdmin
      .from('admins')
      .update({ google_id: googleId, updated_at: new Date().toISOString() })
      .eq('id', adminId);

    if (error) throw new Error('Error al vincular ID de Google: ' + error.message);
  }

  async verifyPassword(plainPassword: string, hashedPassword: string): Promise<boolean> {
    return bcrypt.compare(plainPassword, hashedPassword);
  }

  // ———————————————————— CRUD de Admins —

  async listAdmins(): Promise<Omit<Admin, 'password'>[]> {
    const { data, error } = await supabaseAdmin
      .from('admins')
      .select('id, email, name, role, permissions, created_at, updated_at')
      .order('created_at', { ascending: true });

    if (error) throw new Error('Error al obtener admins: ' + error.message);
    return (data || []) as any;
  }

  async createAdmin(data: {
    email: string;
    password: string;
    name: string;
    permissions?: string[];
  }): Promise<Omit<Admin, 'password'>> {
    const { data: existing } = await supabaseAdmin.from('admins').select('id').eq('email', data.email).single();
    if (existing) throw new Error('El email ya está registrado como admin');

    const hashedPassword = await bcrypt.hash(data.password, 10);

    const { data: newAdmin, error } = await supabaseAdmin
      .from('admins')
      .insert({ email: data.email, password: hashedPassword, name: data.name, role: 'admin', permissions: data.permissions || [] })
      .select('id, email, name, role, permissions, created_at, updated_at')
      .single();

    if (error || !newAdmin) throw new Error('Error al crear admin: ' + error?.message);
    return newAdmin as any;
  }

  async updateAdminPermissions(adminId: string, permissions: string[]): Promise<void> {
    const { error } = await supabaseAdmin.from('admins').update({ permissions }).eq('id', adminId);
    if (error) throw new Error('Error al actualizar permisos: ' + error.message);
  }

  async deleteAdmin(adminId: string, requestingAdminId: string): Promise<void> {
    if (adminId === requestingAdminId) throw new Error('No puedes eliminarte a ti mismo');
    const { error } = await supabaseAdmin.from('admins').delete().eq('id', adminId);
    if (error) throw new Error('Error al eliminar admin: ' + error.message);
  }

  // ———————————————————— Gestión de Contraseñas —

  async changeAdminPassword(adminId: string, newPassword: string): Promise<void> {
    if (newPassword.length < 8) throw new Error('La nueva contraseña debe tener al menos 8 caracteres');

    const { data: admin, error } = await supabaseAdmin.from('admins').select('id').eq('id', adminId).single();
    if (error || !admin) throw new Error('Admin no encontrado');

    const hashed = await bcrypt.hash(newPassword, 10);
    const { error: updateError } = await supabaseAdmin
      .from('admins')
      .update({ password: hashed, reset_token: null, reset_token_expires_at: null, updated_at: new Date().toISOString() })
      .eq('id', adminId);

    if (updateError) throw new Error('Error al actualizar contraseña: ' + updateError.message);
  }

  async resetAdminPassword(adminId: string): Promise<{ admin: Omit<Admin, 'password'>; newPassword: string }> {
    const { data: admin, error: fetchError } = await supabaseAdmin
      .from('admins')
      .select('id, email, name, role, permissions, created_at, updated_at')
      .eq('id', adminId)
      .single();

    if (fetchError || !admin) throw new Error('Admin no encontrado');

    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789';
    let newPassword = '';
    for (let i = 0; i < 12; i++) newPassword += chars.charAt(Math.floor(Math.random() * chars.length));

    const hashedPassword = await bcrypt.hash(newPassword, 10);
    const { error: updateError } = await supabaseAdmin.from('admins').update({ password: hashedPassword }).eq('id', adminId);
    if (updateError) throw new Error('Error al actualizar contraseña: ' + updateError.message);

    return { admin: admin as any, newPassword };
  }

  async changeOwnPassword(adminId: string, currentPassword: string, newPassword: string): Promise<void> {
    const { data: admin, error } = await supabaseAdmin.from('admins').select('id, password').eq('id', adminId).single();
    if (error || !admin) throw new Error('Admin no encontrado');

    const adminRecord = admin as Pick<AdminRecord, 'id' | 'password'>;

    if (!this.isValidBcryptHash(adminRecord.password)) {
      throw new Error('La cuenta de administrador tiene una contraseña inválida en base de datos. Restablécela desde el panel o recrea el admin con el script seguro.');
    }

    const valid = await bcrypt.compare(currentPassword, adminRecord.password);
    if (!valid) throw new Error('La contraseña actual es incorrecta');

    const complexityCheck = this.validatePasswordComplexity(newPassword);
    if (!complexityCheck.isValid) throw new Error(complexityCheck.message);

    if (newPassword === currentPassword) throw new Error('La nueva contraseña debe ser diferente a la actual');

    const hashed = await bcrypt.hash(newPassword, 10);
    const { error: updateError } = await supabaseAdmin
      .from('admins')
      .update({ password: hashed, reset_token: null, reset_token_expires_at: null, updated_at: new Date().toISOString() })
      .eq('id', adminId);

    if (updateError) throw new Error('Error al actualizar contraseña: ' + updateError.message);
  }

  async requestPasswordResetGetToken(email: string): Promise<{ admin: { name: string; email: string } | null; token: string | null }> {
    const { data: admin } = await supabaseAdmin.from('admins').select('id, name, email').eq('email', email).single();
    if (!admin) return { admin: null, token: null };

    const token = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 60 * 60 * 1000);

    const { error } = await supabaseAdmin
      .from('admins')
      .update({ reset_token: token, reset_token_expires_at: expiresAt.toISOString(), updated_at: new Date().toISOString() })
      .eq('id', admin.id);

    if (error) throw new Error('Error al generar token de recuperación: ' + error.message);
    return { admin: { name: admin.name, email: admin.email }, token };
  }

  async resetPasswordWithToken(token: string, newPassword: string): Promise<void> {
    const { data: admin, error } = await supabaseAdmin.from('admins').select('id, reset_token_expires_at').eq('reset_token', token).single();
    if (error || !admin) throw new Error('TOKEN_INVALID');

    const expiresAt = admin.reset_token_expires_at ? new Date(admin.reset_token_expires_at) : null;
    if (!expiresAt || expiresAt < new Date()) throw new Error('TOKEN_EXPIRED');

    const complexityCheck = this.validatePasswordComplexity(newPassword);
    if (!complexityCheck.isValid) throw new Error('PASSWORD_TOO_SHORT');

    const hashed = await bcrypt.hash(newPassword, 10);
    const { error: updateError } = await supabaseAdmin
      .from('admins')
      .update({ password: hashed, reset_token: null, reset_token_expires_at: null, updated_at: new Date().toISOString() })
      .eq('id', admin.id);

    if (updateError) throw new Error('Error al actualizar contraseña: ' + updateError.message);
  }
}

export const authAdminService = new AuthAdminService();

import { supabaseAdmin } from '../../config/supabase';
import bcrypt from 'bcryptjs';
import { getBrandSocialLinks } from '../../utils/brandLifecycle';

export interface BrandWithStats {
  id: string;
  email: string;
  name: string;
  slug: string;
  plan: string;
  created_at: string;
  products_count: number;
  generations_count: number;
  last_generation: string | null;
}

/**
 * Brand Admin Service — Gestión de marcas desde el panel de administración.
 * Extraído de AdminService para mejorar mantenibilidad.
 */
export class BrandAdminService {
  /**
   * Obtener todas las marcas con estadísticas (optimizado con Promise.all)
   */
  async getAllBrandsWithStats(): Promise<any[]> {
    try {
      const { data: brands, error } = await supabaseAdmin
        .from('brands')
        .select('*')
        .order('created_at', { ascending: false });

      if (error || !brands) {
        throw new Error('Error al obtener marcas: ' + error?.message);
      }

      // Filtrar marcas que tienen el flag de archivado en social_links
      const activeBrands = brands.filter(b => {
        const sl = b.social_links || {};
        return !sl.account_archived_at;
      });

      const brandIds = activeBrands.map(b => b.id);

      const now = new Date();
      const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);

      const [productsData, generationsData, monthlyData, successData, failedData] = await Promise.all([
        supabaseAdmin.from('products').select('brand_id').in('brand_id', brandIds).eq('is_active', true),
        supabaseAdmin.from('generations').select('brand_id').in('brand_id', brandIds),
        supabaseAdmin.from('generations').select('brand_id').in('brand_id', brandIds).gte('generated_at', startOfMonth.toISOString()),
        supabaseAdmin.from('generations').select('brand_id').in('brand_id', brandIds).eq('status', 'SUCCESS'),
        supabaseAdmin.from('generations').select('brand_id').in('brand_id', brandIds).eq('status', 'FAILED'),
      ]);

      const productCounts: Record<string, number> = {};
      const generationCounts: Record<string, number> = {};
      const monthlyCounts: Record<string, number> = {};
      const successCounts: Record<string, number> = {};
      const failedCounts: Record<string, number> = {};

      productsData.data?.forEach(p => { productCounts[p.brand_id] = (productCounts[p.brand_id] || 0) + 1; });
      generationsData.data?.forEach(g => { generationCounts[g.brand_id] = (generationCounts[g.brand_id] || 0) + 1; });
      monthlyData.data?.forEach(m => { monthlyCounts[m.brand_id] = (monthlyCounts[m.brand_id] || 0) + 1; });
      successData.data?.forEach(s => { successCounts[s.brand_id] = (successCounts[s.brand_id] || 0) + 1; });
      failedData.data?.forEach(f => { failedCounts[f.brand_id] = (failedCounts[f.brand_id] || 0) + 1; });

      return activeBrands.map(brand => {
        const trialEnd = brand.trial_end_date ? new Date(brand.trial_end_date) : null;
        const isInTrial =
          brand.plan === 'TRIAL' &&
          trialEnd !== null &&
          trialEnd > now &&
          brand.subscription_status !== 'suspended';
        const trialDaysRemaining = isInTrial && trialEnd
          ? Math.ceil((trialEnd.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
          : null;

        return {
          id: brand.id,
          email: brand.email,
          name: brand.name,
          slug: brand.slug,
          plan: brand.plan,
          created_at: brand.created_at,
          phone: brand.phone,
          address: brand.address,
          city: brand.city,
          country: brand.country,
          contact_name: brand.contact_name,
          subscription_status: brand.subscription_status,
          trial_end_date: brand.trial_end_date,
          is_in_trial: isInTrial,
          trial_days_remaining: trialDaysRemaining,
          has_landing_page: brand.has_landing_page ?? false,
          modal_title: brand.modal_title ?? null,
          modal_description: brand.modal_description ?? null,
          modal_features: brand.modal_features ?? null,
          totalGenerations: generationCounts[brand.id] || 0,
          successfulGenerations: successCounts[brand.id] || 0,
          failedGenerations: failedCounts[brand.id] || 0,
          generationsThisMonth: monthlyCounts[brand.id] || 0,
          productsCount: productCounts[brand.id] || 0,
          // Retrocompatibilidad
          stats: {
            productsCount: productCounts[brand.id] || 0,
            generationsCount: generationCounts[brand.id] || 0,
            generationsThisMonth: monthlyCounts[brand.id] || 0,
          },
        };
      });
    } catch (error) {
      console.error('Error in getAllBrandsWithStats:', error);
      throw error;
    }
  }

  /**
   * Cambiar el plan de una marca (solo entre planes pagos activos)
   */
  async changeBrandPlan(brandId: string, newPlan: 'BASIC' | 'PRO'): Promise<void> {
    const { data: current } = await supabaseAdmin
      .from('brands')
      .select('plan, subscription_start_date, subscription_end_date, subscription_status, trial_end_date')
      .eq('id', brandId)
      .single();

    const updatePayload: Record<string, any> = { plan: newPlan };
    const now = new Date();

    const hasActiveTrial =
      current?.plan === 'TRIAL' &&
      !!current?.trial_end_date &&
      new Date(current.trial_end_date).getTime() > now.getTime() &&
      current?.subscription_status !== 'active' &&
      current?.subscription_status !== 'expiring_soon';

    if (hasActiveTrial) {
      throw new Error('PLAN_CHANGE_REQUIRES_PAYMENT');
    }

    const hasActivePaidSubscription =
      !!current?.subscription_end_date &&
      new Date(current.subscription_end_date).getTime() > now.getTime() &&
      (current?.subscription_status === 'active' || current?.subscription_status === 'expiring_soon');

    if (!hasActivePaidSubscription) {
      throw new Error('PLAN_CHANGE_REQUIRES_ACTIVE_SUBSCRIPTION');
    }

    const status = current?.subscription_status;
    if (!status || status === 'suspended' || status === 'expired') {
      const endDate = new Date(now);
      endDate.setDate(endDate.getDate() + 30);
      updatePayload.subscription_status = 'active';
      if (!current?.subscription_start_date) updatePayload.subscription_start_date = now.toISOString();
      if (!current?.subscription_end_date) updatePayload.subscription_end_date = endDate.toISOString();
    }

    const { error } = await supabaseAdmin.from('brands').update(updatePayload).eq('id', brandId);
    if (error) throw new Error('Error al cambiar plan: ' + error.message);
  }

  /**
   * Archivar una marca (soft delete — suspende y registra en social_links)
   */
  async deleteBrand(brandId: string): Promise<void> {
    const { data: brand, error: fetchError } = await supabaseAdmin
      .from('brands')
      .select('id, email, slug, social_links')
      .eq('id', brandId)
      .single();

    if (fetchError || !brand) throw new Error('Marca no encontrada');

    // Generar sufijo único para liberar el email y slug originales
    const suffix = Math.random().toString(36).substring(2, 7);
    const archivedEmail = `archived-${brandId.slice(0, 8)}-${suffix}@lookitry.archived`;
    const archivedSlug = `archived-${brand.slug}-${suffix}`.replace(/_/g, '-');
    const socialLinks = getBrandSocialLinks(brand as any);

    const { error: deleteError } = await supabaseAdmin
      .from('brands')
      .update({
        email: archivedEmail, // Liberamos el email original
        slug: archivedSlug,   // Liberamos el slug original
        subscription_status: 'suspended',
        has_landing_page: false,
        landing_suspended_at: new Date().toISOString(),
        social_links: {
          ...socialLinks,
          account_archived_at: new Date().toISOString(),
          account_archived_reason: 'admin_delete_reproduction',
          account_archived_by: 'admin',
          original_email: brand.email,
        },
      })
      .eq('id', brandId);

    if (deleteError) throw new Error('Error al archivar marca y liberar credenciales: ' + deleteError.message);
  }

  /**
   * Resetear una marca (limpiar trial/suscripción pero mantener cuenta e histórico)
   */
  async resetBrand(brandId: string): Promise<void> {
    const { error } = await supabaseAdmin
      .from('brands')
      .update({
        plan: 'BASIC',
        subscription_status: 'expired',
        trial_end_date: null,
        subscription_start_date: null,
        subscription_end_date: null,
        has_landing_page: false,
        landing_suspended_at: null
      })
      .eq('id', brandId);

    if (error) throw new Error('Error al resetear marca: ' + error.message);
  }

  /**
   * Eliminar un producto inactivo de una marca
   */
  async deleteInactiveProduct(brandId: string, productId: string): Promise<void> {
    const { data: product, error: fetchError } = await supabaseAdmin
      .from('products')
      .select('id, is_active, brand_id')
      .eq('id', productId)
      .eq('brand_id', brandId)
      .single();

    if (fetchError || !product) throw new Error('Producto no encontrado o no pertenece a esta marca');
    if (product.is_active) throw new Error('Solo se pueden eliminar productos inactivos');

    const { error: deleteError } = await supabaseAdmin
      .from('products')
      .delete()
      .eq('id', productId)
      .eq('brand_id', brandId);

    if (deleteError) throw new Error('Error al eliminar producto: ' + deleteError.message);
  }

  /**
   * Obtener productos de una marca específica
   */
  async getBrandProducts(brandId: string) {
    const { data, error } = await supabaseAdmin
      .from('products')
      .select('*')
      .eq('brand_id', brandId)
      .order('created_at', { ascending: false });

    if (error) throw new Error('Error al obtener productos: ' + error.message);
    return data || [];
  }

  /**
   * Crear una nueva marca manualmente desde el panel admin
   */
  async createBrand(data: {
    email: string;
    password: string;
    name: string;
    slug: string;
    plan?: 'BASIC' | 'PRO' | 'TRIAL';
    trial_days?: number;
    phone?: string;
    contact_name?: string;
  }) {
    const { data: existingEmail } = await supabaseAdmin.from('brands').select('id').eq('email', data.email).single();
    if (existingEmail) throw new Error('El email ya está registrado');

    const { data: existingSlug } = await supabaseAdmin.from('brands').select('id').eq('slug', data.slug).single();
    if (existingSlug) throw new Error('El slug ya está en uso');

    const hashedPassword = await bcrypt.hash(data.password, 10);
    const trialDays = data.trial_days ?? 7;
    const trialEndDate = new Date();
    trialEndDate.setDate(trialEndDate.getDate() + trialDays);
    const requestedPlan = String(data.plan || 'TRIAL').toUpperCase();

    const { data: newBrand, error } = await supabaseAdmin
      .from('brands')
      .insert({
        email: data.email,
        password: hashedPassword,
        name: data.name,
        slug: data.slug,
        plan: requestedPlan,
        phone: data.phone || null,
        contact_name: data.contact_name || null,
        subscription_status: null,
        trial_end_date: trialEndDate.toISOString(),
        trial_generations_limit: 30,
      })
      .select()
      .single();

    if (error || !newBrand) throw new Error('Error al crear la marca: ' + error?.message);
    return newBrand;
  }

  /**
   * Obtener marcas en período de prueba activo
   */
  async getTrialBrands() {
    const now = new Date().toISOString();

    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('id, name, email, slug, plan, trial_end_date, subscription_status, created_at')
      .eq('plan', 'TRIAL')
      .gt('trial_end_date', now)
      .neq('subscription_status', 'suspended')
      .order('trial_end_date', { ascending: true });

    if (error) throw new Error('Error al obtener marcas en trial: ' + error.message);

    return (data || []).map(brand => {
      const trialEnd = new Date(brand.trial_end_date);
      const diffMs = trialEnd.getTime() - new Date().getTime();
      const daysRemaining = Math.ceil(diffMs / (1000 * 60 * 60 * 24));
      return { ...brand, trial_days_remaining: daysRemaining };
    });
  }

  /**
   * Obtener ficha completa de una marca (para la vista de detalle del admin)
   */
  async getBrandFull(brandId: string) {
    const { data: brand, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('id', brandId)
      .single();

    if (error || !brand) throw new Error('Marca no encontrada');

    const now = new Date();
    const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    const [productsRes, generationsRes, paymentsRes, feedbackRes] = await Promise.all([
      supabaseAdmin.from('products').select('id, name, category, is_active, external_id, created_at').eq('brand_id', brandId).order('created_at', { ascending: false }),
      supabaseAdmin.from('generations').select('id, status, generated_at, error_message, product_id').eq('brand_id', brandId).gte('generated_at', thirtyDaysAgo.toISOString()).order('generated_at', { ascending: false }).limit(50),
      supabaseAdmin.from('subscription_payments').select('id, amount, currency, status, payment_date, payment_method, notes').eq('brand_id', brandId).order('payment_date', { ascending: false }).limit(20),
      supabaseAdmin.from('generation_feedback').select('id, error_type, comment, created_at, resolved').eq('brand_id', brandId).order('created_at', { ascending: false }).limit(20),
    ]);

    const products = productsRes.data || [];
    const generations = generationsRes.data || [];
    const payments = paymentsRes.data || [];
    const feedback = feedbackRes.data || [];

    const totalGenerations = generations.length;
    const successfulGenerations = generations.filter(g => g.status === 'SUCCESS').length;
    const failedGenerations = generations.filter(g => g.status === 'FAILED').length;
    const successRate = totalGenerations > 0 ? (successfulGenerations / totalGenerations) * 100 : 0;
    const totalRevenue = payments.filter(p => p.status === 'completed').reduce((sum, p) => sum + (Number(p.amount) || 0), 0);

    const isInTrial = brand.plan === 'TRIAL' && brand.trial_end_date && new Date(brand.trial_end_date) > now;
    const trialDaysRemaining = isInTrial ? Math.ceil((new Date(brand.trial_end_date!).getTime() - now.getTime()) / (1000 * 60 * 60 * 24)) : null;

    const riskFactors: string[] = [];
    let riskScore = 0;
    if (isInTrial && trialDaysRemaining !== null && trialDaysRemaining <= 3) { riskFactors.push(`Trial expira en ${trialDaysRemaining} días`); riskScore += 30; }
    if (totalGenerations === 0) { riskFactors.push('Sin uso en 30 días'); riskScore += 25; }
    if (totalGenerations > 0 && failedGenerations / totalGenerations > 0.5) { riskFactors.push('Alta tasa de error en generaciones'); riskScore += 25; }
    if (brand.subscription_status === 'suspended') { riskFactors.push('Suscripción suspendida'); riskScore += 40; }

    return {
      brand: {
        id: brand.id, name: brand.name, email: brand.email, slug: brand.slug, plan: brand.plan,
        subscription_status: brand.subscription_status, trial_end_date: brand.trial_end_date,
        subscription_end_date: brand.subscription_end_date, created_at: brand.created_at,
        has_landing_page: brand.has_landing_page, landing_suspended_at: brand.landing_suspended_at,
        phone: brand.phone, contact_name: brand.contact_name,
        is_in_trial: isInTrial, trial_days_remaining: trialDaysRemaining,
      },
      usage: {
        products_count: products.length,
        active_products: products.filter(p => p.is_active).length,
        generations_30d: totalGenerations,
        successful_generations: successfulGenerations,
        failed_generations: failedGenerations,
        success_rate: Math.round(successRate * 10) / 10,
        last_generation: generations[0]?.generated_at || null,
      },
      finances: {
        total_revenue: totalRevenue,
        payments,
        payment_count: payments.length,
        failed_payments: payments.filter(p => p.status === 'failed').length,
      },
      support: {
        feedback_count: feedback.length,
        unresolved_feedback: feedback.filter(f => !f.resolved).length,
        feedback,
      },
      risk: { score: Math.min(riskScore, 100), factors: riskFactors },
      products,
      recent_generations: generations,
    };
  }

  /**
   * Obtener marcas para dropdowns (con soporte para limit y search)
   */
  async getBrandsForDropdown(options: { limit?: number; search?: string } = {}) {
    const { limit = 1000, search } = options;

    let query = supabaseAdmin
      .from('brands')
      .select('id, name, email, slug, plan, subscription_status, social_links')
      .order('name', { ascending: true })
      .limit(limit * 2); // Fetch more to allow for filtering

    if (search && typeof search === 'string' && search.trim().length > 0) {
      const searchTerm = search.trim();
      query = query.or(`name.ilike.%${searchTerm}%,email.ilike.%${searchTerm}%,slug.ilike.%${searchTerm}%`);
    }

    const { data, error } = await query;

    if (error) throw new Error('Error al obtener marcas: ' + error.message);
    
    // Filtrar archivados en memoria para mayor seguridad con JSONB
    return (data || [])
      .filter(brand => {
        const sl = brand.social_links || {};
        return !sl.account_archived_at;
      })
      .slice(0, limit);
  }
}

export const brandAdminService = new BrandAdminService();

import { supabaseAdmin } from '../../config/supabase';
import { getReportingTrm, normalizePaymentRecordToCop } from '../../utils/paymentNormalization';
import { getPaymentDisplayBrand, inferBillingType, inferIncludesLanding } from '../../utils/paymentLedger';

/**
 * Payment Admin Service — Gestión de pagos y activación de planes.
 * Extraído de AdminService para mejorar mantenibilidad.
 */
export class PaymentAdminService {
  /**
   * Historial de pagos global con filtros y estadísticas
   */
  async getPayments(filters: {
    brand_id?: string;
    status?: string;
    payment_method?: string;
    from?: string;
    to?: string;
    search?: string;
    limit?: number;
    offset?: number;
  }) {
    const reportingTrm = await getReportingTrm();
    const trmCache = new Map<string, number | null>();

    // 1. Consulta de estadísticas (independiente de la paginación)
    let statsQuery = supabaseAdmin
      .from('subscription_payments')
      .select('amount, currency, notes')
      .eq('status', 'completed');

    if (filters.brand_id) statsQuery = statsQuery.eq('brand_id', filters.brand_id);
    if (filters.payment_method) statsQuery = statsQuery.eq('payment_method', filters.payment_method);
    if (filters.from) statsQuery = statsQuery.gte('payment_date', new Date(filters.from).toISOString());
    if (filters.to) {
      const endDate = new Date(filters.to);
      endDate.setHours(23, 59, 59, 999);
      statsQuery = statsQuery.lte('payment_date', endDate.toISOString());
    }

    const { data: statsRows, error: statsError } = await statsQuery;
    if (statsError) throw new Error('Error al calcular ingresos: ' + statsError.message);

    // 2. Consulta paginada principal
    let query = supabaseAdmin
      .from('subscription_payments')
      .select('*, brands(name, email, slug, plan, social_links)', { count: 'exact' })
      .order('payment_date', { ascending: false });

    if (filters.brand_id) query = query.eq('brand_id', filters.brand_id);
    if (filters.status) query = query.eq('status', filters.status);
    if (filters.payment_method) query = query.eq('payment_method', filters.payment_method);
    if (filters.from) query = query.gte('payment_date', new Date(filters.from).toISOString());
    if (filters.to) {
      const endDate = new Date(filters.to);
      endDate.setHours(23, 59, 59, 999);
      query = query.lte('payment_date', endDate.toISOString());
    }
    if (typeof filters.limit === 'number' && filters.limit > 0) {
      const offset = filters.offset || 0;
      query = query.range(offset, offset + filters.limit - 1);
    }

    const { data, error, count } = await query;
    if (error) throw new Error('Error al obtener pagos: ' + error.message);

    // 3. Filtrar por búsqueda de texto (post-fetch)
    const normalizedSearch = filters.search?.trim().toLowerCase();
    const filteredPayments = normalizedSearch
      ? (data || []).filter((payment: any) => {
          const displayBrand = getPaymentDisplayBrand(payment);
          const haystack = [displayBrand.name, displayBrand.email, displayBrand.slug, payment.reference, payment.transaction_id, payment.notes]
            .filter(Boolean).join(' ').toLowerCase();
          return haystack.includes(normalizedSearch);
        })
      : (data || []);

    // 4. Normalizar monedas y enriquecer campos
    const normalizedPayments = await Promise.all(
      filteredPayments.map(async (payment: any) => {
        if (!payment.brands) {
          payment.brands = { name: 'Marca Desconocida', email: 'N/A', slug: 'unknown', plan: 'N/A' };
        }
        const normalized = await normalizePaymentRecordToCop(payment, reportingTrm, trmCache);
        const displayBrand = getPaymentDisplayBrand(payment);
        return {
          ...payment,
          brands: {
            name: displayBrand?.name || 'N/A',
            email: displayBrand?.email || 'N/A',
            slug: displayBrand?.slug || 'unknown',
            plan: displayBrand?.plan || 'N/A',
          },
          billing_type: inferBillingType(payment),
          includes_landing: inferIncludesLanding(payment),
          archived: Boolean(payment.brands?.social_links?.account_archived_at),
          amount: normalized?.amountCop || 0,
          amount_original: normalized?.originalAmount || 0,
          amount_cop: normalized?.amountCop || 0,
          exchange_rate_used: normalized?.exchangeRateUsed || 0,
          currency: normalized?.currency || 'COP',
          reference_used: normalized?.referenceUsed || false,
        };
      })
    );

    const completedPayments = normalizedPayments.filter((payment: any) => payment.status === 'completed');
    const normalizedStatsRows = await Promise.all(
      (statsRows || []).map((payment: any) => normalizePaymentRecordToCop(payment, reportingTrm, trmCache))
    );
    const totalRevenue = normalizedStatsRows.reduce((sum: number, payment) => sum + payment.amountCop, 0);

    return {
      payments: normalizedPayments,
      count: normalizedSearch ? normalizedPayments.length : (count || 0),
      stats: {
        total_revenue: totalRevenue,
        completed_count: completedPayments.length,
      },
    };
  }

  /**
   * Activar plan de una marca (convierte trial en suscripción activa pagada por 30 días)
   */
  async activateBrandPlan(
    brandId: string,
    options: {
      plan: 'BASIC' | 'PRO';
      amount: number;
      payment_method: string;
      notes: string;
    }
  ) {
    const now = new Date();
    const endDate = new Date(now);
    endDate.setDate(endDate.getDate() + 30);

    const { data: updatedBrand, error } = await supabaseAdmin
      .from('brands')
      .update({
        plan: options.plan,
        subscription_status: 'active',
        subscription_start_date: now.toISOString(),
        subscription_end_date: endDate.toISOString(),
        trial_end_date: null,
        trial_payment_status: null,
        last_payment_date: now.toISOString(),
        next_payment_date: endDate.toISOString(),
      })
      .eq('id', brandId)
      .select()
      .single();

    if (error || !updatedBrand) throw new Error('Error al activar plan: ' + error?.message);

    if (options.amount > 0) {
      await supabaseAdmin.from('subscription_payments').insert({
        brand_id: brandId,
        amount: options.amount,
        currency: 'COP',
        payment_date: now.toISOString(),
        payment_method: options.payment_method,
        status: 'completed',
        notes: options.notes,
      });
    }

    return updatedBrand;
  }
}

