export class BrandsService {

async getBrandById(brandId: string): Promise<Brand | null> {
    if (!brandId) return null;

    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('id', brandId)
      .maybeSingle();

    if (error) {
      console.error('[brandsService.getBrandById] Error:', error);
      return null;
    }

    return data as Brand;
  }



  async updateBrand(brandId: string, updates: UpdateBrandDto): Promise<Brand> {

    // 1. Validar slug

    if (updates.slug) {

      const slugRegex = /^[a-z0-9-]+$/;

      if (!slugRegex.test(updates.slug) || updates.slug.length < 3 || updates.slug.length > 50) {

        throw new Error('El slug debe tener entre 3 y 50 caracteres, solo letras minúsculas, números y guiones');

      }

      

      const reservedSlugs = [

        'admin', 'api', 'app', 'blog', 'checkout', 'dashboard', 'home', 'login', 

        'logout', 'register', 'signup', 'signin', 'password', 'reset', 'forgot',

        'account', 'accounts', 'auth', 'authorize', 'callback', 'contact', 'docs',

        'documentation', 'download', 'downloads', 'email', 'help', 'jobs', 'legal',

        'market', 'markets', 'news', 'onboarding', 'payment', 'payments', 'plans',

        'pricing', 'privacy', 'products', 'profile', 'public', 'root', 'secure',

        'security', 'settings', 'shop', 'site', 'sites', 'static', 'support', 'terms',

        'tools', 'trial', 'trial-checkout', 'upload', 'uploads', 'users', 'verify',

        'webhook', 'webhooks', 'www', 'mail', 'superadmin', 'system', 'null', 'undefined',

        'true', 'false', 'none', 'default', 'main', 'test', 'demo', 'dev', 'development',

        'staging', 'stage', 'prod', 'production', 'lookitry', 'mobile', 'desktop'

      ];

      if (reservedSlugs.includes(updates.slug.toLowerCase())) {

        throw new Error('Este slug está reservado. Elige otro.');

      }



      const existing = await this.getBrandBySlug(updates.slug);

      if (existing && existing.id !== brandId) {

        throw new Error('Ese slug ya está en uso por otra marca');

      }

    }



    // 2. Validar colores

    if (updates.primary_color && !this.isValidHexColor(updates.primary_color)) {

      throw new Error('El color primario debe estar en formato hexadecimal (#RRGGBB)');

    }



    // 3. Filtrar campos que podrían no existir en la DB (Blindaje contra Error 500)

    // Obtenemos las columnas reales de la tabla para este entorno

    const { data: sample } = await supabaseAdmin.from('brands').select('*').limit(1).single();

    const validColumns = sample ? Object.keys(sample) : [];

    

    const filteredUpdates: any = {};

    Object.keys(updates).forEach(key => {

      if (validColumns.includes(key) && (updates as any)[key] !== undefined) {

        filteredUpdates[key] = (updates as any)[key];

      }

    });



    // 4. Ejecutar actualización con campos filtrados

    const { data, error } = await supabaseAdmin

      .from('brands')

      .update(filteredUpdates)

      .eq('id', brandId)

      .select()

      .single();



    if (error) {

      console.error('[BrandsService] Error en updateBrand:', error);

      throw new Error('Error al actualizar la marca: ' + error.message);

    }



    if (!data) throw new Error('No se recibieron datos tras la actualización');



    return data as Brand;

  }



  async getBrandBySlug(slug: string): Promise<Brand | null> {

    const { data, error } = await supabaseAdmin

      .from('brands')

      .select('*')

      .eq('slug', slug)

      .single();



    if (error || !data) return null;

    return data as Brand;

  }



  async getBrandByCustomDomain(domain: string): Promise<Brand | null> {

    const { data, error } = await supabaseAdmin

      .from('brands')

      .select('*')

      .eq('custom_domain', domain)

      .single();



    if (error || !data) return null;

    return data as Brand;

  }



  private isValidHexColor(color: string): boolean {

    return /^#[0-9A-Fa-f]{6}$/.test(color);

  }



  async getBrandByApiKey(apiKey: string): Promise<Brand | null> {

    if (!apiKey) return null;



    // Tratamiento transparente de JWTs (para el plugin refactorizado con tokens efímeros)

    if (apiKey.startsWith('ey')) {

      const jwtSecret = process.env.JWT_SECRET;

      if (jwtSecret) {

        try {

          const decoded = jwt.verify(apiKey, jwtSecret) as any;

          if (decoded.brand_id && decoded.type === 'embed_session') {

            return await this.getBrandById(decoded.brand_id);

          }

        } catch (e) {

          console.warn('[BrandsService] JWT erróneo o expirado recibido como API Key:', (e as Error).message);

          return null;

        }

      }

    }



    const { data, error } = await supabaseAdmin

      .from('brands')

      .select('*')

      .eq('api_key', apiKey)

      .single();



    if (error || !data) return null;

    return data as Brand;

  }



  isValidDomain(domain: string): boolean {

    return /^[a-z0-9]+([\-\.]{1}[a-z0-9]+)*\.[a-z]{2,10}$/i.test(domain);

  }

}

import https from 'https';

export interface BrevoEmailOptions {
  to: string;
  subject: string;
  html: string;
  fromName?: string;
}

export interface BrevoSendResult {
  messageId: string;
  accepted: string[];
  rejected: string[];
}

export interface BrevoMessageStatus {
  email: string;
  messageId: string;
  status: 'sent' | 'delivered' | 'opened' | 'clicked' | 'bounced' | 'blocked';
  sentAt?: string;
  deliveredAt?: string;
  openedAt?: string;
  clickedAt?: string;
}

export class BrevoCampaignService {
  private apiKey: string;
  private senderEmail: string;
  private senderName: string;

  constructor() {
    this.apiKey = process.env.BREVO_API_KEY || '';
    const fromStr = process.env.SMTP_FROM || process.env.SMTP_USER || 'info@lookitry.com';
    const parsed = this.parseSender(fromStr);
    this.senderEmail = parsed.email;
    this.senderName = process.env.SMTP_FROM_NAME || parsed.name || 'Lookitry';
  }

  private parseSender(senderStr: string): { name?: string; email: string } {
    const match = senderStr.match(/^(.*)<(.*)>$/);
    if (match) {
      return {
        name: match[1].trim(),
        email: match[2].trim()
      };
    }
    return { email: senderStr.trim() };
  }

  async verifyConnection(): Promise<boolean> {
    try {
      await this.makeRequest('/smtp/statistics/reports', 'GET');
      return true;
    } catch (error) {
      console.error('[Brevo] Connection verification failed:', error);
      return false;
    }
  }

  private async makeRequest(path: string, method: string, body?: object): Promise<any> {
    return new Promise((resolve, reject) => {
      if (!this.apiKey) {
        return reject(new Error('BREVO_API_KEY no configurada'));
      }

      const options = {
        hostname: 'api.brevo.com',
        port: 443,
        path: `/v3${path}`,
        method,
        headers: {
          'Content-Type': 'application/json',
          'api-key': this.apiKey,
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => (data += chunk));
        res.on('end', () => {
          let parsed: any;
          try {
            parsed = JSON.parse(data);
          } catch {
            parsed = data;
          }

          if (res.statusCode && (res.statusCode < 200 || res.statusCode >= 300)) {
            const error: any = new Error(parsed?.message || `Brevo Error ${res.statusCode}`);
            error.statusCode = res.statusCode;
            error.response = parsed;
            console.error(`[Brevo] API Error (${res.statusCode}):`, JSON.stringify(parsed, null, 2));
            return reject(error);
          }
          resolve(parsed);
        });
      });

      req.on('error', reject);

      if (body) {
        req.write(JSON.stringify(body));
      }
      req.end();
    });
  }

  async sendEmail(options: BrevoEmailOptions): Promise<BrevoSendResult> {
    const payload = {
      sender: {
        name: options.fromName || this.senderName,
        email: this.senderEmail,
      },
      to: [{ email: options.to }],
      subject: options.subject,
      htmlContent: options.html,
    };

    const result = await this.makeRequest('/smtp/email', 'POST', payload);

    return {
      messageId: result.messageId || result['message-id'] || '',
      accepted: result.to || [options.to],
      rejected: result.rejected || [],
    };
  }

  async sendBatchEmails(
    emails: Array<{ to: string; subject: string; html: string; fromName?: string }>
  ): Promise<{ successful: number; failed: number; results: BrevoSendResult[] }> {
    if (!this.apiKey) {
      throw new Error('BREVO_API_KEY no configurada');
    }

    const payload = {
      sender: {
        name: this.senderName,
        email: this.senderEmail,
      },
      to: emails.map((e) => ({ email: e.to })),
      subject: emails[0]?.subject || 'Email de Lookitry',
      htmlContent: emails[0]?.html || '',
    };

    try {
      const result = await this.makeRequest('/smtp/email', 'POST', payload);
      return {
        successful: emails.length,
        failed: 0,
        results: [
          {
            messageId: result.messageId || result['message-id'] || '',
            accepted: result.to || emails.map((e) => e.to),
            rejected: result.rejected || [],
          },
        ],
      };
    } catch (error: any) {
      console.error('[Brevo] Error sending batch:', error);
      return {
        successful: 0,
        failed: emails.length,
        results: [],
      };
    }
  }

  async getEmailStatus(messageId: string): Promise<BrevoMessageStatus | null> {
    if (!this.apiKey) {
      return null;
    }

    try {
      const result = await this.makeRequest(`/smtp/emails/${messageId}/details`, 'GET');
      return {
        email: result.email || '',
        messageId,
        status: this.mapBrevoStatus(result.status),
        sentAt: result.date,
        deliveredAt: result.deliveredAt,
        openedAt: result.openedAt,
        clickedAt: result.clickedAt,
      };
    } catch (error) {
      console.error('[Brevo] Error getting email status:', error);
      return null;
    }
  }

  private mapBrevoStatus(status: string): BrevoMessageStatus['status'] {
    const statusMap: Record<string, BrevoMessageStatus['status']> = {
      sent: 'sent',
      delivered: 'delivered',
      opened: 'opened',
      clicked: 'clicked',
      bounced: 'bounced',
      blocked: 'blocked',
    };
    return statusMap[status?.toLowerCase()] || 'sent';
  }
}

