import { supabaseAdmin } from '../config/supabase';

import { createAdminNotification } from '../utils/adminNotifications';



export type GenerationErrorType =

  | 'wrong_clothing_removed'

  | 'wrong_clothing_kept'

  | 'body_distortion'

  | 'color_wrong'

  | 'product_not_applied'

  | 'background_changed'

  | 'other';



export interface CreateFeedbackDto {

  generation_id: string;

  brand_id: string;

  error_type: GenerationErrorType;

  description?: string;

  product_category?: string;

  prompt_used?: string;

}



export interface FeedbackRecord {

  id: string;

  generation_id: string;

  brand_id: string;

  error_type: GenerationErrorType;

  description: string | null;

  product_category: string | null;

  prompt_used: string | null;

  resolved: boolean;

  resolved_at: string | null;

  created_at: string;

}



export interface SimilarFeedback {

  id: string;

  error_type: GenerationErrorType;

  description: string | null;

  product_category: string | null;

  prompt_used: string | null;

  similarity: number;

}



export class FeedbackService {

  /**

   * Crea un registro de feedback para una generación fallida.

   * Dispara el webhook de n8n para generar el embedding de forma asíncrona.

   */

  async createFeedback(data: CreateFeedbackDto): Promise<FeedbackRecord> {

    const { data: record, error } = await supabaseAdmin

      .from('generation_feedback')

      .insert({

        generation_id: data.generation_id,

        brand_id: data.brand_id,

        error_type: data.error_type,

        description: data.description ?? null,

        product_category: data.product_category ?? null,

        prompt_used: data.prompt_used ?? null,

      })

      .select()

      .single();



    if (error || !record) {

      throw new Error('Error al guardar feedback: ' + error?.message);

    }



    // Disparar embedding de forma asíncrona (fire-and-forget)

    this.triggerEmbeddingAsync(record as FeedbackRecord).catch(() => {

      // No bloquear la respuesta si falla el embedding

    });



    // Verificar si se deben notificar errores frecuentes (task 51.9)

    this.checkAndNotifyFrequentErrors(record as FeedbackRecord).catch(() => {});



    return record as FeedbackRecord;

  }



  /**

   * Verifica si hay 3+ feedbacks del mismo tipo en las últimas 24h y notifica al admin.

   * Task 51.9

   */

  private async checkAndNotifyFrequentErrors(feedback: FeedbackRecord): Promise<void> {

    const THRESHOLD = 3;

    const count = await this.countRecentByType(

      feedback.error_type,

      feedback.product_category,

      24

    );



    if (count < THRESHOLD) return;



    // Evitar notificaciones duplicadas: verificar si ya existe una notificación

    // del mismo tipo en las últimas 2 horas

    const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString();

    const { data: existing } = await supabaseAdmin

      .from('admin_notifications')

      .select('id')

      .eq('type', 'high_usage')

      .gte('created_at', twoHoursAgo)

      .ilike('message', `%${feedback.error_type}%${feedback.product_category ?? ''}%`)

      .limit(1);



    if (existing && existing.length > 0) return;



    const categoryLabel = feedback.product_category

      ? ` en categoría '${feedback.product_category}'`

      : '';



    await createAdminNotification({

      type: 'high_usage',

      title: 'Errores frecuentes detectados',

      message: `Alerta: ${count}+ errores de tipo '${feedback.error_type}'${categoryLabel} en las últimas 24h`,

      severity: 'warning',

      metadata: {

        error_type: feedback.error_type,

        product_category: feedback.product_category,

        count,

        triggered_by_feedback_id: feedback.id,

      },

    });

  }



  /**

   * Llama al webhook de n8n para generar el embedding del feedback.

   * Se ejecuta de forma asíncrona — no bloquea la respuesta al cliente.

   */

  private async triggerEmbeddingAsync(feedback: FeedbackRecord): Promise<void> {

    const n8nUrl = process.env.N8N_WEBHOOK_URL?.replace('/tryon', '/feedback-embedding');

    if (!n8nUrl) return;



    const bearerToken = process.env.N8N_BEARER_TOKEN;

    const headers: Record<string, string> = {

      'Content-Type': 'application/json',

    };

    if (bearerToken) {

      headers['Authorization'] = `Bearer ${bearerToken}`;

    }



    await fetch(n8nUrl, {

      method: 'POST',

      headers,

      body: JSON.stringify({

        feedback_id: feedback.id,

        error_type: feedback.error_type,

        description: feedback.description,

        product_category: feedback.product_category,

        prompt_used: feedback.prompt_used,

      }),

      signal: AbortSignal.timeout(5000),

    });

  }



  /**

   * Busca feedbacks similares usando pgvector similarity search.

   * Usado por el servicio RAG para enriquecer prompts.

   */

  async searchSimilarFeedback(

    queryEmbedding: number[],

    threshold = 0.3,

    limit = 5

  ): Promise<SimilarFeedback[]> {

    const { data, error } = await supabaseAdmin.rpc('search_similar_feedback', {

      query_embedding: queryEmbedding,

      similarity_threshold: threshold,

      max_results: limit,

    });



    if (error) {

      console.error('[FeedbackService] Error en similarity search:', error.message);

      return [];

    }



    return (data || []) as SimilarFeedback[];

  }



  /**

   * Obtiene feedbacks sin resolver para el panel admin.

   */

  async getUnresolvedFeedbacks(limit = 50): Promise<FeedbackRecord[]> {

    const { data, error } = await supabaseAdmin

      .from('generation_feedback')

      .select('*')

      .eq('resolved', false)

      .order('created_at', { ascending: false })

      .limit(limit);



    if (error) throw new Error('Error al obtener feedbacks: ' + error.message);

    return (data || []) as FeedbackRecord[];

  }



  /**

   * Obtiene todos los feedbacks con filtros opcionales para el panel admin.

   * Incluye result_image_url de la generación relacionada.

   */

  async getFeedbacks(filters: {
    error_type?: GenerationErrorType;
    brand_id?: string;
    resolved?: boolean;
    limit?: number;
    generation_id?: string;
  } = {}): Promise<(FeedbackRecord & { result_image_url?: string | null })[]> {
    let query = supabaseAdmin
      .from('generation_feedback')
      .select('*, generations(result_image_url)')
      .order('created_at', { ascending: false })
      .limit(filters.limit ?? 100);

    if (filters.error_type) query = query.eq('error_type', filters.error_type);
    if (filters.brand_id) query = query.eq('brand_id', filters.brand_id);
    if (filters.resolved !== undefined) query = query.eq('resolved', filters.resolved);
    if (filters.generation_id) query = query.eq('generation_id', filters.generation_id);

    const { data, error } = await query;
    if (error) throw new Error('Error al obtener feedbacks: ' + error.message);

    // Aplanar el join: generations es un objeto o null
    return (data || []).map((row: any) => ({
      ...row,
      result_image_url: row.generations?.result_image_url ?? null,
      generations: undefined,
    }));
  }

  /**
   * Obtiene feedbacks para una generación específica.
   */
  async getFeedbacksByGenerationId(generationId: string): Promise<(FeedbackRecord & { result_image_url?: string | null })[]> {
    return this.getFeedbacks({ generation_id: generationId });
  }



  /**

   * Marca un feedback como resuelto.

   */

  async resolveFeedback(feedbackId: string, resolvedBy: string): Promise<void> {

    const { error } = await supabaseAdmin

      .from('generation_feedback')

      .update({

        resolved: true,

        resolved_at: new Date().toISOString(),

        resolved_by: resolvedBy,

      })

      .eq('id', feedbackId);



    if (error) throw new Error('Error al resolver feedback: ' + error.message);

  }



  /**

   * Cuenta feedbacks del mismo tipo en las últimas N horas.

   * Usado para detectar errores frecuentes y notificar al admin.

   */

  async countRecentByType(

    errorType: GenerationErrorType,

    productCategory: string | null,

    hoursBack = 24

  ): Promise<number> {

    const since = new Date(Date.now() - hoursBack * 60 * 60 * 1000).toISOString();



    let query = supabaseAdmin

      .from('generation_feedback')

      .select('*', { count: 'exact', head: true })

      .eq('error_type', errorType)

      .gte('created_at', since);



    if (productCategory) {

      query = query.eq('product_category', productCategory);

    }



    const { count, error } = await query;

    if (error) return 0;

    return count ?? 0;

  }



  /**

   * Elimina un feedback del RAG (borra el registro completo).

   */

  async deleteFeedback(feedbackId: string): Promise<void> {

    const { error } = await supabaseAdmin

      .from('generation_feedback')

      .delete()

      .eq('id', feedbackId);



    if (error) throw new Error('Error al eliminar feedback: ' + error.message);

  }



  /**

   * Estadísticas agrupadas por tipo de error para el panel admin.

   */

  async getErrorStats(): Promise<{ error_type: string; product_category: string | null; count: number }[]> {

    const { data, error } = await supabaseAdmin

      .from('generation_feedback')

      .select('error_type, product_category')

      .eq('resolved', false);



    if (error || !data) return [];



    // Agrupar en memoria

    const groups: Record<string, number> = {};

    for (const row of data) {

      const key = `${row.error_type}||${row.product_category ?? ''}`;

      groups[key] = (groups[key] ?? 0) + 1;

    }



    return Object.entries(groups)

      .map(([key, count]) => {

        const [error_type, product_category] = key.split('||');

        return { error_type, product_category: product_category || null, count };

      })

      .sort((a, b) => b.count - a.count);

  }

}

import { redis } from '../config/redis';
import { supabaseAdmin } from '../config/supabase';

export interface ConcurrencyLimit {
  maxConcurrent: number;
  queueTimeoutMs: number;
}

const PLAN_LIMITS: Record<string, ConcurrencyLimit> = {
  BASIC: { maxConcurrent: 2, queueTimeoutMs: 30000 },
  PRO: { maxConcurrent: 5, queueTimeoutMs: 30000 },
  ENTERPRISE: { maxConcurrent: 20, queueTimeoutMs: 30000 },
  TRIAL: { maxConcurrent: 1, queueTimeoutMs: 30000 },
  DEFAULT: { maxConcurrent: 1, queueTimeoutMs: 30000 },
};

const SLOT_TTL_SECONDS = 120;

export interface GenerationSlot {
  acquired: boolean;
  slotId: string | null;
  waitTimeMs: number;
}

export class GenerationConcurrencyService {
  private getKey(brandId: string): string {
    return `generation:concurrency:${brandId}`;
  }

  private getSlotKey(brandId: string, slotId: string): string {
    return `generation:slot:${brandId}:${slotId}`;
  }

  private getPlanLimit(plan: string): ConcurrencyLimit {
    return PLAN_LIMITS[plan.toUpperCase()] || PLAN_LIMITS.DEFAULT;
  }

  private async countActiveSlots(brandId: string): Promise<number> {
    if (!redis.status || redis.status === 'wait') return 0;
    try {
      const key = this.getKey(brandId);
      const current = await redis.get(key);
      return parseInt(current || '0', 10);
    } catch {
      return 0;
    }
  }

  /**
   * Atomically try to acquire a slot using Lua script.
   * Returns the new count if successful, or -1 if at capacity.
   */
  async acquireSlot(brandId: string, plan: string): Promise<GenerationSlot> {
    if (!redis.status || redis.status === 'wait') {
      return { acquired: true, slotId: null, waitTimeMs: 0 };
    }

    const limit = this.getPlanLimit(plan);
    const key = this.getKey(brandId);

    const luaScript = `
      local current = tonumber(redis.call('GET', KEYS[1]) or '0')
      local maxConcurrent = tonumber(ARGV[1])
      local ttl = tonumber(ARGV[2])
      if current < maxConcurrent then
        redis.call('INCR', KEYS[1])
        redis.call('EXPIRE', KEYS[1], ttl)
        return current + 1
      else
        return -1
      end
    `;

    try {
      const result = await redis.eval(
        luaScript, 1, key,
        limit.maxConcurrent.toString(),
        SLOT_TTL_SECONDS.toString()
      ) as number;

      if (result === -1) {
        return { acquired: false, slotId: null, waitTimeMs: limit.queueTimeoutMs };
      }

      const slotId = `${brandId}-${Date.now()}-${Math.random().toString(36).slice(2)}`;
      await redis.setex(this.getSlotKey(brandId, slotId), SLOT_TTL_SECONDS, '1');

      return { acquired: true, slotId, waitTimeMs: 0 };
    } catch (err) {
      console.error('[Concurrency] acquireSlot error:', err);
      return { acquired: true, slotId: null, waitTimeMs: 0 };
    }
  }

  async releaseSlot(brandId: string, slotId: string | null): Promise<void> {
    if (!slotId || !redis.status || redis.status === 'wait') return;
    try {
      const key = this.getKey(brandId);
      const slotKey = this.getSlotKey(brandId, slotId);

      const luaScript = `
        redis.call('DECR', KEYS[1])
        redis.call('DEL', KEYS[2])
        local val = tonumber(redis.call('GET', KEYS[1]) or '0')
        if val <= 0 then redis.call('DEL', KEYS[1]) end
        return val
      `;

      await redis.eval(luaScript, 2, key, slotKey);
    } catch (err) {
      console.error('[Concurrency] releaseSlot error:', err);
    }
  }

  async getActiveCount(brandId: string): Promise<number> {
    return this.countActiveSlots(brandId);
  }

  async getSlotInfo(brandId: string, plan: string): Promise<{
    active: number;
    max: number;
    available: number;
    queueTimeoutMs: number;
  }> {
    const limit = this.getPlanLimit(plan);
    const active = await this.countActiveSlots(brandId);

    return {
      active,
      max: limit.maxConcurrent,
      available: Math.max(0, limit.maxConcurrent - active),
      queueTimeoutMs: limit.queueTimeoutMs,
    };
  }

  /**
   * Get global count of active generation slots across all brands.
   * Uses SCAN (safer than KEYS in production, never blocks).
   * Falls back to 0 if Redis is unavailable.
   */
  async getGlobalActiveCount(): Promise<number> {
    if (!redis.status || redis.status === 'wait') {
      // Fallback: contar generaciones recientes desde Supabase (últimos 2 min)
      const cutoff = new Date(Date.now() - 2 * 60 * 1000).toISOString();
      const { count } = await supabaseAdmin
        .from('generations')
        .select('id', { count: 'exact', head: true })
        .in('status', ['PENDING'])
        .gte('generated_at', cutoff);
      return count || 0;
    }

    try {
      let cursor = '0';
      let total = 0;
      const pattern = 'generation:concurrency:*';

      do {
        const [nextCursor, keys] = await redis.scan(
          cursor, 'MATCH', pattern, 'COUNT', 100
        );
        cursor = nextCursor;

        if (keys.length > 0) {
          const pipeline = redis.pipeline();
          keys.forEach(key => pipeline.get(key));
          const results = await Promise.race([
            pipeline.exec(),
            new Promise<null>((_, reject) => setTimeout(() => reject(new Error('timeout')), 2000)),
          ]) as any[][];
          if (results) {
            total += (results || []).reduce((sum, [err, val]) => {
              if (err || !val) return sum;
              return sum + parseInt(String(val), 10);
            }, 0);
          }
        }
      } while (cursor !== '0');

      return total;
    } catch {
      return 0;
    }
  }

  /**
   * Get all brands with active generation slots, including brand name and last activity.
   * Uses SCAN (never blocks). Falls back to empty array if Redis unavailable.
   */
  async getBrandsWithActiveGenerations(): Promise<Array<{
    brandId: string;
    brandName: string;
    active: number;
    max: number;
    lastActivity: string | null;
  }>> {
    if (!redis.status || redis.status === 'wait') {
      // Fallback: usar Supabase para contar generaciones activas (últimos 2 min)
      const cutoff = new Date(Date.now() - 2 * 60 * 1000).toISOString();
      const { data: recentGens } = await supabaseAdmin
        .from('generations')
        .select('brand_id, generated_at, brands(name)')
        .in('status', ['PENDING'])
        .gte('generated_at', cutoff)
        .order('generated_at', { ascending: false });

      if (!recentGens || recentGens.length === 0) return [];

      const brandMap: Record<string, { name: string; latest: string | null }> = {};
      for (const g of recentGens) {
        if (!brandMap[g.brand_id]) {
          brandMap[g.brand_id] = {
            name: (g as any).brands?.name || 'Marca',
            latest: g.generated_at,
          };
        }
      }

      return Object.entries(brandMap).map(([brandId, info]) => ({
        brandId,
        brandName: info.name,
        active: recentGens.filter(g => g.brand_id === brandId).length,
        max: PLAN_LIMITS.DEFAULT.maxConcurrent,
        lastActivity: info.latest,
      })).sort((a, b) => b.active - a.active).slice(0, 20);
    }

    try {
      let cursor = '0';
      const keys: string[] = [];
      const pattern = 'generation:concurrency:*';

      // Collect all matching keys via SCAN
      do {
        const [nextCursor, batch] = await Promise.race([
          redis.scan(cursor, 'MATCH', pattern, 'COUNT', 100),
          new Promise<['0', string[]]>((_, reject) => setTimeout(() => reject(new Error('scan timeout')), 3000)),
        ]) as [string, string[]];
        cursor = nextCursor;
        keys.push(...batch);
      } while (cursor !== '0');

      if (keys.length === 0) return [];

      // Extract brand IDs from keys
      const brandIds = keys.map(key => {
        const parts = key.split(':');
        return parts[parts.length - 1];
      }).filter(Boolean);

      // Get brand names from Supabase
      const { data: brands } = await supabaseAdmin
        .from('brands')
        .select('id, name')
        .in('id', brandIds.slice(0, 50));

      // Get active counts via pipeline
      const pipeline = redis.pipeline();
      keys.forEach(key => pipeline.get(key));
      const countResults = await Promise.race([
        pipeline.exec(),
        new Promise<null>((_, reject) => setTimeout(() => reject(new Error('pipeline timeout')), 2000)),
      ]) as any[][];

      // Get last generation timestamps per brand (from recent generations)
      const recentCutoff = new Date(Date.now() - 30 * 60 * 1000).toISOString();
      const { data: recentGens } = await supabaseAdmin
        .from('generations')
        .select('brand_id, generated_at')
        .in('brand_id', brandIds.slice(0, 50))
        .gte('generated_at', recentCutoff)
        .order('generated_at', { ascending: false });

      const brandNameMap: Record<string, string> = {};
      if (brands) brands.forEach((b: any) => { brandNameMap[b.id] = b.name; });

      const lastGenMap: Record<string, string> = {};
      if (recentGens) {
        recentGens.forEach((g: any) => {
          if (!lastGenMap[g.brand_id]) lastGenMap[g.brand_id] = g.generated_at;
        });
      }

      const result: Array<{
        brandId: string;
        brandName: string;
        active: number;
        max: number;
        lastActivity: string | null;
      }> = [];

      for (let i = 0; i < keys.length; i++) {
        const brandId = brandIds[i];
        const countArr = countResults?.[i];
        const active = countArr && !countArr[0] ? parseInt(String(countArr[1] || '0'), 10) : 0;

        result.push({
          brandId,
          brandName: brandNameMap[brandId] || 'Marca desconocida',
          active,
          max: PLAN_LIMITS.DEFAULT.maxConcurrent,
          lastActivity: lastGenMap[brandId] || null,
        });
      }

      return result.sort((a, b) => b.active - a.active).slice(0, 20);
    } catch (err) {
      console.error('[Concurrency] getBrandsWithActiveGenerations error:', err);
      return [];
    }
  }

  /**
   * Get activity history for the last N hours.
   * Reads from a Redis sorted set keyed by hour buckets.
   * Falls back to empty array if Redis unavailable.
   */
  async getActivityHistory(hours: number): Promise<Array<{ hour: string; count: number }>> {
    if (!redis.status || redis.status === 'wait') return [];

    const history: Array<{ hour: string; count: number }> = [];
    try {
      for (let i = hours - 1; i >= 0; i--) {
        const d = new Date();
        d.setHours(d.getHours() - i, 0, 0, 0);
        const key = `generation:history:${d.toISOString().slice(0, 13)}`;
        const count = await redis.get(key);
        history.push({ hour: d.toISOString().slice(0, 13), count: parseInt(count || '0', 10) });
      }
      return history;
    } catch {
      return [];
    }
  }
}

