import { Generation } from '../types';



export interface CreateGenerationDto {
  brand_id: string;
  product_id: string;
  selfie_url: string;
  input_fingerprint?: string | null;
  client_fingerprint?: string | null;
  status: 'PENDING' | 'SUCCESS' | 'FAILED';
}


export interface UpdateGenerationDto {
  status?: 'PENDING' | 'SUCCESS' | 'FAILED';
  result_image_url?: string;
  selfie_url?: string;
  input_fingerprint?: string | null;
  error_message?: string;
  processing_time?: number;
  prompt_used?: string;
  engine_used?: 'vertex' | 'n8n';
}


export class GenerationsService {
  async createGeneration(data: CreateGenerationDto): Promise<Generation> {
    let query = supabaseAdmin
      .from('generations')
      .insert({
        brand_id: data.brand_id,
        product_id: data.product_id,
        selfie_url: data.selfie_url,
        input_fingerprint: data.input_fingerprint ?? null,
        client_fingerprint: data.client_fingerprint ?? null,
        status: data.status,
        generated_at: new Date().toISOString()
      })
      .select()
      .single();

    let { data: generation, error } = await query;

    if (error?.message?.includes('input_fingerprint')) {
      const fallback = await supabaseAdmin
        .from('generations')
        .insert({
          brand_id: data.brand_id,
          product_id: data.product_id,
          selfie_url: data.selfie_url,
          client_fingerprint: data.client_fingerprint ?? null,
          status: data.status,
          generated_at: new Date().toISOString()
        })
        .select()
        .single();

      generation = fallback.data;
      error = fallback.error;
    }

    if (error || !generation) {
      throw new Error('Error al crear registro de generación: ' + error?.message);
    }


    return generation as Generation;

  }



  async updateGeneration(generationId: string, updates: UpdateGenerationDto): Promise<Generation> {

    const { data, error } = await supabaseAdmin

      .from('generations')

      .update(updates)

      .eq('id', generationId)

      .select()

      .single();



    if (error || !data) {

      throw new Error('Error al actualizar generación: ' + error?.message);

    }



    return data as Generation;

  }



  async getGenerationById(generationId: string): Promise<Generation | null> {

    const { data, error } = await supabaseAdmin

      .from('generations')

      .select('*')

      .eq('id', generationId)

      .single();



    if (error || !data) return null;

    return data as Generation;

  }



  async getGenerationsByBrand(brandId: string, limit = 50, status?: string): Promise<(Generation & { has_feedback: boolean; feedback_types: string[]; feedback_count: number })[]> {
    let query = supabaseAdmin
      .from('generations')
      .select(`
        *,
        generation_feedback (
          id,
          error_type
        )
      `)
      .eq('brand_id', brandId);

    if (status) {
      query = query.eq('status', status);
    }

    const { data, error } = await query
      .order('generated_at', { ascending: false })
      .limit(limit);

    if (error) throw new Error('Error al obtener generaciones: ' + error.message);

    // Process feedback data to compute aggregated fields
    const result = (data || []).map((g: any) => {
      const feedbackList = g.generation_feedback || [];
      const uniqueErrorTypes = [...new Set(feedbackList
        .map((f: any) => f.error_type)
        .filter((t: string | null) => t !== null)
      )];

      return {
        ...g,
        has_feedback: feedbackList.length > 0,
        feedback_types: uniqueErrorTypes,
        feedback_count: feedbackList.length,
      };
    });

    return result;
  }

  async getSuccessfulGenerationByFingerprint(
    brandId: string,
    productId: string,
    inputFingerprint: string
  ): Promise<Generation | null> {
    const { data, error } = await supabaseAdmin
      .from('generations')
      .select('*')
      .eq('brand_id', brandId)
      .eq('product_id', productId)
      .eq('input_fingerprint', inputFingerprint)
      .eq('status', 'SUCCESS')
      .not('result_image_url', 'is', null)
      .order('generated_at', { ascending: false })
      .limit(1)
      .maybeSingle();

    if (error?.message?.includes('input_fingerprint')) {
      return null;
    }

    if (error || !data) return null;
    return data as Generation;
  }


  async deleteGeneration(generationId: string, brandId: string): Promise<void> {

    const { error } = await supabaseAdmin

      .from('generations')

      .delete()

      .eq('id', generationId)

      .eq('brand_id', brandId);



    if (error) throw new Error('Error al eliminar generación: ' + error.message);

  }



  async deleteGenerations(generationIds: string[], brandId: string): Promise<number> {

    const { data, error } = await supabaseAdmin

      .from('generations')

      .delete()

      .in('id', generationIds)

      .eq('brand_id', brandId)

      .select('id');



    if (error) throw new Error('Error al eliminar generaciones: ' + error.message);

    return data?.length ?? 0;

  }



  async countSuccessfulGenerationsThisMonth(brandId: string): Promise<number> {

    const currentMonth = this.getCurrentMonthRange();



    const { count, error } = await supabaseAdmin

      .from('generations')

      .select('*', { count: 'exact', head: true })

      .eq('brand_id', brandId)

      .eq('status', 'SUCCESS')

      .gte('generated_at', currentMonth.start.toISOString())

      .lte('generated_at', currentMonth.end.toISOString());



    if (error) throw new Error('Error al contar generaciones: ' + error.message);

    return count || 0;

  }



  private getCurrentMonthRange() {

    const now = new Date();

    const start = new Date(now.getFullYear(), now.getMonth(), 1);

    const end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);

    return { start, end };

  }


  /**
   * T-5: Purga im\u00e1genes generadas con m\u00e1s de 48h (Art. 10-B t\u00e9rminos)
   * Elimina de GCS + marca result_image_url como '[EXPIRADO]'
   */
  async purgeExpiredResultImages(limit = 100): Promise<number> {
    const cutoff = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();

    // Marca personal de Sam — nunca purgar sus generaciones (excepción manual)
    const EXEMPT_BRAND_ID = 'cf95f272-8de9-45e2-9290-d026312f2c31';
    const { data: expired, error } = await supabaseAdmin
      .from('generations')
      .select('id, result_image_url, brand_id')
      .eq('status', 'SUCCESS')
      .not('result_image_url', 'is', null)
      .not('result_image_url', 'like', '[%')
      .is('result_image_deleted_at', null)
      .lt('generated_at', cutoff)
      .neq('brand_id', EXEMPT_BRAND_ID)
      .limit(limit);

    if (error || !expired?.length) return 0;

    let purged = 0;

    for (const gen of expired) {
      try {
        const path = this._extractPathFromUrl(gen.result_image_url);
        if (path) {
          const { uploadService } = await import('./upload.service');
          await uploadService.deleteFromGCS(path);
        }
      } catch (err) {
        console.warn(`[purgeExpiredResultImages] No se pudo eliminar GCS para ${gen.id}:`, err);
      }

      const { error: updateError } = await supabaseAdmin
        .from('generations')
        .update({
          result_image_url: '[EXPIRADO]',
          result_image_deleted_at: new Date().toISOString(),
        })
        .eq('id', gen.id);

      if (!updateError) purged++;
    }

    return purged;
  }

  private _extractPathFromUrl(url: string): string | null {
    try {
      const u = new URL(url);
      const hostname = u.hostname;
      let path = u.pathname;

      if (hostname.includes('storage.googleapis.com')) {
        path = path.replace(/^\//, '');
        const segs = path.split('/');
        if (segs.length > 1) segs.shift();
        return segs.join('/');
      }

      const segs = path.split('/').filter(Boolean);
      if (segs.length > 1) segs.shift();
      return segs.join('/') || null;
    } catch {
      return null;
    }
  }
}

import { supabaseAdmin } from '../config/supabase';
import { GOOGLE_CONFIG } from '../config/google';
import { generateToken } from '../utils/jwt';

export interface GoogleTokenPayload {
  sub: string;
  email: string;
  email_verified: boolean;
  name: string;
  picture?: string;
  given_name?: string;
  family_name?: string;
}

export interface GoogleAuthResult {
  token: string | null;
  brand: any;
  needsOnboarding: boolean;
  isNewBrand: boolean;
  accountLinked: boolean;
  pendingRegistrationId?: string;
  redirectTo?: string;
}

/**
 * Verifica un access token de Google consultando userinfo desde el backend.
 * Evita confiar en email/googleId enviados por el cliente.
 */
export async function verifyGoogleAccessToken(accessToken: string): Promise<GoogleTokenPayload> {
  const response = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', {
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
  });

  if (!response.ok) {
    const errorText = await response.text().catch(() => 'unknown');
    console.error('[GoogleAuth] Error verifying access token:', response.status, response.statusText, errorText);
    throw new Error('GOOGLE_ACCESS_TOKEN_INVALID');
  }

  const data = await response.json() as Record<string, any>;

  if (!data.sub || !data.email) {
    throw new Error('GOOGLE_NO_EMAIL');
  }

  return {
    sub: data.sub,
    email: String(data.email).toLowerCase(),
    email_verified: data.email_verified === true || data.email_verified === 'true',
    name: data.name || String(data.email).split('@')[0],
    picture: data.picture,
    given_name: data.given_name,
    family_name: data.family_name,
  };
}

/**
 * Verifica el JWT de Google con la API de Google
 */
export async function verifyGoogleToken(token: string): Promise<GoogleTokenPayload> {
  const response = await fetch(
    `${GOOGLE_CONFIG.tokenInfoUrl}?id_token=${encodeURIComponent(token)}`
  );

  if (!response.ok) {
    throw new Error('GOOGLE_TOKEN_INVALID');
  }

  const data = await response.json() as Record<string, any>;

  if (data.aud !== GOOGLE_CONFIG.clientId) {
    throw new Error('GOOGLE_AUDIENCE_MISMATCH');
  }

  if (!data.email) {
    throw new Error('GOOGLE_NO_EMAIL');
  }

  return {
    sub: data.sub,
    email: data.email,
    email_verified: data.email_verified === true || data.email_verified === 'true',
    name: data.name || data.email.split('@')[0],
    picture: data.picture,
    given_name: data.given_name,
    family_name: data.family_name,
  };
}

async function getActiveCampaign() {
  const now = new Date().toISOString();
  const { data } = await supabaseAdmin
    .from('trial_campaigns')
    .select('id, trial_days, trial_generations_limit, price_cop, require_card_verification')
    .eq('active', true)
    .or(`ends_at.is.null,ends_at.gt.${now}`)
    .order('created_at', { ascending: false })
    .limit(1)
    .single();
  return data as { id: string; trial_days: number; trial_generations_limit: number; price_cop: number; require_card_verification: boolean } | null;
}

/**
 * Busca o crea una marca a partir de datos de Google
 * - Si existe por google_id â login directo
 * - Si existe por email â vincula google_id y login
 * - Si no existe â crea marca con needs_onboarding=true
 */
export async function findOrCreateBrandFromGoogle(
  payload: GoogleTokenPayload
): Promise<GoogleAuthResult> {
  // 0. Bloquear dominios de email desechables
  const disposableDomains = ['mailinator.com','guerrillamail.com','tempmail.com','throwam.com','yopmail.com','sharklasers.com','grr.la','guerrillamail.info','spam4.me','trashmail.com','trashmail.me','dispostable.com','fakeinbox.com','maildrop.cc','mailnull.com','spamgourmet.com','tempr.email','discard.email','10minutemail.com','minutemail.com','throwaway.email','getairmail.com','filzmail.com','spamgourmet.net','spamgourmet.org'];
  const emailDomain = payload.email.split('@')[1]?.toLowerCase();
  if (emailDomain && disposableDomains.includes(emailDomain)) {
    throw new Error('DISPOSABLE_EMAIL');
  }

  // 1. Buscar por google_id primero
  const { data: brandByGoogleId } = await supabaseAdmin
    .from('brands')
    .select('*')
    .eq('google_id', payload.sub)
    .maybeSingle();

  if (brandByGoogleId) {
    const token = generateToken({ brandId: brandByGoogleId.id, email: brandByGoogleId.email });
    return {
      token,
      brand: brandByGoogleId,
      needsOnboarding: false,
      isNewBrand: false,
      accountLinked: false,
    };
  }

  // 2. Buscar por email (vinculación automática)
  const { data: brandByEmail } = await supabaseAdmin
    .from('brands')
    .select('*')
    .eq('email', payload.email.toLowerCase())
    .maybeSingle();

  if (brandByEmail) {
    // Vincular google_id si no lo tiene
    if (!brandByEmail.google_id) {
      await supabaseAdmin
        .from('brands')
        .update({
          google_id: payload.sub,
          auth_provider: 'google',
        })
        .eq('id', brandByEmail.id);
    }

    const token = generateToken({ brandId: brandByEmail.id, email: brandByEmail.email });
    return {
      token,
      brand: brandByEmail,
      needsOnboarding: false,
      isNewBrand: false,
      accountLinked: true,
    };
  }

  // 3. Usuario nuevo â Crear registro pendiente en pending_registrations (NO crear marca aún)
  // Esto evita "marcas fantasma" si el usuario abandona antes de pagar
  const contactName = [payload.given_name, payload.family_name]
    .filter(Boolean)
    .join(' ') || payload.name;

  const pendingRef = `G-${payload.sub.substring(0, 8)}-${Date.now()}`;

  const { data: pendingReg, error: pendingError } = await supabaseAdmin
    .from('pending_registrations')
    .insert({
      email: payload.email.toLowerCase(),
      reference: pendingRef,
      plan: 'TRIAL', // Plan por defecto, se puede cambiar en checkout
      months: 1,
      amount: 0,
      includes_landing: false,
      status: 'initiated',
      brand_name: contactName,
    })
    .select()
    .single();

  if (pendingError) {
    console.error('[GoogleAuth] Error creando registro pendiente:', pendingError);
    throw new Error('GOOGLE_PENDING_REG_FAILED');
  }

  // Devolver pendingRegistrationId para que el frontend rediriga al checkout
  return {
    token: null, // Sin token - el usuario debe completar el checkout primero
    brand: {
      id: pendingReg.id,
      email: payload.email.toLowerCase(),
      name: contactName,
    },
    needsOnboarding: true,
    isNewBrand: true,
    accountLinked: false,
    pendingRegistrationId: pendingReg.id,
    redirectTo: '/trial-checkout', // NUEVO: usuario nuevo va al flujo trial
  };
}

/**
 * Endpoint principal: recibe credential de Google, verifica y retorna sesión
 */
export async function loginWithGoogle(googleCredential: string): Promise<GoogleAuthResult> {
  if (!GOOGLE_CONFIG.clientId) {
    throw new Error('GOOGLE_NOT_CONFIGURED');
  }

  const payload = await verifyGoogleToken(googleCredential);
  return findOrCreateBrandFromGoogle(payload);
}

import sharp from 'sharp';
import axios from 'axios';
import https from 'https';
import crypto from 'crypto';
import { UploadService } from './upload.service';

/**
 * Downloads an image from a URL and compresses it using sharp.
 * @param url URL of the image (must be publicly accessible)
 * @param maxPx Maximum pixels on longest side (default: 1024)
 * @returns Buffer of the compressed image in JPEG quality 85
 */
export async function compressImageFromUrl(url: string, maxPx: number = 1024): Promise<{ buffer: Buffer; originalSize: number; compressedSize: number }> {
  let finalUrl = url;
  try {
    const parsed = new URL(finalUrl);
    if (parsed.pathname.includes('/img-proxy')) {
      const originalUrl = parsed.searchParams.get('url');
      if (originalUrl) {
        finalUrl = originalUrl;
      }
    }
  } catch {}

  console.log(`[ImageCompression] Descargando imagen para comprimir: ${finalUrl}`);

  const isInternalService = finalUrl.includes('wilkiedevs.com') || finalUrl.includes('minio.wilkiedevs.com');
  const httpsAgent = isInternalService ? new https.Agent({ rejectUnauthorized: false }) : undefined;

  const response = await axios.get(finalUrl, {
    responseType: 'arraybuffer',
    timeout: 30000,
    httpsAgent,
  });

  const originalBuffer = Buffer.from(response.data);
  const originalSize = originalBuffer.length;

  console.log(`[ImageCompression] Imagen descargada: ${originalSize} bytes, procesando con sharp...`);

  const compressedBuffer = await sharp(originalBuffer)
    .resize(maxPx, maxPx, {
      withoutEnlargement: true,
      fit: 'inside',
    })
    .jpeg({ quality: 85 })
    .toBuffer();

  const compressedSize = compressedBuffer.length;

  console.log(`[ImageCompression] Compresión completa: ${originalSize} bytes → ${compressedSize} bytes (${Math.round((1 - compressedSize / originalSize) * 100)}% reducción)`);

  return { buffer: compressedBuffer, originalSize, compressedSize };
}

/**
 * Sube una imagen comprimida a MinIO en la carpeta temp/ y retorna la URL pública.
 * @param buffer Buffer de la imagen comprimida
 * @param originalUrl URL original para derivar el nombre
 * @returns URL pública del archivo subido
 */
export async function uploadCompressedToMinio(buffer: Buffer, originalUrl: string): Promise<string> {
  const timestamp = Date.now();
  const random = crypto.randomBytes(4).toString('hex');
  const filename = `temp/compressed-${timestamp}-${random}.jpg`;

  // Upload using the existing UploadService
  const uploadService = new UploadService();
  const result = await uploadService.uploadImageBuffer({
    buffer,
    filename,
    temporary: true,
  });

  console.log(`[ImageCompression] Imagen comprimida subida a: ${result.url}`);
  return result.url;
}

/**
 * Comprime y sube una imagen, retornando la URL de la versión comprimida.
 * Si la compresión falla, retorna la URL original.
 * @param url URL original de la imagen
 * @param maxPx Máximo de píxeles (default: 1024)
 * @returns URL de la imagen comprimida (o original si falló)
 */
export async function compressAndUpload(url: string, maxPx: number = 1024): Promise<{ compressedUrl: string; originalUrl: string; success: boolean; sizeBefore?: number; sizeAfter?: number }> {
  let unproxiedUrl = url;
  try {
    const parsed = new URL(url);
    if (parsed.pathname.includes('/img-proxy')) {
      const origUrl = parsed.searchParams.get('url');
      if (origUrl) unproxiedUrl = origUrl;
    }
  } catch {}

  try {
    const { buffer, originalSize, compressedSize } = await compressImageFromUrl(unproxiedUrl, maxPx);
    const compressedUrl = await uploadCompressedToMinio(buffer, unproxiedUrl);
    return {
      compressedUrl,
      originalUrl: unproxiedUrl,
      success: true,
      sizeBefore: originalSize,
      sizeAfter: compressedSize,
    };
  } catch (error: any) {
    console.error(`[ImageCompression] Error comprimiendo imagen ${unproxiedUrl}:`, error.message);
    return {
      compressedUrl: unproxiedUrl,
      originalUrl: unproxiedUrl,
      success: false,
    };
  }
}

/**
 * Comprime ambas imágenes (selfie y producto) en paralelo y retorna las URLs comprimidas.
 * Si alguna compresión falla, usa la URL original como fallback.
 */
export async function compressImagesForN8N(
  selfieUrl: string,
  productImageUrl: string,
  maxPx: number = 1024
): Promise<{ selfie_url: string; product_image_url: string; compressionStats: CompressionStats }> {
  console.log('[ImageCompression] Iniciando compresión de imágenes para n8n...');
  console.log(`[ImageCompression] Selfie: ${selfieUrl}`);
  console.log(`[ImageCompression] Producto: ${productImageUrl}`);

  const results = await Promise.allSettled([
    compressAndUpload(selfieUrl, maxPx),
    compressAndUpload(productImageUrl, maxPx),
  ]);

  const selfieResult = results[0].status === 'fulfilled' ? results[0].value : { compressedUrl: selfieUrl, success: false };
  const productResult = results[1].status === 'fulfilled' ? results[1].value : { compressedUrl: productImageUrl, success: false };

  const compressionStats: CompressionStats = {
    selfie: {
      success: selfieResult.success,
      originalSize: (selfieResult as any).sizeBefore,
      compressedSize: (selfieResult as any).sizeAfter,
    },
    product: {
      success: productResult.success,
      originalSize: (productResult as any).sizeBefore,
      compressedSize: (productResult as any).sizeAfter,
    },
  };

  if (selfieResult.success) {
    console.log(`[ImageCompression] Selfie comprimida: ${compressionStats.selfie.originalSize} → ${compressionStats.selfie.compressedSize} bytes`);
  } else {
    console.warn(`[ImageCompression] Selfie no se pudo comprimir, usando original`);
  }

  if (productResult.success) {
    console.log(`[ImageCompression] Producto comprimido: ${compressionStats.product.originalSize} → ${compressionStats.product.compressedSize} bytes`);
  } else {
    console.warn(`[ImageCompression] Producto no se pudo comprimir, usando original`);
  }

  return {
    selfie_url: selfieResult.compressedUrl,
    product_image_url: productResult.compressedUrl,
    compressionStats,
  };
}

export interface CompressionStats {
  selfie: {
    success: boolean;
    originalSize?: number;
    compressedSize?: number;
  };
  product: {
    success: boolean;
    originalSize?: number;
    compressedSize?: number;
  };
}

import sharp from 'sharp';
import axios from 'axios';
import path from 'path';
import fs from 'fs';

export class ImageService {
  private readonly assetsPath = path.join(process.cwd(), 'assets');
  private readonly watermarkBasic = path.join(this.assetsPath, 'watermark-basic.webp');
  private readonly watermarkTrial = path.join(this.assetsPath, 'watermark-trial.webp');

  /**
   * Procesa una imagen aplicando una marca de agua según el plan.
   * @param imageUrl URL de la imagen original en MinIO
   * @param plan Plan de la marca (BASIC, TRIAL, PRO)
   * @returns Buffer de la imagen procesada
   */
  async processWithWatermark(imageUrl: string, plan: string): Promise<Buffer> {
    try {
      // 1. Descargar la imagen
      const response = await axios.get(imageUrl, { responseType: 'arraybuffer', timeout: 8000 });
      const imageBuffer = Buffer.from(response.data);

      // Si es PRO, no aplicamos marca de agua (solo optimizamos un poco)
      if (plan === 'PRO') {
        return await sharp(imageBuffer)
          .jpeg({ quality: 90 })
          .toBuffer();
      }

      // 2. Obtener dimensiones de la imagen original
      const metadata = await sharp(imageBuffer).metadata();
      const { width, height } = metadata;

      if (!width || !height) {
        throw new Error('No se pudieron obtener las dimensiones de la imagen');
      }

      // 3. Seleccionar marca de agua
      let watermarkPath = plan === 'BASIC' ? this.watermarkBasic : this.watermarkTrial;
      
      // Verificar que el archivo existe
      if (!fs.existsSync(watermarkPath)) {
        console.warn(`[ImageService] Marca de agua no encontrada en ${watermarkPath}, devolviendo imagen limpia`);
        return imageBuffer;
      }

      const watermarkBuffer = fs.readFileSync(watermarkPath);

      // 4. Calcular dimensiones y posición de la marca de agua
      if (plan === 'BASIC') {
        // BASIC: Marca de agua pequeña en la esquina inferior derecha
        const wmWidth = Math.round(width * 0.10); // 10% del ancho es suficiente y elegante
        const padding = 20; // Padding de 20px para evitar que se corte

        const wmMetadata = await sharp(watermarkBuffer).metadata();
        const wmHeight = Math.round((wmMetadata.height! / wmMetadata.width!) * wmWidth);

        const resizedWatermark = await sharp(watermarkBuffer)
          .resize({ width: wmWidth })
          .toBuffer();

        return await sharp(imageBuffer)
          .composite([
            {
              input: resizedWatermark,
              top: height - wmHeight - padding,
              left: width - wmWidth - padding,
              blend: 'over'
            }
          ])
          .jpeg({ quality: 85 })
          .toBuffer();
      } else {
        // TRIAL: Marca de agua central más grande con opacidad (el archivo ya debe tenerla o se puede ajustar)
        const wmWidth = Math.round(width * 0.45);
        
        const resizedWatermark = await sharp(watermarkBuffer)
          .resize({ width: wmWidth })
          .toBuffer();

        return await sharp(imageBuffer)
          .composite([
            {
              input: resizedWatermark,
              gravity: 'center',
              blend: 'over'
            }
          ])
          .jpeg({ quality: 85 })
          .toBuffer();
      }
    } catch (error: any) {
      console.error('[ImageService] Error procesando imagen:', error.message);
      throw error;
    }
  }

  /**
   * Refina el posicionamiento usando gravity nativo de Sharp para mayor simplicidad
   */
  async applyWatermarkSimple(imageUrl: string, plan: string): Promise<Buffer> {
    const response = await axios.get(imageUrl, { responseType: 'arraybuffer' });
    const imageBuffer = Buffer.from(response.data);

    if (plan !== 'BASIC' && plan !== 'TRIAL') return imageBuffer;

    const metadata = await sharp(imageBuffer).metadata();
    const watermarkPath = plan === 'BASIC' ? this.watermarkBasic : this.watermarkTrial;
    
    if (!fs.existsSync(watermarkPath)) return imageBuffer;

    const wmWidth = plan === 'BASIC' ? Math.round(metadata.width! * 0.15) : Math.round(metadata.width! * 0.45);
    const resizedWm = await sharp(watermarkPath).resize(wmWidth).toBuffer();

    return await sharp(imageBuffer)
      .composite([{
        input: resizedWm,
        gravity: plan === 'BASIC' ? 'southeast' : 'center',
      }])
      .jpeg({ quality: 90 })
      .toBuffer();
  }
}

/**
 * KnowledgeEmbeddingService
 *
 * Genera y actualiza embeddings para los items del knowledge base de Rebecca.
 * Usa text-embedding-004 vía Vertex AI (768 dimensiones).
 */

import { GoogleGenAI } from '@google/genai';
import { supabaseAdmin } from '../config/supabase';

const TABLE = 'lookitry_knowledge';

function getAI(): GoogleGenAI {
  return new GoogleGenAI({
    vertexai: true,
    project: process.env.VERTEX_PROJECT_ID || 'gen-lang-client-0591001769',
    location: 'us-central1',
  });
}

async function generateEmbedding(text: string, taskType: 'RETRIEVAL_DOCUMENT' | 'RETRIEVAL_QUERY' = 'RETRIEVAL_DOCUMENT'): Promise<number[] | null> {
  try {
    const ai = getAI();
    const result = await (ai.models as any).embedContent({
      model: 'text-embedding-004',
      contents: [{ parts: [{ text }] }],
      taskType,
    });
    return result?.embeddings?.[0]?.values ?? result?.embedding?.values ?? null;
  } catch (err: any) {
    console.warn('[KnowledgeEmbedding] Error generando embedding:', err.message);
    return null;
  }
}

export class KnowledgeEmbeddingService {
  async generateAndSave(itemId: string, title: string, content: string): Promise<void> {
    try {
      const text = `${title}\n\n${content}`.slice(0, 2000);
      const embedding = await generateEmbedding(text);
      if (!embedding) return;

      const { error } = await supabaseAdmin
        .from(TABLE)
        .update({ embedding: JSON.stringify(embedding) })
        .eq('id', itemId);

      if (error) {
        console.error('[KnowledgeEmbedding] Error guardando embedding:', error.message);
      } else {
        console.log(`[KnowledgeEmbedding] Embedding guardado para item "${itemId}"`);
      }
    } catch (err: any) {
      console.error('[KnowledgeEmbedding] Error inesperado:', err.message);
    }
  }

  async backfillMissing(): Promise<{ processed: number; failed: number }> {
    const { data: items, error } = await supabaseAdmin
      .from(TABLE)
      .select('id, title, content')
      .is('embedding', null);

    if (error || !items?.length) {
      console.log('[KnowledgeEmbedding] No hay items sin embedding');
      return { processed: 0, failed: 0 };
    }

    let processed = 0;
    let failed = 0;

    for (const item of items) {
      try {
        await this.generateAndSave(item.id, item.title, item.content);
        processed++;
        await new Promise(r => setTimeout(r, 300));
      } catch {
        failed++;
      }
    }

    console.log(`[KnowledgeEmbedding] Backfill completo: ${processed} OK, ${failed} fallidos`);
    return { processed, failed };
  }
}

