export class PaymentSettingsService {

  private readonly TABLE = 'payment_settings';

  private readonly SINGLETON_ID = 1; // Solo hay una fila de configuración

  

  // Cache simple para evitar múltiples lecturas a la BD

  private cache: { data: PaymentSettings | null; timestamp: number } = {

    data: null,

    timestamp: 0

  };

  private readonly CACHE_TTL_MS = 10000; // 10 segundos



  async getSettings(): Promise<PaymentSettings> {

    // Verificar cache primero

    if (this.cache.data && (Date.now() - this.cache.timestamp) < this.CACHE_TTL_MS) {

      return this.cache.data;

    }

    

    const { data, error } = await supabaseAdmin

      .from(this.TABLE)

      .select('*')

      .eq('id', this.SINGLETON_ID)

      .single();



    if (error || !data) {

      return DEFAULT_SETTINGS;

    }



    this.cache = { data: data as PaymentSettings, timestamp: Date.now() };

    return data as PaymentSettings;

  }



  async updateSettings(settings: Partial<PaymentSettings>): Promise<PaymentSettings> {

    // Intentar actualizar primero

    const { data: existing } = await supabaseAdmin

      .from(this.TABLE)

      .select('id')

      .eq('id', this.SINGLETON_ID)

      .single();



    let result;



    if (existing) {

      const { data, error } = await supabaseAdmin

        .from(this.TABLE)

        .update({ ...settings, updated_at: new Date().toISOString() })

        .eq('id', this.SINGLETON_ID)

        .select()

        .single();



      if (error) {

        console.error('[PaymentSettingsService] Error al actualizar Supabase:', error);

        throw new Error('Error al actualizar configuración: ' + error.message);

      }

      result = data;

    } else {

      const { data, error } = await supabaseAdmin

        .from(this.TABLE)

        .insert({ id: this.SINGLETON_ID, ...DEFAULT_SETTINGS, ...settings, updated_at: new Date().toISOString() })

        .select()

        .single();



      if (error) throw new Error('Error al crear configuración: ' + error.message);

      result = data;

    }



    // Invalidar cache al actualizar

    this.cache.data = null;

    return result as PaymentSettings;

  }



  /**

   * Enmascara números de cuenta mostrando solo los últimos 4 dígitos

   */

  private maskAccountNumber(accountNumber: string): string {

    if (!accountNumber || accountNumber.length < 4) {

      return accountNumber || '';

    }

    return '****' + accountNumber.slice(-4);

  }



  /**

   * Retorna solo los campos públicos seguros (sin claves privadas)

   * para exponer al frontend de la marca.

   * Si wompi_test_mode=false, expone la llave pública de producción.

   */

  async getPublicSettings(): Promise<{

    landingPrice: number;

    landingOriginalPrice: number;

    wompiEnabled: boolean;

    wompiPublicKey: string;

    wompiTestMode: boolean;

    paypalEnabled: boolean;

    paypalEmail: string;

    paypalSandbox: boolean;

    manualEnabled: boolean;

    manualInstructions: string;

    manualWhatsapp: string;

    manualEmail: string;

    socialInstagram: string;

    socialTiktok: string;

    socialFacebook: string;

    socialYoutube: string;

    transferEnabled: boolean;

    transferBankName: string;

    transferAccountNumber: string;

    transferAccountType: string;

    transferAccountHolder: string;

    currency: string;

    modalPromoConfig: any;

    modalTitle: string;

    modalDescription: string;

    modalImageUrl: string;

    miniLandingPreviewSeconds: number;

    maintenanceMode: boolean;

    maintenanceMessage: string;

    trm: number;

    gaMeasurementId: string;

    whatsappContact: string;

  }> {

    const s = await this.getSettings();

    // En modo producción usar la llave pública de producción

    const wompiPublicKey = s.wompi_test_mode

      ? s.wompi_public_key

      : (s.wompi_prod_public_key || s.wompi_public_key);



    let trm = 4000; // Fallback seguro

    try {

      const trmResult = await pricingService.getEffectiveTrm();

      trm = trmResult.trm;

    } catch (err) {

      console.error('[PaymentSettings] Error al obtener TRM, usando fallback:', err instanceof Error ? err.message : err);

    }



    const { data: metaRow } = await supabaseAdmin

      .from('pricing_config')

      .select('data')

      .eq('id', 'meta')

      .maybeSingle();



    const meta = (metaRow?.data ?? {}) as Record<string, unknown>;



    return {

      landingPrice: s.landing_price ?? 650000,

      landingOriginalPrice: s.landing_original_price ?? 900000,

      wompiEnabled: s.wompi_enabled,

      wompiPublicKey,

      wompiTestMode: s.wompi_test_mode,

      paypalEnabled: s.paypal_enabled,

      paypalEmail: s.paypal_email,

      paypalSandbox: s.paypal_sandbox,

      manualEnabled: s.manual_enabled,

      manualInstructions: s.manual_instructions,

      manualWhatsapp: s.manual_whatsapp || '573105436281',

      manualEmail: s.manual_email || 'info@lookitry.com',

      socialInstagram: String(meta.social_instagram ?? 'https://instagram.com/looki.try'),

      socialTiktok: String(meta.social_tiktok ?? 'https://www.tiktok.com/@lookitry'),

      socialFacebook: String(meta.social_facebook ?? ''),

      socialYoutube: String(meta.social_youtube ?? ''),

      transferEnabled: s.transfer_enabled,

      transferBankName: s.transfer_bank_name,

      transferAccountNumber: this.maskAccountNumber(s.transfer_account_number),

      transferAccountType: s.transfer_account_type,

      transferAccountHolder: s.transfer_account_holder,

      currency: s.currency,

      modalPromoConfig: s.modal_promo_config,

      modalTitle: s.modal_title,

      modalDescription: s.modal_description,

      modalImageUrl: s.modal_image_url,

      miniLandingPreviewSeconds: s.mini_landing_preview_seconds,

      maintenanceMode: s.maintenance_mode,

      maintenanceMessage: s.maintenance_message,

      trm,

      gaMeasurementId: s.ga_measurement_id || '',

      whatsappContact: s.whatsapp_contact || '+573105436281',

    };

  }

}

import axios from 'axios';

import { supabaseAdmin } from '../config/supabase';
import { calculatePriceUSD } from '../utils/pricingCurrency';


type PaypalOrderRecord = {

  reference: string;

  brand_id: string | null;

  email: string | null;

  plan: string;

  months: number;

  amount_cop: number;

  trm: number;

  amount_usd_expected: number;

  order_id: string | null;

  status: string | null;

};



export class PaypalService {

  /**
   * Convierte COP a USD con margen mínimo de 10,000 COP.
   * Alias para backward compatibility - usa la función centralizada.
   */
  convertCopToUsd(amountCOP: number, trm: number): number {
    return calculatePriceUSD(amountCOP, trm);
  }



  private isProd(): boolean {

    return process.env.NODE_ENV === 'production';

  }



  private async getActiveKeys() {

    // Prioridad 1: Variables de entorno (seguridad y facilidad de despliegue)

    if (process.env.PAYPAL_CLIENT_ID && process.env.PAYPAL_CLIENT_SECRET) {

      return {

        clientId: process.env.PAYPAL_CLIENT_ID,

        clientSecret: process.env.PAYPAL_CLIENT_SECRET,

        sandbox: process.env.PAYPAL_SANDBOX === 'true'

      };

    }



    // Prioridad 2: Base de datos (configuración dinámica desde el panel admin)

    const { data: settings, error } = await supabaseAdmin

      .from('payment_settings')

      .select('paypal_enabled, paypal_client_id, paypal_client_secret, paypal_prod_client_id, paypal_prod_client_secret, paypal_sandbox')

      .eq('id', 1)

      .single();



    if (error || !settings) {

      throw new Error('No se pudo cargar la configuración de PayPal');

    }



    if (!settings.paypal_enabled) {

      throw new Error('PayPal no está habilitado en este momento');

    }



    const sandbox = !!settings.paypal_sandbox;



    return sandbox

      ? {

          clientId: settings.paypal_client_id,

          clientSecret: settings.paypal_client_secret,

          sandbox: true

        }

      : {

          clientId: settings.paypal_prod_client_id || settings.paypal_client_id,

          clientSecret: settings.paypal_prod_client_secret || settings.paypal_client_secret,

          sandbox: false

        };

  }



  private async getAccessToken(): Promise<string> {

    const { clientId, clientSecret, sandbox } = await this.getActiveKeys();

    const baseUrl = sandbox ? 'https://api-m.sandbox.paypal.com' : 'https://api-m.paypal.com';

    const auth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');



    const response = await axios.post(

      `${baseUrl}/v1/oauth2/token`,

      'grant_type=client_credentials',

      {

        headers: {

          'Content-Type': 'application/x-www-form-urlencoded',

          Authorization: `Basic ${auth}`

        }

      }

    );



    return response.data.access_token;

  }



  /**

   * Crea una orden en PayPal

   * @param amountCOP Monto en COP

   * @param trm Tasa representativa del mercado (COP -> USD)

   * @param reference Referencia de pago interna

   * @param returnUrl URL de retorno exitoso (opcional)

   * @param cancelUrl URL de cancelación (opcional)

   */

  async createOrder(

    amountCOP: number,

    trm: number,

    reference: string,

    returnUrl?: string,

    cancelUrl?: string,

    planStr: string = 'UNKNOWN'

  ): Promise<{ checkoutUrl: string; orderId: string; amountUSD: number }> {

    const accessToken = await this.getAccessToken();

    const { sandbox } = await this.getActiveKeys();

    const baseUrl = sandbox ? 'https://api-m.sandbox.paypal.com' : 'https://api-m.paypal.com';



    // Convertir COP a USD (PayPal no acepta COP directamente para suscripciones)

    const amountUSD = this.convertCopToUsd(amountCOP, trm);



    const shortRef = reference.length > 254 ? reference.substring(0, 254) : reference;

    const returnUrlFinal = returnUrl || `${process.env.FRONTEND_URL}/pago-exitoso?method=paypal&ref=${encodeURIComponent(reference)}`;

    const cancelUrlFinal = cancelUrl || `${process.env.FRONTEND_URL}/checkout`;



    const orderPayload: Record<string, any> = {

      intent: 'CAPTURE',

      purchase_units: [

        {

          reference_id: shortRef,

          amount: {

            currency_code: 'USD',

            value: amountUSD.toFixed(2)

          },

          description: `Suscripción Lookitry - Plan ${planStr}`

        }

      ],

      application_context: {

        brand_name: 'Lookitry',

        landing_page: 'BILLING',

        user_action: 'PAY_NOW',

        return_url: returnUrlFinal,

        cancel_url: cancelUrlFinal

      }

    };



    const response = await axios.post(

      `${baseUrl}/v2/checkout/orders`,

      orderPayload,

      {

        headers: {

          'Content-Type': 'application/json',

          Authorization: `Bearer ${accessToken}`

        }

      }

    );



    // Buscar el link de aprobación

    const approveLink = response.data.links?.find((l: any) => l.rel === 'approve');

    if (!approveLink) {

      console.error('[PayPal] Respuesta completa:', JSON.stringify(response.data, null, 2));

      throw new Error('No se pudo generar el link de aprobación de PayPal');

    }



    return {

      checkoutUrl: approveLink.href,

      orderId: response.data.id,

      amountUSD,

    };

  }



  /**

   * Captura el pago aprobado por el usuario

   */

  async captureOrder(orderId: string): Promise<any> {
    const accessToken = await this.getAccessToken();

    const { sandbox } = await this.getActiveKeys();

    const baseUrl = sandbox ? 'https://api-m.sandbox.paypal.com' : 'https://api-m.paypal.com';



    const response = await axios.post(

      `${baseUrl}/v2/checkout/orders/${orderId}/capture`,

      {},

      {

        headers: {

          'Content-Type': 'application/json',

          Authorization: `Bearer ${accessToken}`

        }

      }

    );



    return response.data;

  }



  /**

   * Obtiene el detalle de una orden de PayPal para verificar su estado

   */

  async getOrder(orderId: string): Promise<any> {

    const accessToken = await this.getAccessToken();

    const { sandbox } = await this.getActiveKeys();

    const baseUrl = sandbox ? 'https://api-m.sandbox.paypal.com' : 'https://api-m.paypal.com';



    const response = await axios.get(

      `${baseUrl}/v2/checkout/orders/${orderId}`,

      {

        headers: {

          'Content-Type': 'application/json',

          Authorization: `Bearer ${accessToken}`

        }

      }

    );



    return response.data;

  }



  extractReference(source: any): string | null {

    const purchaseUnit = source?.purchase_units?.[0];

    return (

      purchaseUnit?.custom_id ||

      purchaseUnit?.invoice_id ||

      purchaseUnit?.reference_id ||

      source?.custom_id ||

      source?.invoice_id ||

      source?.supplementary_data?.related_ids?.order_id ||

      null

    );

  }



  extractAmountUsd(source: any): number | null {

    const purchaseUnit = source?.purchase_units?.[0];

    const captureAmount = purchaseUnit?.payments?.captures?.[0]?.amount?.value;

    const orderAmount = purchaseUnit?.amount?.value;

    const raw = captureAmount ?? orderAmount ?? source?.amount?.value;

    const parsed = raw ? parseFloat(raw) : NaN;

    return Number.isFinite(parsed) ? parsed : null;

  }



  async recordOrder(payload: PaypalOrderRecord): Promise<void> {

    const { error } = await supabaseAdmin.from('paypal_orders').upsert(payload, {

      onConflict: 'reference',

    });



    if (error) {

      throw new Error(`No se pudo registrar la orden PayPal: ${error.message}`);

    }

  }



  async getTrackedOrder(reference: string): Promise<PaypalOrderRecord | null> {

    const { data, error } = await supabaseAdmin

      .from('paypal_orders')

      .select('reference, brand_id, email, plan, months, amount_cop, trm, amount_usd_expected, order_id, status')

      .eq('reference', reference)

      .maybeSingle();



    if (error) {

      throw new Error(`No se pudo consultar paypal_orders: ${error.message}`);

    }



    return (data as PaypalOrderRecord | null) ?? null;

  }



  async markOrderStatus(reference: string, status: string, orderId?: string | null): Promise<void> {

    const patch: Record<string, unknown> = { status };

    if (orderId) {

      patch.order_id = orderId;

    }



    const { error } = await supabaseAdmin

      .from('paypal_orders')

      .update(patch)

      .eq('reference', reference);



    if (error) {

      throw new Error(`No se pudo actualizar paypal_orders: ${error.message}`);

    }

  }



  /**

   * Intenta atomicizar el procesamiento de una orden (lock optimista).

   * Retorna true si fue exitoso (la orden estaba en estado válido para procesar).

   * Retorna false si ya estaba procesada/completada.

   */

  async tryStartProcessing(reference: string): Promise<boolean> {

    const { data, error } = await supabaseAdmin

      .from('paypal_orders')

      .update({ status: 'processing' })

      .eq('reference', reference)

      .in('status', ['pending', 'failed'])

      .select();



    if (error) {

      console.error('[PayPal] Error en tryStartProcessing:', error.message);

      return false;

    }



    // Si data.length > 0, pudimos adquirir el lock

    return data && data.length > 0;

  }



  /**

   * Verifica la firma de un webhook de PayPal

   * Nota: Idealmente se usa el endpoint de validación de PayPal o una librería

   */

  async verifyWebhookSignature(req: any): Promise<boolean> {

    // PayPal Webhook verification:

    // https://developer.paypal.com/docs/api/webhooks/v1/#verify-webhook-signature

    //

    // En producción, rechazamos si no se puede verificar.

    const strict = this.isProd();



    const webhookId =

      process.env.PAYPAL_WEBHOOK_ID ||

      process.env.PAYPAL_WEBHOOK_ID_SANDBOX ||

      '';



    if (!webhookId) {

      console.error('[PayPal] PAYPAL_WEBHOOK_ID no configurado — RECHAZANDO webhook');

      return false;

    }



    const transmissionId = req.headers['paypal-transmission-id'];

    const transmissionTime = req.headers['paypal-transmission-time'];

    const certUrl = req.headers['paypal-cert-url'];

    const authAlgo = req.headers['paypal-auth-algo'];

    const transmissionSig = req.headers['paypal-transmission-sig'];



    if (!transmissionId || !transmissionTime || !certUrl || !authAlgo || !transmissionSig) {

      console.error('[PayPal] Headers de verificación faltantes');

      return false;

    }



    try {

      const accessToken = await this.getAccessToken();

      const { sandbox } = await this.getActiveKeys();

      const baseUrl = sandbox ? 'https://api-m.sandbox.paypal.com' : 'https://api-m.paypal.com';



      const resp = await axios.post(

        `${baseUrl}/v1/notifications/verify-webhook-signature`,

        {

          auth_algo: authAlgo,

          cert_url: certUrl,

          transmission_id: transmissionId,

          transmission_sig: transmissionSig,

          transmission_time: transmissionTime,

          webhook_id: webhookId,

          webhook_event: req.body,

        },

        { headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${accessToken}` } }

      );



      return resp.data?.verification_status === 'SUCCESS';

    } catch (e) {

      console.error('[PayPal] Error en verificación de webhook:', e instanceof Error ? e.message : String(e));

      return false;

    }

  }

}



export const paypalService = new PaypalService();

import { supabaseAdmin } from '../config/supabase';
import { PaymentSettingsService } from './paymentSettings.service';
import { TrmService } from '../utils/trm';
import { calculatePriceUSD, getMinimumTrmForConsistency } from '../utils/pricingCurrency';

export { calculatePriceUSD, getMinimumTrmForConsistency };

export interface PricingConfig {
  id: string;
  data: any;
}

interface ActivePromotion {
  type: string;
  config: any;
  starts_at?: string | null;
  ends_at?: string | null;
}

export class PricingService {
  private async getActivePromotions(): Promise<ActivePromotion[]> {
    const { data, error } = await supabaseAdmin
      .from('promotions')
      .select('type, config, starts_at, ends_at')
      .eq('active', true);

    if (error || !data) {
      return [];
    }

    const now = new Date();
    return data.filter((promo: any) => {
      const startsOk = !promo.starts_at || new Date(promo.starts_at) <= now;
      const endsOk = !promo.ends_at || new Date(promo.ends_at) >= now;
      return startsOk && endsOk;
    });
  }

  private applyExternalPlanPromotions(planKey: string, baseMonthlyPrice: number, promotions: ActivePromotion[]): number {
    const normalizedPlan = planKey.toUpperCase();
    const overridePromo = promotions.find((promo) =>
      promo.type === 'plan_override' &&
      String(promo.config?.plan || '').toUpperCase() === normalizedPlan &&
      Number(promo.config?.override_price) > 0
    );

    let effectiveBasePrice = overridePromo
      ? Number(overridePromo.config.override_price)
      : baseMonthlyPrice;

    const globalDiscountPct = promotions.reduce((max, promo) => {
      if (['launch_offer', 'modal_timer'].includes(promo.type) && Number(promo.config?.discount_pct) > 0) {
        return Math.max(max, Number(promo.config.discount_pct));
      }
      return max;
    }, 0);

    if (globalDiscountPct > 0) {
      effectiveBasePrice = Math.ceil(effectiveBasePrice * (1 - globalDiscountPct / 100));
    }

    return effectiveBasePrice;
  }

  /**
   * Obtiene la configuración de precios desde la base de datos
   */
  async getPricingConfig(): Promise<PricingConfig[]> {
    const { data, error } = await supabaseAdmin
      .from('pricing_config')
      .select('id, data');

    if (error) {
      console.error('[PricingService] Error al obtener pricing_config:', error);
      return [];
    }

    return data || [];
  }

  /**
   * Calcula el monto total a cobrar de forma segura en el backend.
   * Ignora montos enviados desde el frontend para evitar manipulaciones.
   * 
   * @param plan - 'BASIC' | 'PRO'
   * @param months - 1, 3, 6, 12
   * @param includesLanding - si incluye mini-landing
   * @returns Monto total en COP
   */
  async calculateTotal(plan: string, months: number, includesLanding: boolean = false): Promise<number> {
    const configs = await this.getPricingConfig();
    const planKey = plan.toLowerCase(); // 'basic' o 'pro'
    
    // Buscar el plan de forma insensible a mayúsculas en el ID
    const planConfig = configs.find(c => c.id.toLowerCase() === planKey);
    const planData = planConfig?.data;
    const discounts = configs.find(c => c.id.toLowerCase() === 'descuentos_duracion')?.data;
    
    // 1. Precio base del plan (fallback si no está en DB)
    const baseMonthlyPrice = planData?.precio_mensual_cop || (planKey === 'pro' ? 350000 : 180000);
    
    // 2. Aplicar descuento por duración
    const discountKey = `meses_${months}`;
    const discountPct = discounts?.[discountKey] || 0;
    
    const planTotal = Math.round(baseMonthlyPrice * months * (1 - discountPct / 100));
    
    // 3. Sumar landing page si aplica
    let landingTotal = 0;
    if (includesLanding) {
      // El servicio se instancia localmente para evitar dependencia circular extrema
      const settingsService = new PaymentSettingsService();
      const settings = await settingsService.getSettings();
      landingTotal = settings.landing_price || 650000;
    }
    
    const finalTotal = planTotal + landingTotal;
    
    console.log(`[PricingService] Calculado: plan=${plan} months=${months} landing=${includesLanding} -> Total=${finalTotal} (Base=${baseMonthlyPrice} Desc=${discountPct}%)`);
    
    return finalTotal;
  }

  async calculateExternalCheckoutTotal(plan: string, months: number, includesLanding: boolean = false): Promise<number> {
    const configs = await this.getPricingConfig();
    const promotions = await this.getActivePromotions();
    const planKey = plan.toLowerCase();

    const planConfig = configs.find(c => c.id.toLowerCase() === planKey);
    const planData = planConfig?.data;
    const discounts = configs.find(c => c.id.toLowerCase() === 'descuentos_duracion')?.data;

    const baseMonthlyPrice = planData?.precio_mensual_cop || (planKey === 'pro' ? 350000 : 180000);
    const effectiveMonthlyPrice = this.applyExternalPlanPromotions(planKey, baseMonthlyPrice, promotions);

    const discountKey = `meses_${months}`;
    const discountPct = discounts?.[discountKey] || 0;
    const planTotal = Math.ceil(effectiveMonthlyPrice * months * (1 - discountPct / 100));

    let landingTotal = 0;
    if (includesLanding) {
      // El servicio se instancia localmente para evitar dependencia circular extrema
      const settingsService = new PaymentSettingsService();
      const settings = await settingsService.getSettings();
      landingTotal = settings.landing_price || 650000;
    }

    const finalTotal = planTotal + landingTotal;
    console.log(`[PricingService] Checkout externo: plan=${plan} months=${months} landing=${includesLanding} -> Total=${finalTotal} (BasePromo=${effectiveMonthlyPrice} Desc=${discountPct}%)`);
    return finalTotal;
  }


  /**

   * Obtiene la TRM efectiva respetando configuración en pricing_config.meta.

   * - Si trm_auto = false y hay trm_referencia válida â usa ese valor (manual).

   * - En otro caso â usa TRM automática (servicio externo + caché).

   * - En desarrollo se puede pasar un override explícito para pruebas.

   */

  async getEffectiveTrm(overrideFromQuery?: number | null): Promise<{ trm: number; source: 'query' | 'meta_manual' | 'meta_auto' }> {
    // Permitir override solo en desarrollo para evitar manipulaciones en producción

    if (process.env.NODE_ENV === 'development' && overrideFromQuery && overrideFromQuery > 0) {

      console.log(`[PricingService] TRM override desde query (solo dev): ${overrideFromQuery}`);

      return { trm: overrideFromQuery, source: 'query' };

    }



    const configs = await this.getPricingConfig();

    const metaConfig = configs.find(c => c.id.toLowerCase() === 'meta')?.data || {};



    const trmAuto = metaConfig.trm_auto !== false; // por defecto true

    const trmRefRaw = metaConfig.trm_referencia;

    const trmReferencia = typeof trmRefRaw === 'number' ? trmRefRaw : Number(trmRefRaw);



    // Preferir valor manual cuando trm_auto = false y el valor es válido

    if (!trmAuto && trmReferencia && trmReferencia > 0) {
      console.log(`[PricingService] TRM manual desde pricing_config.meta: ${trmReferencia}`);
      return { trm: trmReferencia, source: 'meta_manual' };
    }

    // Fallback: TRM automática desde servicio externo (con caché + fallback interno)
    const hadFreshCache = TrmService.isCacheFresh();
    const autoTrm = await TrmService.getCurrentTrm();
    if (!hadFreshCache) {
      console.log(`[PricingService] TRM automática refrescada: ${autoTrm}`);
    }
    return { trm: autoTrm, source: 'meta_auto' };
  }
}


