import { supabaseAdmin } from '../config/supabase';
import { SocialApiConfig } from './lead.service';

export interface SocialApiConfigInput {
  platform: 'instagram' | 'tiktok' | 'facebook' | 'googlemaps';
  config: Record<string, any>;
  created_by: string;
}

export class SocialApiConfigService {
  async getConfigs(): Promise<SocialApiConfig[]> {
    const { data, error } = await supabaseAdmin
      .from('social_api_configs')
      .select('*')
      .order('platform');

    if (error) throw error;
    return (data as SocialApiConfig[]) || [];
  }

  async getConfigByPlatform(platform: string): Promise<SocialApiConfig | null> {
    const { data, error } = await supabaseAdmin
      .from('social_api_configs')
      .select('*')
      .eq('platform', platform)
      .maybeSingle();

    if (error) throw error;
    return data as SocialApiConfig | null;
  }

  async upsertConfig(input: SocialApiConfigInput): Promise<SocialApiConfig> {
    const existing = await this.getConfigByPlatform(input.platform);

    const configToStore = {
      platform: input.platform,
      config: input.config,
      is_active: existing?.is_active || false,
      created_by: input.created_by,
    };

    if (existing) {
      const { data, error } = await supabaseAdmin
        .from('social_api_configs')
        .update({
          ...configToStore,
          updated_at: new Date().toISOString(),
        })
        .eq('platform', input.platform)
        .select()
        .single();

      if (error) throw error;
      return data as SocialApiConfig;
    } else {
      const { data, error } = await supabaseAdmin
        .from('social_api_configs')
        .insert(configToStore)
        .select()
        .single();

      if (error) throw error;
      return data as SocialApiConfig;
    }
  }

  async setActive(platform: string, active: boolean): Promise<void> {
    const { error } = await supabaseAdmin
      .from('social_api_configs')
      .update({
        is_active: active,
        updated_at: new Date().toISOString(),
      })
      .eq('platform', platform);

    if (error) throw error;
  }

  async testConnection(platform: string): Promise<{ success: boolean; message: string }> {
    const config = await this.getConfigByPlatform(platform);
    if (!config) {
      return { success: false, message: 'Configuración no encontrada' };
    }

    try {
      if (platform === 'instagram' || platform === 'facebook') {
        return await this.testMetaConnection(config.config);
      } else if (platform === 'tiktok') {
        return await this.testTiktokConnection(config.config);
      } else if (platform === 'googlemaps') {
        return await this.testGoogleMapsConnection(config.config);
      }

      return { success: false, message: 'Plataforma no soportada' };
    } catch (error: any) {
      return { success: false, message: error.message };
    }
  }

  private async testGoogleMapsConnection(config: Record<string, any>): Promise<{ success: boolean; message: string }> {
    const apiKey = config.api_key;
    if (!apiKey) {
      return { success: false, message: 'API Key no configurada' };
    }

    try {
      const response = await fetch(
        `https://maps.googleapis.com/maps/api/place/textsearch/json?query=test&key=${apiKey}`
      );
      const data = await response.json() as { error?: string; results?: unknown[] };

      if (data.error) {
        return { success: false, message: data.error };
      }

      await this.updateLastTest('googlemaps', { success: true });
      return { success: true, message: 'API de Google Maps configurada correctamente' };
    } catch (error: any) {
      return { success: false, message: error.message };
    }
  }

  private async testMetaConnection(config: Record<string, any>): Promise<{ success: boolean; message: string }> {
    const accessToken = config.access_token;
    if (!accessToken) {
      return { success: false, message: 'Access token no configurado' };
    }

    try {
      const response = await fetch(
        `https://graph.facebook.com/v18.0/me?access_token=${accessToken}`
      );
      const data = await response.json() as { error?: { message: string }; id?: string; name?: string };

      if (data.error) {
        return { success: false, message: data.error.message };
      }

      await this.updateLastTest(config.platform as string, { success: true, page_id: data.id });
      return { success: true, message: `Conectado como ${data.name} (${data.id})` };
    } catch (error: any) {
      return { success: false, message: error.message };
    }
  }

  private async testTiktokConnection(config: Record<string, any>): Promise<{ success: boolean; message: string }> {
    const accessToken = config.access_token;
    if (!accessToken) {
      return { success: false, message: 'Access token no configurado' };
    }

    try {
      const response = await fetch('https://open.tiktokapis.com/v2/user/info/', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ fields: ['open_id', 'display_name'] }),
      });

      const data = await response.json() as { error?: { message: string }; data?: { user?: { open_id: string; display_name: string } } };

      if (data.error) {
        return { success: false, message: data.error.message };
      }

      await this.updateLastTest(config.platform as string, { success: true, user_id: data.data?.user?.open_id });
      return { success: true, message: `Conectado como ${data.data?.user?.display_name || 'Tiktok User'}` };
    } catch (error: any) {
      return { success: false, message: error.message };
    }
  }

  private async updateLastTest(platform: string, result: Record<string, any>): Promise<void> {
    await supabaseAdmin
      .from('social_api_configs')
      .update({
        last_test_at: new Date().toISOString(),
        last_test_result: result,
        updated_at: new Date().toISOString(),
      })
      .eq('platform', platform);
  }

  async deleteConfig(platform: string): Promise<void> {
    const { error } = await supabaseAdmin
      .from('social_api_configs')
      .delete()
      .eq('platform', platform);

    if (error) throw error;
  }
}

export const socialApiConfigService = new SocialApiConfigService();

import { supabaseAdmin } from '../config/supabase';
import { Brand, SubscriptionPayment, CreatePaymentDto } from '../types';
import { PaymentSettingsService } from './paymentSettings.service';
import { getReportingTrm, normalizePaymentRecordToCop } from '../utils/paymentNormalization';
import {
  attachLedgerSnapshotToNotes,
  parseLedgerSnapshotFromNotes,
  type PaymentLedgerSnapshot,
} from '../utils/paymentLedger';
import { hasActivePaidSubscription, isTrialOperationalBrand, recordTrialEvent } from '../utils/brandLifecycle';
import { pricingService } from './pricing.service';
import { referralService } from './referral.service';

/**
 * SubscriptionService
 *
 * Servicio para gestionar suscripciones de marcas.
 * Maneja verificación de estado, renovaciones, suspensiones y cálculos de fechas.
 */
export class SubscriptionService {
  private async insertPaymentCompat(payload: Record<string, unknown>): Promise<SubscriptionPayment> {
    const { data, error } = await supabaseAdmin
      .from('subscription_payments')
      .insert(payload)
      .select()
      .single();

    if (!error && data) {
      return data as SubscriptionPayment;
    }

    if (error?.message?.toLowerCase().includes('reference') && 'reference' in payload) {
      const fallbackPayload = Object.fromEntries(
        Object.entries(payload as Record<string, unknown>).filter(([key]) => key !== 'reference')
      );
      const retry = await supabaseAdmin
        .from('subscription_payments')
        .insert(fallbackPayload)
        .select()
        .single();

      if (retry.error || !retry.data) {
        throw new Error('Error al registrar el pago: ' + retry.error?.message);
      }

      return retry.data as SubscriptionPayment;
    }

    throw new Error('Error al registrar el pago: ' + error?.message);
  }

  async checkSubscriptionStatus(brandId: string): Promise<boolean> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('plan, subscription_status, trial_end_date, trial_payment_status')
      .eq('id', brandId)
      .single();

    if (error || !data) return false;
    if (isTrialOperationalBrand(data)) return true;

    if (
      data.subscription_status === 'active' ||
      data.subscription_status === 'expiring_soon' ||
      (data.plan !== 'TRIAL' && data.subscription_status == null)
    ) {
      return true;
    }

    if ((data.plan === 'TRIAL' || data.trial_payment_status === 'active') && data.trial_end_date) {
      const trialEnd = new Date(data.trial_end_date);
      if (trialEnd > new Date()) return true;
    }

    return false;
  }

  async isInTrial(brandId: string): Promise<boolean> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('plan, trial_end_date, subscription_status, trial_payment_status')
      .eq('id', brandId)
      .single();

    if (error || !data || !data.trial_end_date) return false;
    return isTrialOperationalBrand(data);
  }

  async getTrialDaysRemaining(brandId: string): Promise<number | null> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('plan, trial_end_date, trial_payment_status, subscription_status')
      .eq('id', brandId)
      .single();

    if (error || !data || !data.trial_end_date || !isTrialOperationalBrand(data)) return null;

    const trialEnd = new Date(data.trial_end_date);
    const now = new Date();
    const diffMs = trialEnd.getTime() - now.getTime();
    const diffDays = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

    return diffDays > 0 ? diffDays : 0;
  }

  calculateExpirationDate(startDate: Date, months: number = 1): Date {
    const expirationDate = new Date(startDate);
    expirationDate.setDate(expirationDate.getDate() + 30 * months);
    return expirationDate;
  }

  async renewSubscription(
    brandId: string,
    paymentData: CreatePaymentDto,
    months: number = 1,
    plan?: string,
    isUpgrade: boolean = false
  ): Promise<Brand> {
    if (![1, 3, 6, 12].includes(months)) {
      throw new Error('Los períodos permitidos son 1, 3, 6 o 12 meses');
    }

    if (paymentData.reference) {
      try {
        const { data: existingPayment } = await supabaseAdmin
          .from('subscription_payments')
          .select('id')
          .eq('reference', paymentData.reference)
          .limit(1)
          .maybeSingle();

        if (existingPayment) {
          const { data: currentBrand } = await supabaseAdmin
            .from('brands')
            .select('*')
            .eq('id', brandId)
            .single();
          if (currentBrand) return currentBrand as Brand;
        }
      } catch (e) {
        console.warn('[Subscription] Idempotency check failed:', e);
      }
    }

    const { data: brand, error: brandError } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('id', brandId)
      .single();

    if (brandError || !brand) throw new Error('Marca no encontrada');

    const now = new Date();
    const hadActiveTrial = isTrialOperationalBrand(brand);
    const previousPlan = brand.plan ?? 'BASIC';
    
    const newStartDate = isUpgrade
      ? now
      : brand.subscription_end_date && new Date(brand.subscription_end_date) > now
        ? new Date(brand.subscription_end_date)
        : now;

    const newEndDate = this.calculateExpirationDate(newStartDate, months);

    const updateData: Record<string, unknown> = {
      subscription_start_date: newStartDate.toISOString(),
      subscription_end_date: newEndDate.toISOString(),
      subscription_status: 'active',
      last_payment_date: paymentData.payment_date || now.toISOString(),
      next_payment_date: newEndDate.toISOString(),
    };

    if (plan && ['BASIC', 'PRO', 'ENTERPRISE', 'TRIAL'].includes(plan.toUpperCase())) {
      const planUpper = plan.toUpperCase();
      updateData.plan = planUpper;

      if (planUpper === 'TRIAL') {
        const nowIso = new Date().toISOString();
        const { data: campaign } = await supabaseAdmin
          .from('trial_campaigns')
          .select('trial_days')
          .eq('active', true)
          .or(`ends_at.is.null,ends_at.gt.${nowIso}`)
          .order('created_at', { ascending: false })
          .limit(1)
          .single();

        const trialDays = campaign?.trial_days ?? 7;
        const trialEndDate = new Date();
        trialEndDate.setDate(trialEndDate.getDate() + trialDays);

        updateData.trial_end_date = trialEndDate.toISOString();
        updateData.trial_payment_status = 'active';
        updateData.subscription_status = 'active';
        updateData.subscription_start_date = now.toISOString();
        updateData.subscription_end_date = trialEndDate.toISOString();
        updateData.next_payment_date = trialEndDate.toISOString();
      } else {
        updateData.trial_end_date = null;
        updateData.trial_payment_status = null;
      }
    }

    if (brand.landing_suspended_at) {
      const diasSuspendida = (Date.now() - new Date(brand.landing_suspended_at).getTime()) / (1000 * 60 * 60 * 24);
      if (diasSuspendida < 90) {
        updateData.has_landing_page = true;
        updateData.landing_suspended_at = null;
      }
    }

    const { data: updatedBrand, error: updateError } = await supabaseAdmin
      .from('brands')
      .update(updateData)
      .eq('id', brandId)
      .select()
      .single();

    if (updateError || !updatedBrand) throw new Error('Error al renovar: ' + updateError?.message);

    const planPurchased = String((plan || updatedBrand.plan || brand.plan || 'BASIC')).toUpperCase();
    const includesLanding = String(paymentData.notes || '').toUpperCase().includes('LANDING');
    const billingType = (paymentData.payment_method === 'credit_proration' || isUpgrade) ? 'upgrade' : 
                         (includesLanding && Number(paymentData.months_paid || months || 0) === 0) ? 'landing' : 'subscription';

    const ledgerSnapshot: PaymentLedgerSnapshot = {
      version: 1,
      brandId: brand.id,
      brandName: brand.name || null,
      brandEmail: brand.email || null,
      brandSlug: brand.slug || null,
      planPurchased,
      billingType,
      includesLanding,
      brandPlanBefore: previousPlan,
      brandPlanAfter: updatedBrand.plan || previousPlan,
    };

    await this.createPaymentRecord({
      ...paymentData,
      brand_id: brandId,
      payment_date: paymentData.payment_date || now.toISOString(),
      status: paymentData.status || 'completed',
      ledger_snapshot: ledgerSnapshot,
    });

    if (hadActiveTrial && ['BASIC', 'PRO', 'ENTERPRISE'].includes(planPurchased)) {
      await recordTrialEvent(brandId, 'trial_converted', { planPurchased }).catch(() => {});
    }

    if (billingType === 'subscription' && this.isEligibleReferralConversion(planPurchased, isUpgrade)) {
      await referralService.convertReferralForFirstPaidPlan({
        referredBrandId: brandId,
        planPurchased,
        paymentReference: paymentData.reference || null,
      }).catch((error) => {
        console.error('[Referral] Error applying referral reward after paid conversion:', error);
      });
    }

    return updatedBrand as Brand;
  }

  private isEligibleReferralConversion(planPurchased: string, isUpgrade: boolean): boolean {
    // TRIAL purchases do NOT trigger referral rewards — only paid plans (BASIC, PRO, ENTERPRISE)
    if (planPurchased === 'TRIAL') return false;
    return referralService.isEligiblePlan(planPurchased);
  }

  async calculateUpgradeProration(
    brandId: string,
    newPlan: string,
    newMonths: number,
    newPlanTotal: number,
    currentPlanPriceTotalFallback: number
  ): Promise<any> {
    const { data: brand, error } = await supabaseAdmin
      .from('brands')
      .select('subscription_end_date, subscription_start_date, subscription_status, trial_end_date, plan')
      .eq('id', brandId)
      .single();

    if (error || !brand) throw new Error('Marca no encontrada');

    const basePlanTotal = Math.round(newPlanTotal);

    if (!hasActivePaidSubscription(brand)) {
      const newEndDate = this.calculateExpirationDate(new Date(), newMonths);
      return {
        daysRemaining: 0,
        basePlanTotal,
        creditAmount: 0,
        newPlanTotal: basePlanTotal,
        amountToPay: basePlanTotal,
        remainingCredit: 0,
        newEndDate: newEndDate.toISOString(),
        isFree: false,
        creditLabel: 'Sin credito disponible',
      };
    }

    const now = new Date();
    const endDate = brand.subscription_end_date ? new Date(brand.subscription_end_date) : now;
    const daysRemaining = Math.max(0, Math.ceil((endDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)));

    const { data: lastPayment } = await supabaseAdmin
      .from('subscription_payments')
      .select('amount, currency, months_paid, notes')
      .eq('brand_id', brandId)
      .eq('status', 'completed')
      .gt('months_paid', 0)
      .neq('payment_method', 'credit_proration')
      .order('payment_date', { ascending: false })
      .limit(1)
      .maybeSingle();

    const paymentMonths = lastPayment?.months_paid || Math.max(1, Math.round(Math.max(30, (endDate.getTime() - (brand.subscription_start_date ? new Date(brand.subscription_start_date).getTime() : now.getTime())) / (1000 * 60 * 60 * 24)) / 30));
    const totalDays = Math.max(1, 30 * paymentMonths);
    const effectiveDaysRemaining = Math.min(daysRemaining, totalDays);

    let currentPlanPriceTotal: number;
    const rawAmount = lastPayment?.amount ? (typeof lastPayment.amount === 'string' ? parseFloat(lastPayment.amount) : lastPayment.amount) : 0;

    if (rawAmount > 0 && lastPayment?.months_paid && lastPayment.months_paid > 0) {
      const currency = String(lastPayment.currency || 'COP').toUpperCase();

      if (currency !== 'COP') {
        const { trm } = await pricingService.getEffectiveTrm();
        currentPlanPriceTotal = Math.round(rawAmount * trm);
        console.log(`[Proration] Convertido monto de lastPayment: ${rawAmount} ${currency} -> ${currentPlanPriceTotal} COP (TRM: ${trm})`);
      } else {
        currentPlanPriceTotal = rawAmount;
        console.log(`[Proration] Usando monto de lastPayment en COP: ${currentPlanPriceTotal}`);
      }
    } else {
      // No hay pago real anterior (trial, pago $0, etc) — calcular precio de plan actual desde config
      const currentPlanKey = String(brand.plan || 'BASIC').toUpperCase();
      currentPlanPriceTotal = currentPlanPriceTotalFallback > 0
        ? currentPlanPriceTotalFallback
        : await pricingService.calculateTotal(currentPlanKey, paymentMonths, false);
      console.log(`[Proration] Sin pago anterior valido. Usando precio de config para ${currentPlanKey} x ${paymentMonths} meses: ${currentPlanPriceTotal}`);
    }


    const lastSnapshot = parseLedgerSnapshotFromNotes(lastPayment?.notes);
    if (lastSnapshot?.includesLanding || String(lastPayment?.notes || '').includes('Incluye Landing Page')) {
      try {
        const settings = await new PaymentSettingsService().getSettings();
        const landingPrice = settings.landing_price || 650000;
        currentPlanPriceTotal = Math.max(0, currentPlanPriceTotal - landingPrice);
        console.log(`[Proration] Ajustado monto por landing page: -${landingPrice}`);
      } catch (e) {
        console.error('[Proration] Error al obtener precio de landing para ajuste:', e);
      }
    }

    const pricePerDay = currentPlanPriceTotal / totalDays;
    const creditAmount = Math.max(0, Math.round(pricePerDay * effectiveDaysRemaining));
    const amountToPay = Math.max(0, basePlanTotal - creditAmount);
    const remainingCredit = Math.max(0, creditAmount - basePlanTotal);

    const newEndDate = this.calculateExpirationDate(now, newMonths);
    const label = brand.plan === 'PRO' ? 'Plan Pro' : brand.plan === 'ENTERPRISE' ? 'Plan Enterprise' : 'Plan Básico';

    return {
      daysRemaining,
      basePlanTotal,
      creditAmount,
      newPlanTotal: basePlanTotal,
      amountToPay,
      remainingCredit,
      newEndDate: newEndDate.toISOString(),
      isFree: amountToPay <= 0,
      creditLabel: `Crédito por ${daysRemaining} días restantes del ${label}`,
    };
  }

  async applyFreeUpgrade(
    brandId: string,
    newPlan: string,
    newMonths: number,
    creditAmount: number,
    newPlanTotal: number,
    reference: string,
    forcedEndDate?: string
  ): Promise<Brand> {
    const now = new Date();
    const normalizedPlan = newPlan.toUpperCase();
    const newEndDate = forcedEndDate ? new Date(forcedEndDate) : this.calculateExpirationDate(now, newMonths);

    const { data: updatedBrand, error } = await supabaseAdmin
      .from('brands')
      .update({
        plan: normalizedPlan,
        subscription_start_date: now.toISOString(),
        subscription_end_date: newEndDate.toISOString(),
        subscription_status: 'active',
        trial_end_date: null,
        trial_payment_status: null,
        last_payment_date: now.toISOString(),
        next_payment_date: newEndDate.toISOString(),
      })
      .eq('id', brandId)
      .select()
      .single();

    if (error || !updatedBrand) throw new Error('Error al aplicar cambio de plan: ' + error?.message);

    if (newPlanTotal > creditAmount) {
      await this.createPaymentRecord({
        brand_id: brandId,
        amount: Math.max(0, newPlanTotal - creditAmount),
        currency: 'COP',
        payment_date: now.toISOString(),
        payment_method: 'credit_proration',
        status: 'completed',
        months_paid: newMonths,
        notes: `Cambio de plan por prorrateo. Plan: ${newPlan}. Crédito aplicado: $${creditAmount}. Valor plan: $${newPlanTotal}. Ref: ${reference}`,
        ledger_snapshot: {
          version: 1,
          brandId: brandId,
          brandName: (updatedBrand as any).name || null,
          brandEmail: (updatedBrand as any).email || null,
          brandSlug: (updatedBrand as any).slug || null,
          planPurchased: normalizedPlan,
          billingType: 'upgrade',
          includesLanding: false,
          brandPlanBefore: null,
          brandPlanAfter: normalizedPlan,
        },
      });
    }

    return updatedBrand as Brand;
  }

  async suspendSubscription(brandId: string): Promise<Brand> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .update({ subscription_status: 'suspended' })
      .eq('id', brandId)
      .select()
      .single();

    if (error || !data) throw new Error('Error al suspender: ' + error?.message);
    return data as Brand;
  }

  async getDaysRemaining(brandId: string): Promise<number | null> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('subscription_end_date')
      .eq('id', brandId)
      .single();

    if (error || !data || !data.subscription_end_date) return null;
    const diffTime = new Date(data.subscription_end_date).getTime() - new Date().getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  }

  async getExpiringSubscriptions(days: number): Promise<Brand[]> {
    const now = new Date();
    const futureDate = new Date();
    futureDate.setDate(futureDate.getDate() + days);

    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .in('subscription_status', ['active', 'expiring_soon'])
      .gte('subscription_end_date', now.toISOString())
      .lte('subscription_end_date', futureDate.toISOString())
      .order('subscription_end_date', { ascending: true });

    if (error) throw new Error('Error al obtener suscripciones por vencer: ' + error.message);
    return (data || []) as Brand[];
  }

  async getSubscriptionInfo(brandId: string): Promise<any> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('subscription_status, subscription_start_date, subscription_end_date, last_payment_date, next_payment_date, trial_end_date')
      .eq('id', brandId)
      .single();

    if (error || !data) throw new Error('Error al obtener info');

    const daysRemaining = await this.getDaysRemaining(brandId);
    const inTrial = await this.isInTrial(brandId);
    const trialDaysRemaining = await this.getTrialDaysRemaining(brandId);

    if (inTrial && trialDaysRemaining !== null && trialDaysRemaining <= 3) {
      await recordTrialEvent(brandId, 'trial_expiring', { trialDaysRemaining }).catch(() => {});
    }

    return {
      status: data.subscription_status,
      startDate: data.subscription_start_date,
      endDate: data.subscription_end_date,
      lastPaymentDate: data.last_payment_date,
      nextPaymentDate: data.next_payment_date,
      daysRemaining,
      isInTrial: inTrial,
      trialEndDate: data.trial_end_date,
      trialDaysRemaining,
    };
  }

  async reactivateSubscription(brandId: string): Promise<Brand> {
    const { data: brand, error: fetchError } = await supabaseAdmin
      .from('brands')
      .select('id, landing_suspended_at, has_landing_page, trial_end_date, subscription_end_date')
      .eq('id', brandId)
      .single();

    if (fetchError || !brand) throw new Error('Marca no encontrada');

    const now = new Date();
    const trialEndDate = brand.trial_end_date ? new Date(brand.trial_end_date) : null;
    const subscriptionEndDate = brand.subscription_end_date ? new Date(brand.subscription_end_date) : null;
    const hasActiveTrial = trialEndDate !== null && trialEndDate > now;
    const hasActivePaidPeriod = subscriptionEndDate !== null && subscriptionEndDate > now;

    if (!hasActiveTrial && !hasActivePaidPeriod) throw new Error('PAYMENT_REQUIRED_FOR_REACTIVATION');

    let restaurarLanding = false;
    if (brand.landing_suspended_at) {
      const diasSuspendida = (Date.now() - new Date(brand.landing_suspended_at).getTime()) / (1000 * 60 * 60 * 24);
      if (diasSuspendida < 90) restaurarLanding = true;
    }

    const shouldBeExpiringSoon = hasActivePaidPeriod && subscriptionEndDate !== null && subscriptionEndDate.getTime() - now.getTime() <= 7 * 24 * 60 * 60 * 1000;

    const payload: any = { subscription_status: shouldBeExpiringSoon ? 'expiring_soon' : 'active' };
    if (restaurarLanding) {
      payload.has_landing_page = true;
      payload.landing_suspended_at = null;
    }

    const { data, error } = await supabaseAdmin.from('brands').update(payload).eq('id', brandId).select().single();
    if (error || !data) throw new Error('Error al reactivar');
    return data as Brand;
  }

  async updateSubscriptionStatuses(): Promise<any> {
    const now = new Date().toISOString();
    const sevenDays = new Date();
    sevenDays.setDate(sevenDays.getDate() + 7);

    const { data: expiredTrials } = await supabaseAdmin.from('brands').update({ subscription_status: 'expired' }).eq('plan', 'TRIAL').lte('trial_end_date', now).not('trial_end_date', 'is', null).select('id');
    const { data: expiredBrands } = await supabaseAdmin.from('brands').update({ subscription_status: 'expired' }).neq('plan', 'TRIAL').lte('subscription_end_date', now).not('subscription_end_date', 'is', null).in('subscription_status', ['active', 'expiring_soon']).select('id');
    const { data: expiringSoon } = await supabaseAdmin.from('brands').update({ subscription_status: 'expiring_soon' }).neq('plan', 'TRIAL').gt('subscription_end_date', now).lte('subscription_end_date', sevenDays.toISOString()).eq('subscription_status', 'active').select('id');
    const { data: suspended } = await supabaseAdmin.from('brands').update({ subscription_status: 'suspended' }).eq('subscription_status', 'expired').select('id');

    return {
      expired: (expiredBrands?.length || 0) + (expiredTrials?.length || 0),
      expiringSoon: expiringSoon?.length || 0,
      suspended: suspended?.length || 0,
      trialExpired: expiredTrials?.length || 0,
    };
  }

  private async createPaymentRecord(paymentData: CreatePaymentDto): Promise<SubscriptionPayment> {
    if (paymentData.reference) {
      try {
        const { data: existing } = await supabaseAdmin.from('subscription_payments').select('*').eq('reference', paymentData.reference).limit(1).maybeSingle();
        if (existing) return existing as SubscriptionPayment;
      } catch (e) {}
    }

    const notes = paymentData.ledger_snapshot ? attachLedgerSnapshotToNotes(paymentData.notes || null, paymentData.ledger_snapshot as any) : (paymentData.notes || null);

    return this.insertPaymentCompat({
      brand_id: paymentData.brand_id,
      amount: paymentData.amount,
      currency: paymentData.currency || 'COP',
      payment_date: paymentData.payment_date || new Date().toISOString(),
      payment_method: paymentData.payment_method || null,
      status: paymentData.status || 'completed',
      notes,
      months_paid: paymentData.months_paid || 1,
      reference: paymentData.reference || null,
    });
  }

  async getPaymentHistory(brandId: string): Promise<SubscriptionPayment[]> {
    const { data, error } = await supabaseAdmin.from('subscription_payments').select('*').eq('brand_id', brandId).order('payment_date', { ascending: false });
    if (error) throw new Error('Error historial: ' + error.message);

    const reportingTrm = await getReportingTrm();
    const cache = new Map<string, number | null>();

    const normalized = await Promise.all((data || []).map(async (payment: any) => {
      const norm = await normalizePaymentRecordToCop(payment, reportingTrm, cache);
      return { ...payment, amount: norm.amountCop, amount_original: norm.originalAmount, amount_cop: norm.amountCop, currency: norm.currency };
    }));

    return normalized as SubscriptionPayment[];
  }

  async purgeExpiredSuspendedBrands(): Promise<any> {
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - 90);

    const { data: brands } = await supabaseAdmin.from('brands').select('id, name').eq('subscription_status', 'suspended').lt('subscription_end_date', cutoff.toISOString());
    if (!brands?.length) return { purged: 0, errors: 0 };

    let purged = 0;
    for (const b of brands) {
      const { error } = await supabaseAdmin.from('brands').update({ name: `[ELIMINADA] ${b.name}`, email: `deleted_${b.id}@purged.local`, logo: null }).eq('id', b.id);
      if (!error) purged++;
    }
    return { purged, errors: brands.length - purged };
  }
}

import { Storage, Bucket } from '@google-cloud/storage';
import sharp from 'sharp';
import axios from 'axios';
import crypto from 'crypto';
import fs from 'fs';
import { selectExpiredTempPaths } from '../utils/temp-cleanup';

// Re-export para compatibilidad con consumidores previos.
export { selectExpiredTempPaths };

export interface UploadImageDto {
  image_base64: string;
  filename: string;
  temporary?: boolean;
  folder?: string;
  assetType?: UploadAssetType;
}

export interface UploadImageBufferDto {
  buffer: Buffer;
  filename: string;
  temporary?: boolean;
  folder?: string;
  assetType?: UploadAssetType;
}

export interface UploadResponse {
  success: boolean;
  url: string;
  path?: string;
}

export type UploadAssetType =
  | 'general'
  | 'blog-inline'
  | 'blog-social'
  | 'download-safe';

/**
 * Sube imágenes a MinIO usando la API S3-compatible con firma HMAC-SHA256.
 * MinIO está en minio.wilkiedevs.com, bucket "images", acceso público de lectura.
 * Opcionalmente sube a GCS si existe gcs-credentials.json
 */
export class UploadService {
  private readonly endpoint = process.env.MINIO_ENDPOINT;
  private readonly bucket = process.env.MINIO_BUCKET;
  private readonly accessKey = process.env.MINIO_ACCESS_KEY;
  private readonly secretKey = process.env.MINIO_SECRET_KEY;
  private readonly publicUrl = process.env.MINIO_PUBLIC_URL;
  private readonly gcsBucketName = process.env.GCS_BUCKET || 'lookitry-vertex';
  private gcsDefaultBucket: Bucket | null = null;
  private storage: Storage | null = null;
  private hasGcsCredentials = false;

  constructor() {
    if (!this.endpoint || !this.bucket || !this.accessKey || !this.secretKey || !this.publicUrl) {
      throw new Error(
        'Variables de entorno de MinIO requeridas: MINIO_ENDPOINT, MINIO_BUCKET, MINIO_ACCESS_KEY, MINIO_SECRET_KEY, MINIO_PUBLIC_URL'
      );
    }

    // Intentar inicializar Google Cloud Storage solo si existe el archivo de credenciales
    try {
      const keyFilename = 'gcs-credentials.json';
      if (fs.existsSync(keyFilename)) {
        this.storage = new Storage({ keyFilename });
        this.hasGcsCredentials = true;
        console.log('[Upload Service] GCS credentials found, will upload to GCS');
        this.gcsDefaultBucket = this.storage.bucket(this.gcsBucketName);
      } else {
        console.log('[Upload Service] No GCS credentials file found, skipping GCS upload');
      }
    } catch (err) {
      console.warn('[Upload Service] GCS initialization skipped:', err);
    }
  }

  async uploadImage(data: UploadImageDto): Promise<UploadResponse> {
    const base64Data = data.image_base64.includes(',')
      ? data.image_base64.split(',')[1]
      : data.image_base64;
    const buffer = Buffer.from(base64Data, 'base64');
    return this.uploadImageBuffer({
      buffer,
      filename: data.filename,
      temporary: data.temporary,
      folder: data.folder,
      assetType: data.assetType,
    });
  }

  async uploadImageBuffer(data: UploadImageBufferDto): Promise<UploadResponse> {
    try {
      let { buffer, filename, temporary, folder, assetType } = data;

      // === VALIDACIÓN DE MAGIC BYTES CON SHARP ===
      try {
        const validatedImage = sharp(buffer);
        const metadata = await validatedImage.metadata();
        if (!metadata.format) {
          throw new Error('No se pudo identificar el formato de imagen');
        }
        const allowedFormats = ['jpeg', 'jpg', 'png', 'webp', 'gif', 'avif', 'tiff'];
        if (!allowedFormats.includes(metadata.format)) {
          throw new Error(`Formato de imagen no permitido: ${metadata.format}`);
        }
        console.log(`[Upload Service] Magic bytes validados: ${metadata.format}, ${buffer.length} bytes`);
      } catch (sharpError: any) {
        console.error('[Upload Service] Validación de imagen falló:', sharpError.message);
        throw new Error('El archivo no es una imagen válida o está corrupto');
      }

      // OPTIMIZACIÓN CON SHARP
      if (!temporary) {
        try {
          const image = sharp(buffer);
          const metadata = await image.metadata();
          const targetAssetType = assetType || 'general';
          let pipeline = image.rotate();
          let targetExtension = filename.split('.').pop()?.toLowerCase() || 'jpg';

          if (metadata.width && metadata.width > 1400) {
            pipeline = pipeline.resize(1400, null, { withoutEnlargement: true });
          }

          if (targetAssetType === 'blog-social' || targetAssetType === 'download-safe') {
            pipeline = pipeline.jpeg({ quality: 86, mozjpeg: true, progressive: true });
            targetExtension = 'jpg';
          } else {
            pipeline = pipeline.webp({ quality: 82, lossless: false, smartSubsample: true });
            targetExtension = 'webp';
          }

          buffer = await pipeline.toBuffer();
          const nameWithoutExt = filename.split('.').slice(0, -1).join('.') || 'image';
          filename = `${nameWithoutExt}.${targetExtension}`;
        } catch (sharpError) {
          console.error('[Upload Service] Falló Sharp, subiendo original:', sharpError);
        }
      }

      const contentType = this.detectContentType(filename, buffer);
      const ext = this.getExtension(filename, contentType);
      const targetFolder = folder || (temporary ? 'temp' : 'products');
      const uniqueName = `${targetFolder}/${Date.now()}-${crypto.randomBytes(6).toString('hex')}${ext}`;

      // 1. Subir a MinIO como respaldo interno
      await this.putObject(uniqueName, buffer, contentType);
      console.log(`[Upload Service] Imagen subida a MinIO (respaldo): ${uniqueName}`);

      // 2. Subir a GCS para acceso público de Vertex AI
      const gcsUrl = await this.uploadToGCS(buffer, uniqueName, contentType);
      console.log(`[Upload Service] Imagen subida a GCS (público): ${gcsUrl}`);

      // 3. Retornar la URL pública de GCS
      return { success: true, url: gcsUrl, path: uniqueName };
    } catch (error: any) {
      console.error('[Upload Service] Error en el proceso de subida:', error.message);
      throw new Error(error.message || 'Error al subir imagen');
    }
  }

  /**
   * Sube un buffer a Google Cloud Storage y retorna su URL pública.
   * Si no hay credenciales de GCS, retorna la URL de MinIO.
   */
  /**
   * Genera una signed URL temporal para acceso a un objeto en GCS.
   * TTL por defecto: 15 minutos.
   * Usado para dar acceso temporal a Vertex AI y n8n sin exponer objetos públicamente.
   */
  async generateSignedUrl(gcsPath: string, ttlMinutes = 15): Promise<string> {
    if (!this.hasGcsCredentials || !this.gcsDefaultBucket) {
      console.warn('[Upload Service] GCS no configurado, retornando MinIO URL como fallback');
      // Fallback: retornar URL de MinIO (que es pública)
      return `${this.publicUrl}/${this.bucket}/${gcsPath}`;
    }

    try {
      const file = this.gcsDefaultBucket.file(gcsPath);
      const [signedUrl] = await file.getSignedUrl({
        version: 'v4',
        action: 'read',
        expires: Date.now() + ttlMinutes * 60 * 1000,
      });
      console.log(`[Upload Service] Signed URL generada para ${gcsPath} (TTL: ${ttlMinutes}min)`);
      return signedUrl;
    } catch (err: any) {
      console.error(`[Upload Service] Error generando signed URL para ${gcsPath}:`, err.message);
      // En caso de error, fallback a MinIO URL
      return `${this.publicUrl}/${this.bucket}/${gcsPath}`;
    }
  }

  /**
   * Genera signed URL para selfie del usuario final.
   * TTL: 15 minutos — suficiente para que Vertex AI o n8n descarguen la imagen.
   */
  async generateSelfieSignedUrl(selfiePath: string): Promise<string> {
    return this.generateSignedUrl(selfiePath, 15);
  }

  /**
   * Genera signed URL para máscara SAM.
   * TTL: 5 minutos — la máscara se usa inmediatamente en el pipeline.
   */
  async generateMaskSignedUrl(maskPath: string): Promise<string> {
    return this.generateSignedUrl(maskPath, 5);
  }

  /**
   * Sube un buffer a Google Cloud Storage y retorna signed URL temporal.
   * NO usa `public: true` — el acceso se controla via signed URLs.
   * La signed URL tiene TTL de 15 minutos por defecto.
   */
  private async uploadToGCS(buffer: Buffer, destination: string, contentType: string): Promise<string> {
    // Si no hay credenciales de GCS, retornar URL de MinIO
    if (!this.hasGcsCredentials || !this.storage) {
      console.log('[Upload Service] Skipping GCS upload, returning MinIO URL');
      return `${this.publicUrl}/${this.bucket}/${destination}`;
    }

    const bucket = this.storage.bucket(this.gcsBucketName);
    const file = bucket.file(destination);

    try {
      // NO public: true — el acceso se controla via signed URLs
      await file.save(buffer, {
        contentType: contentType,
        metadata: {
          cacheControl: 'private, max-age=0', // No cachear contenido privado
          metadata: {
            source: 'lookitry-backend',
            timestamp: new Date().toISOString(),
            access: 'signed-url-only', // Flag para auditoría
          }
        }
      });

      // Generar signed URL con TTL de 15 min para retorno inmediato
      const signedUrl = await this.generateSignedUrl(destination, 15);
      console.log(`[Upload Service] Imagen subida a GCS (privada): ${destination}`);
      return signedUrl;
    } catch (error: any) {
      console.error(`[Upload Service] Error uploading to GCS bucket "${this.gcsBucketName}":`, error);
      // En caso de error en GCS, retourner URL de MinIO como fallback
      console.log('[Upload Service] Falling back to MinIO URL');
      return `${this.publicUrl}/${this.bucket}/${destination}`;
    }
  }

  private async putObject(key: string, body: Buffer, contentType: string): Promise<void> {
    const host = this.endpoint!.replace(/^https?:\/\//, '');
    const url = `${this.endpoint!}/${this.bucket!}/${key}`;

    const now = new Date();
    const dateStamp = now.toISOString().slice(0, 10).replace(/-/g, '');
    const amzDate = now.toISOString().replace(/[:-]/g, '').slice(0, 15) + 'Z';
    const region = 'us-east-1';
    const payloadHash = crypto.createHash('sha256').update(body).digest('hex');

    const canonicalHeaders =
      `content-type:${contentType}\n` +
      `host:${host}\n` +
      `x-amz-content-sha256:${payloadHash}\n` +
      `x-amz-date:${amzDate}\n`;

    const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';

    const canonicalRequest = [
      'PUT',
      `/${this.bucket}/${key}`,
      '',
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    const credentialScope = `${dateStamp}/${region}/s3/aws4_request`;
    const stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      crypto.createHash('sha256').update(canonicalRequest).digest('hex'),
    ].join('\n');

    const signingKey = this.getSigningKey(dateStamp, region);
    const signature = crypto.createHmac('sha256', signingKey).update(stringToSign).digest('hex');

    const authorization =
      `AWS4-HMAC-SHA256 Credential=${this.accessKey}/${credentialScope}, ` +
      `SignedHeaders=${signedHeaders}, Signature=${signature}`;

    await axios.put(url, body, {
      headers: {
        'Content-Type': contentType,
        'Host': host,
        'x-amz-date': amzDate,
        'x-amz-content-sha256': payloadHash,
        Authorization: authorization,
      },
      maxBodyLength: 10 * 1024 * 1024,
      timeout: 30000,
    });
  }

  private getSigningKey(dateStamp: string, region: string): Buffer {
    const kDate = crypto.createHmac('sha256', `AWS4${this.secretKey}`).update(dateStamp).digest();
    const kRegion = crypto.createHmac('sha256', kDate).update(region).digest();
    const kService = crypto.createHmac('sha256', kRegion).update('s3').digest();
    return crypto.createHmac('sha256', kService).update('aws4_request').digest();
  }

  private detectContentType(filename: string, buffer: Buffer): string {
    if (buffer[0] === 0xff && buffer[1] === 0xd8) return 'image/jpeg';
    if (buffer[0] === 0x89 && buffer[1] === 0x50) return 'image/png';
    if (buffer[0] === 0x47 && buffer[1] === 0x49) return 'image/gif';
    if (buffer[0] === 0x52 && buffer[8] === 0x57) return 'image/webp';
    const ext = filename.split('.').pop()?.toLowerCase();
    const map: Record<string, string> = {
      jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png',
      gif: 'image/gif', webp: 'image/webp', svg: 'image/svg+xml',
    };
    return map[ext || ''] || 'image/jpeg';
  }

  private getExtension(filename: string, contentType: string): string {
    const fromFile = filename.includes('.') ? `.${filename.split('.').pop()?.toLowerCase()}` : '';
    if (fromFile) return fromFile;
    const map: Record<string, string> = {
      'image/jpeg': '.jpg', 'image/png': '.png',
      'image/gif': '.gif', 'image/webp': '.webp', 'image/svg+xml': '.svg',
    };
    return map[contentType] || '.jpg';
  }

  /**
   * Elimina un objeto tanto de MinIO como de GCS (si está configurado).
   * Usado para eliminación inline de datos biométricos (selfies).
   */
  async deleteBiometricData(path: string): Promise<{ minio: boolean; gcs: boolean; error?: string }> {
    const result = { minio: false, gcs: false } as { minio: boolean; gcs: boolean; error?: string };

    // 1. Eliminar de MinIO
    try {
      await this.deleteObject(path);
      result.minio = true;
      console.log(`[BiometricCleanup] Eliminado de MinIO: ${path}`);
    } catch (err: any) {
      // No crítico si falla MinIO — puede que ya se haya movido a GCS o no exista
      console.warn(`[BiometricCleanup] MinIO delete falló (puede no existir): ${path} — ${err.message}`);
      result.minio = false;
    }

    // 2. Eliminar de GCS si está configurado
    if (this.hasGcsCredentials && this.storage && this.gcsDefaultBucket) {
      try {
        const gcsFile = this.gcsDefaultBucket.file(path);
        await gcsFile.delete({ ignoreNotFound: true });
        result.gcs = true;
        console.log(`[BiometricCleanup] Eliminado de GCS: ${path}`);
      } catch (err: any) {
        console.warn(`[BiometricCleanup] GCS delete falló: ${path} — ${err.message}`);
        result.gcs = false;
        result.error = err.message;
      }
    }

    return result;
  }

  /**
   * Elimina múltiples objetos biométricos (batch).
   * Retorna array de resultados individuales.
   */
  async deleteBiometricDataBatch(paths: string[]): Promise<Array<{ path: string; result: { minio: boolean; gcs: boolean; error?: string } }>> {
    const results = [];
    for (const path of paths) {
      const result = await this.deleteBiometricData(path);
      results.push({ path, result });
    }
    return results;
  }

  async cleanupTempFiles(paths: string[]): Promise<{ deleted: number; errors: number }> {
    let deleted = 0;
    let errors = 0;

    for (const path of paths) {
      try {
        // Delete from MinIO
        await this.deleteObject(path);
        // Also delete from GCS if configured
        if (this.hasGcsCredentials && this.gcsDefaultBucket) {
          await this.gcsDefaultBucket.file(path).delete({ ignoreNotFound: true });
        }
        deleted++;
        console.log(`[Cleanup] Eliminado: ${path}`);
      } catch (error: any) {
        errors++;
        console.error(`[Cleanup] Error eliminando ${path}:`, error.message);
      }
    }

    return { deleted, errors };
  }

  /**
   * C-3: red de seguridad para selfies huérfanas. Lista el prefijo `temp/` en GCS
   * y elimina las que superan `maxAgeHours` (las del flujo normal ya se borran inline
   * tras la generación). Pensado para correr desde el scheduler, sin req/res.
   */
  async cleanupOrphanedTempFiles(maxAgeHours = 24): Promise<{ scanned: number; deleted: number; errors: number }> {
    if (!this.hasGcsCredentials || !this.gcsDefaultBucket) {
      console.warn('[OrphanCleanup] GCS no configurado, omitiendo limpieza de temporales huérfanos');
      return { scanned: 0, deleted: 0, errors: 0 };
    }

    try {
      const [files] = await this.gcsDefaultBucket.getFiles({ prefix: 'temp/' });
      const names = files.map((f) => f.name);
      const expired = selectExpiredTempPaths(names, maxAgeHours, Date.now());

      let deleted = 0;
      let errors = 0;
      for (const path of expired) {
        try {
          await this.gcsDefaultBucket.file(path).delete({ ignoreNotFound: true });
          // Borrar también de MinIO (backup); no crítico si falla
          try {
            await this.deleteObject(path);
          } catch {
            /* backup no crítico */
          }
          deleted++;
        } catch (err: any) {
          errors++;
          console.error(`[OrphanCleanup] Error eliminando ${path}:`, err.message);
        }
      }

      console.log(`[OrphanCleanup] Escaneados ${names.length}, expirados ${expired.length}, eliminados ${deleted}, errores ${errors}`);
      return { scanned: names.length, deleted, errors };
    } catch (err: any) {
      console.error('[OrphanCleanup] Error listando temporales:', err.message);
      return { scanned: 0, deleted: 0, errors: 1 };
    }
  }

  /**
   * Elimina un archivo de GCS por path.
   */
  async deleteFromGCS(path: string): Promise<boolean> {
    if (!this.hasGcsCredentials || !this.gcsDefaultBucket) return false;
    try {
      await this.gcsDefaultBucket.file(path).delete({ ignoreNotFound: true });
      return true;
    } catch {
      return false;
    }
  }

  private async deleteObject(key: string): Promise<void> {
    const host = this.endpoint!.replace(/^https?:\/\//, '');
    const url = `${this.endpoint!}/${this.bucket!}/${key}`;

    const now = new Date();
    const dateStamp = now.toISOString().slice(0, 10).replace(/-/g, '');
    const amzDate = now.toISOString().replace(/[:-]/g, '').slice(0, 15) + 'Z';
    const region = 'us-east-1';
    const payloadHash = 'UNSIGNED-PAYLOAD';

    const canonicalHeaders = `host:${host}\nx-amz-content-sha256:${payloadHash}\nx-amz-date:${amzDate}\n`;
    const signedHeaders = 'host;x-amz-content-sha256;x-amz-date';

    const canonicalRequest = [
      'DELETE',
      `/${this.bucket!}/${key}`,
      '',
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    const credentialScope = `${dateStamp}/${region}/s3/aws4_request`;
    const stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      crypto.createHash('sha256').update(canonicalRequest).digest('hex'),
    ].join('\n');

    const signingKey = this.getSigningKey(dateStamp, region);
    const signature = crypto.createHmac('sha256', signingKey).update(stringToSign).digest('hex');

    const authorization =
      `AWS4-HMAC-SHA256 Credential=${this.accessKey!}/${credentialScope}, ` +
      `SignedHeaders=${signedHeaders}, Signature=${signature}`;

    await axios.delete(url, {
      headers: {
        'Host': host,
        'x-amz-date': amzDate,
        'x-amz-content-sha256': payloadHash,
        Authorization: authorization,
      },
      timeout: 30000,
    });
  }
}

export const uploadService = new UploadService();

import { supabaseAdmin } from '../config/supabase';
import { getPlanByType } from '../config/plans';

export interface UsageStats {
  currentMonth: {
    generationsUsed: number;
    generationsLimit: number;
    generationsRemaining: number;
    productsCount: number;
    productsLimit: number;
  };
  extraCreditsBalance: number;
  availableCredits: number;
  percentageUsed: number;
  resetDate: string;
}

export interface GenerationConsumptionReservation {
  source: 'monthly' | 'extra';
  usage: UsageStats;
}

export class UsageService {
  private getCurrentMonthRange() {
    const now = new Date();
    const start = new Date(now.getFullYear(), now.getMonth(), 1);
    const end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    return { start, end };
  }

  private getNextMonthStart() {
    const now = new Date();
    return new Date(now.getFullYear(), now.getMonth() + 1, 1);
  }

  private async getPlanGenerationsLimit(plan: string): Promise<number> {
    const normalizedPlan = String(plan || 'BASIC').toLowerCase();
    const { data } = await supabaseAdmin
      .from('pricing_config')
      .select('data')
      .eq('id', normalizedPlan)
      .maybeSingle();

    const pricingData = (data?.data as any) || {};
    const dynamicLimit = Number(
      pricingData.generaciones_mensuales ??
      pricingData.generaciones_mes
    );
    if (Number.isFinite(dynamicLimit) && dynamicLimit > 0) {
      return dynamicLimit;
    }

    return getPlanByType(plan).maxGenerationsPerMonth;
  }

  private async getBrandUsageContext(brandId: string) {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('plan, email_verified, trial_end_date, trial_generations_limit, subscription_status, extra_credits_balance')
      .eq('id', brandId)
      .single();

    if (!brand) {
      throw new Error('Marca no encontrada');
    }

    const inTrial =
      brand.plan === 'TRIAL' &&
      brand.subscription_status !== 'suspended' &&
      !!brand.trial_end_date &&
      new Date(brand.trial_end_date) > new Date();
    const generationsLimit = inTrial
      ? (brand.trial_generations_limit ?? 15)
      : await this.getPlanGenerationsLimit(brand.plan);

    return {
      brand,
      inTrial,
      generationsLimit,
      extraCreditsBalance: Number(brand.extra_credits_balance || 0),
    };
  }

  async reserveGenerationCredit(brandId: string): Promise<GenerationConsumptionReservation> {
    const usage = await this.getUsageStats(brandId);

    if (usage.currentMonth.generationsRemaining > 0) {
      return { source: 'monthly', usage };
    }

    const { data, error } = await supabaseAdmin.rpc('consume_extra_credit', {
      p_brand_id: brandId,
    });

    if (error) {
      throw new Error(`No se pudo reservar un crédito extra: ${error.message}`);
    }

    if (!data) {
      throw new Error('INSUFFICIENT_CREDITS');
    }

    return {
      source: 'extra',
      usage: {
        ...usage,
        extraCreditsBalance: Math.max(0, usage.extraCreditsBalance - 1),
        availableCredits: Math.max(0, usage.availableCredits - 1),
      },
    };
  }

  async refundReservedExtraCredit(brandId: string): Promise<void> {
    const { error } = await supabaseAdmin.rpc('refund_extra_credit', {
      p_brand_id: brandId,
    });

    if (error) {
      throw new Error(`No se pudo devolver el crédito extra reservado: ${error.message}`);
    }
  }

  async checkGenerationLimit(brandId: string): Promise<boolean> {
    try {
      await this.reserveGenerationCredit(brandId);
      return true;
    } catch {
      return false;
    }
  }

  async checkProductLimit(brandId: string): Promise<boolean> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('plan, trial_end_date, trial_generations_limit, subscription_status')
      .eq('id', brandId)
      .single();

    if (!brand) return false;

    const inTrial =
      brand.plan === 'TRIAL' &&
      brand.subscription_status !== 'suspended' &&
      !!brand.trial_end_date &&
      new Date(brand.trial_end_date) > new Date();
    const plan = getPlanByType(brand.plan);
    const productsLimit = inTrial ? 1 : plan.maxProducts;

    const { count } = await supabaseAdmin
      .from('products')
      .select('*', { count: 'exact', head: true })
      .eq('brand_id', brandId)
      .eq('is_active', true);

    return (count || 0) < productsLimit;
  }

  async getUsageStats(brandId: string): Promise<UsageStats> {
    const { brand, inTrial, generationsLimit, extraCreditsBalance } = await this.getBrandUsageContext(brandId);

    let trialProductsLimit = 1;
    if (inTrial) {
      const { data: pricingMeta } = await supabaseAdmin
        .from('pricing_config')
        .select('data')
        .eq('id', 'meta')
        .single();

      if (pricingMeta?.data) {
        const meta = pricingMeta.data as any;
        trialProductsLimit = meta.trial_products_max ?? 1;
      }
    }

    const plan = getPlanByType(brand.plan);
    const productsLimit = inTrial ? trialProductsLimit : plan.maxProducts;
    const currentMonth = this.getCurrentMonthRange();

    const { count: productsCount } = await supabaseAdmin
      .from('products')
      .select('*', { count: 'exact', head: true })
      .eq('brand_id', brandId)
      .eq('is_active', true);

    const { count: generationsUsed } = await supabaseAdmin
      .from('generations')
      .select('*', { count: 'exact', head: true })
      .eq('brand_id', brandId)
      .eq('status', 'SUCCESS')
      .gte('generated_at', currentMonth.start.toISOString())
      .lte('generated_at', currentMonth.end.toISOString());

    const safeGenerationsUsed = generationsUsed || 0;
    const generationsRemaining = Math.max(0, generationsLimit - safeGenerationsUsed);
    const percentageUsed = (safeGenerationsUsed / generationsLimit) * 100;

    return {
      currentMonth: {
        generationsUsed: safeGenerationsUsed,
        generationsLimit,
        generationsRemaining,
        productsCount: productsCount || 0,
        productsLimit,
      },
      extraCreditsBalance,
      availableCredits: generationsRemaining + extraCreditsBalance,
      percentageUsed: Math.round(percentageUsed * 100) / 100,
      resetDate: this.getNextMonthStart().toISOString(),
    };
  }
}

import { GoogleGenAI, HarmCategory, HarmBlockThreshold, GenerateContentParameters } from '@google/genai';

// Configuration
const VERTEX_PROJECT_ID = process.env.VERTEX_PROJECT_ID || 'gen-lang-client-0591001769';
const VERTEX_LOCATION = process.env.VERTEX_LOCATION || 'us-central1';

// Available models
export const VERTEX_MODELS = {
  // Preview models
  'gemini-3.1-pro-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true },
  'gemini-3-pro-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true },
  'gemini-3-pro-image-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true, supportsImageGen: true },
  'gemini-3-flash-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true },
  'gemini-3.1-flash-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true },
  'gemini-3.1-flash-lite-preview': { contextWindow: 1048576, supportsMultimodal: true, preview: true },
  'gemini-2.5-flash-image': { contextWindow: 1048576, supportsMultimodal: true, preview: false, supportsImageGen: true },
  'gemini-3.1-pro-preview-customtools': { contextWindow: 1048576, supportsMultimodal: true, preview: true, supportsTools: true },

  // GA models
  'gemini-2.5-pro': { contextWindow: 1048576, supportsMultimodal: true, preview: false },
  'gemini-2.5-flash': { contextWindow: 1048576, supportsMultimodal: true, preview: false },
  'gemini-2.5-flash-lite': { contextWindow: 1048576, supportsMultimodal: true, preview: false },
  'gemini-2.0-flash': { contextWindow: 1048576, supportsMultimodal: true, preview: false },
  'gemini-2.0-flash-lite': { contextWindow: 1048576, supportsMultimodal: true, preview: false },
} as const;

export type VertexModelId = keyof typeof VERTEX_MODELS;

// Singleton instance
let genAIInstance: GoogleGenAI | null = null;

function getGenAI(): GoogleGenAI {
  if (!genAIInstance) {
    const rawLocation = process.env.VERTEX_LOCATION || 'us-central1';
    const location = rawLocation === 'global' ? 'us-central1' : rawLocation;

    genAIInstance = new GoogleGenAI({
      vertexai: true,
      project: process.env.VERTEX_PROJECT_ID || 'gen-lang-client-0591001769',
      location: location,
    });
  }
  return genAIInstance;
}

export interface VertexGenerateOptions {
  model?: VertexModelId;
  contents: {
    role?: string;
    parts: {
      text?: string;
      inlineData?: {
        mimeType: string;
        data: string;
      };
      fileData?: {
        mimeType: string;
        fileUri: string;
      };
    }[];
  }[];
  systemInstruction?: {
    parts: { text: string }[];
  };
  generationConfig?: {
    temperature?: number;
    topP?: number;
    topK?: number;
    maxOutputTokens?: number;
    stopSequences?: string[];
    responseMimeType?: string;
  };
  safetySettings?: {
    category: string;
    threshold: string;
  }[];
}

export interface VertexGenerateResult {
  candidates?: {
    content: {
      role: string;
      parts: { text?: string }[];
    };
    finishReason: string;
  }[];
  usageMetadata?: {
    promptTokenCount: number;
    candidatesTokenCount: number;
    totalTokenCount: number;
  };
  modelVersion?: string;
  error?: string;
}

class VertexService {
  private projectId: string;
  private location: string;

  constructor() {
    this.projectId = VERTEX_PROJECT_ID;
    this.location = VERTEX_LOCATION;
  }

  /**
   * Call Vertex AI with system prompt + conversation history + current message
   */
  async callVertex(systemPrompt: string, userMessage: string, history: { role: 'user' | 'assistant'; content: string }[] = []): Promise<string> {
    // Vertex uses 'model' for assistant role
    const contents = [
      ...history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      })),
      { role: 'user', parts: [{ text: userMessage }] }
    ];

    const result = await this.generateContent({
      model: 'gemini-2.5-flash',
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents,
      generationConfig: { temperature: 0.7, maxOutputTokens: 2048 }
    });

    if (result.error) {
      throw new Error(`VERTEX_ERROR: ${result.error}`);
    }

    const text = result.candidates?.[0]?.content?.parts?.[0]?.text;
    if (!text) {
      throw new Error('VERTEX_NO_RESPONSE');
    }

    return text;
  }

  /**
   * Generate content using Vertex AI Gemini models
   */
  async generateContent(options: VertexGenerateOptions): Promise<VertexGenerateResult> {
    const modelId = options.model || 'gemini-2.5-flash';
    const ai = getGenAI();

    try {
      // Clean up config to avoid sending undefined values
      const cleanConfig = options.generationConfig ? Object.fromEntries(
        Object.entries({
          temperature: options.generationConfig.temperature,
          topP: options.generationConfig.topP,
          topK: options.generationConfig.topK,
          maxOutputTokens: options.generationConfig.maxOutputTokens,
          stopSequences: options.generationConfig.stopSequences,
          responseMimeType: options.generationConfig.responseMimeType,
        }).filter(([_, v]) => v !== undefined)
      ) : undefined;

      // Build request parameters
      const requestParams: GenerateContentParameters = {
        model: modelId,
        contents: options.contents as any,
      };

      requestParams.config = cleanConfig ? { ...cleanConfig } : {};

      if (options.systemInstruction) {
        requestParams.config.systemInstruction = {
          parts: options.systemInstruction.parts,
        } as any;
      }

      if (options.safetySettings && options.safetySettings.length > 0) {
        requestParams.config.safetySettings = options.safetySettings as any;
      }

      if (Object.keys(requestParams.config).length === 0) {
        delete requestParams.config;
      }

      const result = await ai.models.generateContent(requestParams);

      return {
        candidates: result.candidates?.map(candidate => ({
          content: {
            role: candidate.content?.role || 'model',
            parts: candidate.content?.parts?.map(part => ({
              text: part.text,
            })) || [],
          },
          finishReason: candidate.finishReason || 'STOP',
        })),
        usageMetadata: result.usageMetadata ? {
          promptTokenCount: result.usageMetadata.promptTokenCount || 0,
          candidatesTokenCount: result.usageMetadata.candidatesTokenCount || 0,
          totalTokenCount: result.usageMetadata.totalTokenCount || 0,
        } : undefined,
      };
    } catch (error: any) {
      console.error(`[VertexService] Error generating content with @google/genai, falling back to REST:`, error?.message || error);

      // Fallback to Gemini REST API — GOOGLE_API_KEY has AIza format (valid for REST);
      // GEMINI_API_KEY uses AQ. format (OAuth token, invalid for this endpoint)
      const apiKey = process.env.GOOGLE_API_KEY || process.env.GEMINI_API_KEY;
      if (apiKey) {
        try {
          const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelId}:generateContent?key=${apiKey}`;

          const payload = {
            system_instruction: options.systemInstruction,
            contents: options.contents,
            generationConfig: options.generationConfig,
            safetySettings: options.safetySettings,
          };

          const res = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
          });

          if (!res.ok) {
            const errorText = await res.text();
            throw new Error(`Gemini API Error ${res.status}: ${errorText}`);
          }

          const json: any = await res.json();
          return {
            candidates: json.candidates?.map((c: any) => ({
              content: c.content,
              finishReason: c.finishReason || 'STOP',
            })),
            usageMetadata: json.usageMetadata,
          };
        } catch (restError: any) {
          console.error(`[VertexService] REST API fallback also failed:`, restError?.message || restError);
          return { error: restError?.message || 'REST API fallback failed' };
        }
      }

      // Parse error response
      if (error?.response?.data?.error) {
        return {
          error: error.response.data.error.message || 'Vertex AI error',
        };
      }

      return {
        error: error?.message || 'Unknown error during generation',
      };
    }
  }

  /**
   * Stream generate content
   */
  async *streamGenerateContent(options: VertexGenerateOptions): AsyncGenerator<string> {
    const modelId = options.model || 'gemini-2.5-flash';
    const ai = getGenAI();

    const requestParams: GenerateContentParameters = {
      model: modelId,
      contents: options.contents as any,
    };

    requestParams.config = {};

    if (options.systemInstruction) {
      requestParams.config.systemInstruction = {
        parts: options.systemInstruction.parts,
      } as any;
    }

    if (options.generationConfig) {
      Object.assign(requestParams.config, {
        temperature: options.generationConfig.temperature,
        topP: options.generationConfig.topP,
        topK: options.generationConfig.topK,
        maxOutputTokens: options.generationConfig.maxOutputTokens,
        stopSequences: options.generationConfig.stopSequences,
      });
    }

    if (Object.keys(requestParams.config).length === 0) {
      delete requestParams.config;
    }

    const streamResult = await ai.models.generateContentStream(requestParams);

    for await (const chunk of streamResult) {
      const text = chunk.candidates?.[0]?.content?.parts?.[0]?.text;
      if (text) {
        yield text;
      }
    }
  }

  /**
   * Get list of available models
   */
  getAvailableModels() {
    return Object.entries(VERTEX_MODELS).map(([id, config]) => ({
      id,
      ...config,
    }));
  }

  /**
   * Check if model exists
   */
  isModelAvailable(modelId: string): boolean {
    return modelId in VERTEX_MODELS;
  }

  /**
   * Get model info
   */
  getModelInfo(modelId: string) {
    return VERTEX_MODELS[modelId as VertexModelId] || null;
  }
}

